(5, 'เครื่องกรีดผนัง เซาะร่อง Wallcheser', 0, 'จำหน่ายเครื่องเซาะร่องผนัง Wall Chaser สำหรับงานเดินท่อไฟฟ้าและประปา ตัดร่องได้แม่นยำ รวดเร็ว ลดฝุ่น ใช้งานง่าย ทนทาน ราคาพิเศษ', 'published', NULL, 'Botble\\ACL\\Models\\User', NULL, 0, 0, 0, '2025-03-13 12:22:28', '2025-11-10 10:13:03'),
(6, 'เครื่องพ่นสีแรงดันสูง Airless Sprayer', 0, 'เปลี่ยนงานพ่นสีให้เป็นเรื่องง่ายด้วย เครื่องพ่นสีแรงดันสูง (Airless Sprayer) เหมาะสำหรับงานทาบ้าน เฟอร์นิเจอร์ หรือโปรเจกต์ช่างทุกประเภท พ่นสีได้เร็ว พื้นผิวเรียบเนียน ประหยัดแรงและเวลา เหมาะทั้งมืออาชีพและมือใหม่ที่ต้องการผลลัพธ์ระดับโปร!', 'published', NULL, 'Botble\\ACL\\Models\\User', NULL, 1, 0, 0, '2025-03-13 12:22:28', '2025-11-10 10:13:03'),
(7, 'เครื่องมือช่าง-Tools', 0, 'เครื่องมือช่าง, เครื่องมือช่างคุณภาพ, เครื่องมือช่างไฟฟ้า, เครื่องมือช่างกล, อุปกรณ์ช่าง, เครื่องมือช่างมือโปร, ซื้อเครื่องมือช่าง, ร้านเครื่องมือช่าง', 'published', 1, 'Botble\\ACL\\Models\\User', NULL, 2, 0, 0, '2025-04-17 05:52:27', '2025-11-10 10:13:03'),
(8, 'Mortar Sprayer-เครื่องพ่นปูนซีเมนต์', 0, 'เครื่องพ่นปูนฉาบ, RUBYSHOP, RB-M30L, Cement Mortar Spraying Machine, เครื่องพ่นปูน, อุปกรณ์ก่อสร้าง, เครื่องมือช่าง, ผู้รับเหมา, ช่างก่อสร้าง, ปูนฉาบ, งานฉาบ', 'published', 1, 'Botble\\ACL\\Models\\User', NULL, 3, 0, 0, '2025-04-21 11:33:23', '2025-11-10 10:13:03'),
