(222, 'RUBY SHOP เครื่องพ่นสีพกพา รุ่น RB-09: จบงานสีสวยง่ายๆ ได้ทุกที่', '<ul><li>พกพาสะดวก: ขนาดเล็ก น้ำหนักเบา เคลื่อนย้ายง่าย พ่นสีได้ทุกที่</li><li>หัวพ่น 3 ขนาด: 1.0 มม., 1.8 มม., 2.5 มม. เลือกใช้ได้ตามความเหมาะสมของงานและประเภทสี</li><li>ใช้งานง่าย: เหมาะสำหรับทั้งมืออาชีพและผู้ใช้งานทั่วไป</li><li>อเนกประสงค์: ใช้พ่นสีได้หลากหลายประเภท เช่น สีน้ำ สีน้ำมัน สีรองพื้น และอื่นๆ</li><li>ราคาคุ้มค่า: เหมาะสำหรับผู้ที่ต้องการเครื่องพ่นสีคุณภาพดี ในราคาสบายกระเป๋า</li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><h6>RUBY SHOP เครื่องพ่นสีพกพา รุ่น RB-09 เป็นเครื่องพ่นสีที่ออกแบบมาเพื่อตอบโจทย์งานพ่นสีที่ต้องการความสะดวก รวดเร็ว และมีประสิทธิภาพ ด้วยขนาดที่เล็ก น้ำหนักเบา ทำให้สามารถพกพาไปใช้งานได้ทุกที่ มาพร้อมหัวพ่น 3 ขนาดให้เลือกใช้ตามความเหมาะสมของงาน เหมาะสำหรับงานพ่นสีหลากหลายประเภท</h6><h5> </h5><h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>พกพาสะดวก</strong>: ขนาดเล็ก น้ำหนักเบา</li><li><strong>หัวพ่น 3 ขนาด</strong>: 1.0 มม., 1.8 มม., 2.5 มม.</li><li><strong>ใช้งานง่าย</strong>: เหมาะสำหรับทั้งมืออาชีพและผู้ใช้งานทั่วไป</li><li><strong>อเนกประสงค์</strong>: ใช้พ่นสีได้หลากหลายประเภท</li><li><strong>ราคาคุ้มค่า</strong></li></ul><h2> </h2><h5><strong>เหมาะสำหรับ</strong></h5><ul><li>งานพ่นสีภายในและภายนอกอาคารขนาดเล็ก</li><li>งานพ่นสีเฟอร์นิเจอร์</li><li>งานพ่นสี DIY ทั่วไป</li></ul><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรสวมใส่อุปกรณ์ป้องกันความปลอดภัยที่เหมาะสมขณะใช้งาน</li></ul><h2> </h2>', 'published', '[\"products\\/rb-093.webp\",\"products\\/rb-092.webp\",\"products\\/rb-09.webp\"]', NULL, 'NN-2443-6OWFH', 0, 3, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 1290, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 935, '2025-03-12 20:51:38', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/rb-093-1.webp', 'physical', NULL, 1290, 0, 0, 0, 0, NULL),
(223, 'RUBY SHOP เครื่องพ่นสีจราจร RB-GM91: ตีเส้นจราจรคมชัด รวดเร็วทันใจ', '<ul><li>พ่นสีได้รวดเร็ว: ด้วยอัตราการพ่นสีสูงถึง 4.1 ลิตร/นาที</li><li>มอเตอร์ทรงพลัง: มอเตอร์ 5.5HP ให้พลังในการพ่นสีอย่างมีประสิทธิภาพ</li><li>แรงดันสูง: แรงดันสูงสุด 20Mpa ช่วยเพิ่มความแม่นยำในการพ่นเส้นจราจร ทำให้ได้เส้นที่คมชัดและสวยงาม</li><li>ใช้งานได้หลากหลาย: เหมาะสำหรับตีเส้นจราจรบนถนน, สนามบิน, สนามกีฬา, สนามเด็กเล่น และอื่นๆ</li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><h6>เครื่องพ่นสีจราจร RB-GM91 เป็นเครื่องพ่นสีที่ออกแบบมาเพื่อการตีเส้นจราจรบนถนนโดยเฉพาะ ด้วยคุณสมบัติที่โดดเด่นทั้งในด้านความเร็ว ความแรง และความแม่นยำ ทำให้เป็นเครื่องมือที่ตอบโจทย์ความต้องการของผู้ใช้งานได้อย่างลงตัว</h6><h2> </h2><h5>คุณสมบัติเด่น</h5><ul><li>อัตราการพ่นสีสูงถึง 4.1 ลิตร/นาที</li><li>มอเตอร์ 5.5HP</li><li>แรงดันสูงสุด 20Mpa</li><li>เหมาะสำหรับใช้งานในหลากหลายสถานที่</li><li>ใช้งานง่าย</li><li>ทนทาน</li></ul><h2> </h2><h5><strong>วิธีการใช้งาน</strong></h5><ol><li>เตรียมสีที่ต้องการใช้</li><li>เติมสีลงในเครื่องพ่นสี</li><li>ปรับแรงดันและปริมาณการพ่นสีให้เหมาะสม</li><li>เริ่มทำการพ่นสีตามแนวที่ต้องการ</li></ol><h2> </h2><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรสวมใส่อุปกรณ์ป้องกันความปลอดภัยขณะใช้งาน</li></ul>[media url=https://youtu.be/XBdFobBONVA][/media]', 'published', '[\"products\\/rb-gm91.webp\",\"products\\/vz.webp\",\"products\\/e7.webp\",\"products\\/9q.webp\"]', NULL, 'NN-2443-0FZJI', 0, 48, 0, NULL, 0, 0, 'in_stock', 1, NULL, 0, 0, 79000, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1156, '2025-03-12 20:51:47', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/rb-gm91-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(224, 'RUBYSHOP เครื่องพ่นสกิมโค้ท ระบบลูกสูบ รุ่น RB-1060 เป็น 2 IN 1 Skim coat machine &amp; Airless sprayer', '<ul><li>ตัวเครื่องทนทาน ทำจากวัสดุคุณภาพสูง ทนแรงดันและการใช้งานหนัก</li><li>กำลังสูง พ่นปูนได้ละเอียด เรียบเนียน สม่ำเสมอ</li><li>ควบคุมการพ่นได้ง่าย ปรับแนวตั้งและแนวนอนของหัวพ่นได้</li><li>สายพ่นยาว คลอบคลุมพื้นที่กว้าง (สามารถต่อสายเพิ่มได้)</li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><h6>เครื่องพ่นสกิมโค้ท  เป็นอุปกรณ์ที่ใช้สำหรับพ่นสกิมโค้ทลงบนผนังหรือพื้น เพื่อปรับปรุงพื้นที่ที่ไม่ราบหรือไม่สวยงาม โดยช่วยให้การทำงานเสร็จสิ้นได้รวดเร็วและมีความแม่นยำสูง</h6><h5> </h5><h5><strong>ข้อมูลทางเทคนิค:</strong></h5><ul><li>ขนาดหัวทิป: 0.039</li><li>ขนาดหัวทิปสูงสุด: 0.045</li><li>แรงดันไฟฟ้า: 220V</li><li>อัตราการพ่น: 9 ลิตร/นาที</li><li>กำลังไฟฟ้า: 3000W</li><li>แรงดันสูงสุด: 220 บาร์</li><li>สายพ่นสี: 15 เมตร (3/8)</li><li>แรงม้า: 4HP</li></ul><h5> </h5><h5><strong>ข้อมูลเฉพาะ:</strong></h5><ul><li>สามารถดูดสกิมโค้ทที่มีความหนืดสูงได้</li><li>สามารถพ่นสกิมโค้ทได้ทั้งปูนสำเร็จรูปและปูนที่ต้องผสมเอง</li><li>สามารถปรับแรงดันและปริมาณการออกของปูนสกิมได้</li><li>สามารถพ่นสีที่มีความหนืดสูงได้ เช่น สีกันไฟ</li><li>เครื่องพ่นสกิมโค้ทช่วยเพิ่มประสิทธิภาพในการทำงานและให้ผลงานที่มีคุณภาพ เหมาะสำหรับการใช้งานในแวดวงก่อสร้างและตกแต่งอาคาร</li></ul><p> </p><h5><strong>หมายเหตุ:</strong> รับประกันมอเตอร์ 1 ปี (ไม่รวมอะไหล่)</h5>[media url=https://www.youtube.com/watch?v=7zrRjW_ddCM][/media]', 'published', '[\"products\\/rb-1060-3.webp\",\"products\\/rubyshop-rb-1060-2-in-1-skim-coat-machine-airless.webp\",\"products\\/rubyshop-rb-1060-2-in-1-skim-coat-machine-airless-1.webp\",\"products\\/rubyshop-rb-1060-2-in-1-skim-coat-machine-airless-2.webp\",\"products\\/rubyshop-rb-1060-2-in-1-skim-coat-machine-airless-3.webp\",\"products\\/rubyshop-rb-1060-2-in-1-skim-coat-machine-airless-4.webp\",\"products\\/rubyshop-rb-1060-2-in-1-skim-coat-machine-airless-5.webp\"]', NULL, 'NN-2443-RTUGA', 0, 4, 0, NULL, 0, 0, 'in_stock', 1, NULL, 0, 0, 89000, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1132, '2025-03-12 20:51:55', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/rb-1060-3-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(225, 'RUBYSHOP เครื่องพ่นสกิมโค้ท ระบบไดอะแฟรม รุ่น RBPU-999 2 IN 1 Skim coat machine &amp; Airless sprayer', '<ul><li><h5>2 IN 1: เป็นทั้งเครื่องพ่นสกิมโค้ทและเครื่องพ่นสีในเครื่องเดียว คุ้มค่าและอเนกประสงค์</h5></li><li><h5>ระบบไดอะแฟรม: เหมาะสำหรับวัสดุที่มีความหนืดสูง เช่น สกิมโค้ท พ่นได้เรียบเนียน ไม่สะดุด</h5></li><li><h5>พ่นได้รวดเร็ว: อัตราการพ่น 8 ลิตร/นาที ช่วยให้งานเสร็จไว</h5></li><li><h5>มอเตอร์ทรงพลัง: 3000W (4HP) ให้แรงดันสูง พ่นสีได้สม่ำเสมอ</h5></li><li><h5>แรงดันสูงสุด 25 MPa: เหมาะสำหรับงานหนักและงานที่ต้องการความละเอียดสูง</h5></li></ul><p> </p><p> </p>', '<h5><strong>รายละเอียดสินค้า</strong></h5><h6>RUBYSHOP เครื่องพ่นสกิมโค้ท รุ่น RBPU-999 เป็นเครื่องพ่นสีและสกิมโค้ทอเนกประสงค์ที่มาพร้อมระบบไดอะแฟรมประสิทธิภาพสูง เหมาะสำหรับงานซ่อมแซมและตกแต่งผนังทั้งภายในและภายนอกอาคาร ด้วยกำลังมอเตอร์ที่ทรงพลังและแรงดันที่สูง ทำให้สามารถพ่นสกิมโค้ทและสีได้อย่างเรียบเนียน สม่ำเสมอ และรวดเร็ว</h6><h2> </h2><h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>2 IN 1</strong>: พ่นสกิมโค้ทและสีได้</li><li><strong>ระบบไดอะแฟรม</strong>: เหมาะสำหรับวัสดุหนืด</li><li><strong>อัตราการพ่น</strong>: 8 ลิตร/นาที</li><li><strong>กำลังมอเตอร์</strong>: 3000W (4HP)</li><li><strong>แรงดันสูงสุด</strong>: 25 MPa</li><li><strong>รองรับหัวทิป</strong>: 0.039</li></ul><h2> </h2><h5><strong>เหมาะสำหรับ</strong></h5><ul><li>งานซ่อมแซมผนัง</li><li>งานตกแต่งผนัง</li><li>งานพ่นสกิมโค้ท</li><li>งานพ่นสี</li></ul><h2> </h2><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรสวมใส่อุปกรณ์ป้องกันความปลอดภัยที่เหมาะสมขณะใช้งาน</li></ul>[media url=https://youtu.be/XgxoNBkECwE][/media]', 'published', '[\"products\\/rbpu-999-1.webp\",\"products\\/rbpu-999-2.webp\",\"products\\/rbpu-999-4.webp\",\"products\\/rbpu-999-6.webp\"]', NULL, 'NN-2443-KUYMU', 0, 5, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 75000, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 899, '2025-03-12 20:52:29', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/rbpu-999-1-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(226, 'RUBYSHOP ถังเทคเจอร์ Texture sprayer 30L ใช้พ่นกาว พ่นสี หรือเคมีภัณฑ์ที่มีความหนืดสูง', '<ul><li><h5>ถังพ่นเทคเจอร์ขนาด 30 ลิตร คุณภาพเยี่ยม </h5></li><li><h5>ออกแบบมาเพื่องานตกแต่งผนังลวดลายเทคเจอร์โดยเฉพาะ </h5></li><li><h5>ให้พลังแรงดันสูงช่วยให้การพ่นวัสดุทำเทคเจอร์ผนังเป็นไปอย่างรวดเร็ว </h5></li><li><h5>ลดเวลาและแรงงาน ถังขนาดใหญ่ช่วยให้ทำงานต่อเนื่องได้ยาวนาน </h5></li><li><h5>แข็งแรง ทนทาน และเคลื่อนย้ายสะดวก เหมาะสำหรับทั้งงานขนาดเล็กและขนาดใหญ่</h5><h5> </h5></li></ul><h5> </h5>', '<h5><strong>รายละเอียดสินค้า</strong></h5><ul><li>ใช้พ่นสี พ่นกาว หรือเคมีภัณฑ์ที่มีความหนืดสูง</li><li>ตัวถังบรรจุได้ 30 ลิตร</li><li>แรงดันสูงสุด 0.1-0.25 bar</li><li>มีล้อเคลื่อนย้ายสะดวก</li></ul><h5> </h5><h5><strong>คุณสมบัติเด่น</strong></h5><ol><li>ระบบแรงดันสูง ให้การพ่นกระจายทั่วถึงและสม่ำเสมอ</li><li>ความจุ 30 ลิตร รองรับงานขนาดกลางถึงขนาดใหญ่</li><li>มีล้อสำหรับเคลื่อนย้ายจุดทำงานได้ง่าย</li><li>กระบอกสูบอะลูมิเนียม แข็งแรง ทนทานต่อการใช้งานหนัก</li><li>รองรับการใช้งานร่วมกับปั๊มลมขนาดใหญ่ ทำให้พ่นได้รวดเร็ว ประหยัดเวลา</li><li>ระบบควบคุมการไหลแม่นยำ ปรับแต่งการพ่นได้ตามต้องการ</li></ol><p> </p>', 'published', '[\"products\\/2-6.webp\",\"products\\/3-6.webp\",\"products\\/1-10.webp\"]', NULL, 'NN-2443-8VDXM', 0, 6, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 35000, 25000, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 842, '2025-03-12 20:52:30', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/2-7.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(227, 'RUBYSHOP เครื่องพ่นสีไฟฟ้า รุ่น RB-360 เล็ก เบา แรง พ่นสีได้ทุกที่', '<ul><li><h5>พกพาสะดวก: น้ำหนักเบาเพียง 17 กก. เคลื่อนย้ายง่าย</h5></li><li><h5>สายพ่นสี 10 เมตร: ใช้งานได้คล่องตัว ครอบคลุมพื้นที่กว้าง</h5></li><li><h5>มอเตอร์ทรงพลัง: 1100W ทำงานราบรื่น พ่นสีได้สม่ำเสมอ</h5></li><li><h5>แรงดันสูง: 20Mpa พ่นสีได้ทั่วถึง แม้ในพื้นที่เข้าถึงยาก</h5></li><li><h5>หัวพ่นหลากหลาย: ปรับขนาดหัวพ่นให้เหมาะกับงานได้</h5><h5> </h5></li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><h6>RUBYSHOP เครื่องพ่นสีไฟฟ้า รุ่น RB-360 เป็นเครื่องพ่นสีแรงดันสูงที่ออกแบบมาให้มีขนาดเล็ก น้ำหนักเบา พกพาสะดวก แต่ยังคงประสิทธิภาพในการพ่นสีสูง ด้วยมอเตอร์กำลังสูงและแรงดันที่ทรงพลัง ทำให้สามารถพ่นสีได้อย่างทั่วถึง แม้ในพื้นที่เข้าถึงยาก เหมาะสำหรับงานพ่นสีทั้งภายในและภายนอกอาคาร</h6><h6> </h6><h5><strong>ข้อดีของการใช้เครื่องพ่นสีแอร์เลส</strong></h5><ul><li>ประหยัดเวลาและแรงงาน</li><li>เคลื่อนที่สะดวก ใช้งานได้ทุกมุม</li><li>พ่นสีได้ทั่วถึง</li><li>ควบคุมการพ่นได้ละเอียดและแม่นยำ</li></ul><h2> </h2><h5><strong>เคล็ดลับการใช้งานให้มีประสิทธิภาพ</strong></h5><ul><li>เตรียมพื้นผิวให้สะอาดและแห้ง</li><li>เลือกขนาดหัวพ่นที่เหมาะสม</li><li>ปรับแรงดันให้เหมาะกับชนิดของสี</li><li>พ่นสีด้วยการเคลื่อนที่แบบเส้นขนาน</li><li>ทำความสะอาดเครื่องหลังใช้งาน</li></ul><h2> </h2><h5><strong>การรับประกัน</strong></h5><ul><li>รับประกันมอเตอร์ 1 ปี (ไม่รวมอะไหล่)</li></ul>', 'published', '[\"products\\/rubyshop-rb-360-2-1.webp\",\"products\\/rubyshop-rb-360-2.webp\",\"products\\/rubyshop-rb-360-3.webp\",\"products\\/rubyshop-rb-360-6.webp\",\"products\\/rubyshop-rb-360-5.webp\"]', NULL, 'NN-2443-LBCXM', 0, 49, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 14900, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 971, '2025-03-12 20:52:40', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/rb-360.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(228, 'RUBYSHOP เครื่องพ่นสีแรงดันสูงไร้สาย รุ่น RB-534 เครื่องพ่นสีไร้สาย เครื่องพ่นสีสะพายข้าง Airless sprayer เครื่องพ่นสีไฟฟ้าไร้สาย', '<ul><li><h5><span>เครื่องพ่นสีแรงดันสูงไร้สายแบบสะพายข้าง </span></h5></li><li><h5><span>เป็นอุปกรณ์พ่นสีที่ออกแบบมาให้มีความคล่องตัวสูง </span></h5></li><li><h5><span>เหมาะสำหรับงานพ่นสีทั้งภายในและภายนอก ด้วยระบบ Airless Sprayer </span></h5></li><li><h5><span>ช่วยให้การพ่นสีมีความแม่นยำและลดการฟุ้งกระจายของสี</span></h5></li></ul><p> </p><p> </p>', '<h5><strong>รายละเอียดสินค้า </strong> <br> </h5><ul><li>ใช้สำหรับพ่นสีเก็บรายละเอียดงานภายในและภายนอก</li><li>ไม่ฟุ้งกระจาย เพราะเป็นระบบ Airless Sprayer</li><li>ใช้งานได้โดยไม่ต้องเสียบปลั๊ก ใช้แบตเตอรี่ขนาด 21V</li><li>มีปั๊มลมในตัว พร้อมสายสะพาย พกพาสะดวก</li><li>รองรับการใช้งานกับสีน้ำ สีพลาสติก และสีน้ำมัน</li><li>ไม่ต้องใช้ปั๊มลมและสายลม สามารถใช้งานได้ทันที</li><li>เหมาะสำหรับพ่นสีภายนอก ภายใน รั้ว เฟอร์นิเจอร์ หน้าต่าง ประตู ผนังบ้าน ฯลฯ</li></ul><h5> </h5><h5><strong>ข้อมูลทางเทคนิค</strong></h5><ul><li>แบตเตอรี่: Li-ion 21V</li><li>ความจุถังสี: 2 ลิตร</li><li>รองรับหัวพ่นสูงสุด: 0.019</li><li>ความยาวสายพ่น: 1.5 เมตร</li><li>น้ำหนักเครื่อง: 5 กิโลกรัม</li><li>กำลังไฟฟ้า: 1000 วัตต์</li><li>แรงดันไฟฟ้า: 220 โวลต์</li><li>ขนาดหัวพ่น (Spray Tip): 0.017</li><li>แรงดูดสี: 1.7 ลิตรต่อนาที</li><li>แรงดันลม: 200 bar</li></ul><h5> </h5><h5><strong>คุณสมบัติเด่น</strong></h5><ul><li>ใช้แบตเตอรี่ลิเธียมไอออนขนาดใหญ่ พลังงานสูง ใช้งานได้ยาวนาน</li><li>มอเตอร์ไร้แปรงถ่าน ประสิทธิภาพสูง ทนทานต่อการใช้งานหนัก</li><li>ระบบพ่นสีแรงดันสูงแบบไร้สาย ลดการสูญเสียสีและช่วยประหยัดสี</li><li>ปั๊มสูบละเอียด ควบคุมการไหลของสีได้สม่ำเสมอ</li><li>รองรับหัวพ่นหลากหลายรูปแบบ สำหรับงานที่แตกต่างกัน</li></ul><h5> </h5><h5><strong>ขั้นตอนการใช้งาน</strong></h5><ol start=\"1\"><li>เตรียมพื้นผิวและปิดคลุมบริเวณที่ไม่ต้องการให้สีกระเด็น</li><li>เติมสีลงในถังบรรจุของเครื่องพ่น</li><li>เลือกหัวพ่นที่เหมาะสมและปรับแรงดันตามความต้องการ</li><li>พ่นสีโดยให้หัวพ่นขนานกับพื้นผิว เคลื่อนที่ไปอย่างสม่ำเสมอ</li><li>พักเครื่องเป็นระยะเพื่อป้องกันมอเตอร์ร้อนเกินไป</li><li>เมื่อแบตเตอรี่ใกล้หมด ให้ชาร์จไฟเพื่อเตรียมใช้งานต่อ</li></ol><h6> </h6><h5><strong>สรุป  </strong></h5><h6>เครื่องพ่นสีแรงดันสูงไร้สาย RUBYSHOP รุ่น RB-534 เป็นตัวเลือกที่ยอดเยี่ยมสำหรับผู้ที่ต้องการความสะดวกและประสิทธิภาพในการพ่นสี ช่วยให้การทำงานรวดเร็ว ละเอียด และประหยัดแรงงาน เหมาะสำหรับทั้งงานภายในและภายนอกบ้าน</h6><h6>หมายเหตุ: รับประกันมอเตอร์ 1 ปี (ไม่รวมอะไหล่)</h6>[media url=https://youtu.be/ywNiApAgTWM][/media]', 'published', '[\"products\\/1-11.webp\",\"products\\/rb-534-1.webp\",\"products\\/rb-534-5.webp\",\"products\\/rb-534-3.webp\",\"products\\/rb-534-2.webp\"]', NULL, 'NN-2443-ITLIO', 0, 7, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 9900, 8500, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 917, '2025-03-12 20:52:46', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/rb-534-1-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(229, 'RUBYSHOP เครื่องพ่นสีแรงดันสูง แบบพกพา รุ่น RB-DQ-600 กำลัง 1600 วัตต์ ถังบรรจุสี 2 ลิตร', '<ul><li><h5>เครื่องพ่นสีระบบไฟฟ้า Airless Sprayer เหมาะสำหรับพ่นสีน้ำ สีน้ำมัน </h5></li><li><h5>ใช้ในงานพ่นสีผนัง ประตู หน้าต่าง หรือการเก็บงานสีขนาดเล็ก จนถึงงาน DIY ต่างๆ </h5></li><li><h5>สามารถใช้ได้ทั้งภายนอก และภายใน เป็นต้น หัวพ่นสีเป็นแบบ Spray tip </h5></li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><ul><li>เครื่องพ่นสีแรงดันสูงแบบพกพา RUBYSHOP รุ่น RB-DQ-600</li><li>พกพาสะดวก เคลื่อนย้ายง่าย ใช้งานรวดเร็ว เพียงเสียบปลั๊ก</li><li>หัวพ่น Spray Tip 515 เหมาะสำหรับพ่นสีเฟอร์นิเจอร์, รั้ว, กำแพง และงานเก็บรายละเอียด</li><li>รองรับทั้งสีน้ำและสีน้ำมัน ใช้งานได้กับช่างมือใหม่และมืออาชีพ</li><li>วัสดุคุณภาพดี ทนทานต่อการใช้งาน</li><li>พ่นสีน้ำได้รวดเร็ว ใช้งานต่อเนื่องได้นานกว่า 1 ชั่วโมง</li><li>น้ำหนักเบา สะดวกต่อการใช้งาน, จัดเก็บ และเคลื่อนย้าย</li></ul><h5> </h5><h5><strong>ข้อมูลทางเทคนิค</strong></h5><ul><li>กำลังไฟ : 1600W</li><li>กระแสไฟ : 220V</li><li>อัตราการพ่นสีสูงสุด : 2.5 ลิตร/นาที</li><li>รองรับขนาดหัวพ่นสูงสุด : 515</li><li>มอเตอร์ : Brush Motor</li></ul><h5> </h5><h5><strong>การใช้งานที่เหมาะสม</strong></h5><ul><li>เครื่องขนาดเล็ก พกพาสะดวก</li><li>เหมาะสำหรับงานพ่นสีภายในและภายนอก ในโครงสร้างขนาดเล็ก</li><li>ใช้กับเฟอร์นิเจอร์, ประตู, รางน้ำ, งานตัดแต่งต่างๆ</li><li>สามารถปรับระดับแรงดันได้</li></ul><h5> </h5><h5><strong>สีที่สามารถใช้งานได้</strong></h5><ul><li>สีน้ำ</li><li>สีน้ำมัน</li><li>สีที่มีความหนืดไม่มาก</li></ul><h5> </h5><h5><strong>คุณสมบัติเด่น</strong></h5><ul><li>วัสดุคุณภาพสูง แข็งแรง ทนทาน</li><li>พ่นงานสีน้ำเสร็จไว ใช้งานต่อเนื่องได้นาน</li><li>น้ำหนักเบา ใช้งานและจัดเก็บสะดวก</li></ul><h5> </h5><h5><strong>ขั้นตอนการใช้งาน</strong></h5><ul><li>เตรียมพื้นที่และปิดคลุมบริเวณที่ไม่ต้องการให้สีกระเซ็น</li><li>เติมสีลงในถังบรรจุของเครื่องพ่น</li><li>เลือกหัวพ่นที่เหมาะสม และปรับแรงดันการพ่นตามต้องการ</li><li>พ่นสีให้หัวพ่นขนานกับพื้นผิว และเคลื่อนที่ด้วยจังหวะสม่ำเสมอ</li><li>พักการพ่นเป็นระยะ เพื่อป้องกันมอเตอร์ร้อนเกินไป</li><li>เมื่อแบตเตอรี่ใกล้หมด ให้ชาร์จไฟทันที</li></ul><h5> </h5><h5><strong>หมายเหตุ</strong> : รับประกันมอเตอร์ 1 ปี (ไม่รวมอะไหล่)</h5>', 'published', '[\"products\\/m2.jpg\",\"products\\/rb-dq-600-6.webp\",\"products\\/rb-dq-600-7.webp\",\"products\\/rb-dq-600-5.webp\",\"products\\/rb-dq-600-4.webp\",\"products\\/rb-dq-600-3.webp\",\"products\\/rb-dq-600-2.webp\",\"products\\/rb-dq-600-8.webp\"]', NULL, 'NN-2443-USHT7', 0, 8, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 6497, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 974, '2025-03-12 20:52:55', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/m2-1.jpg', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(230, 'RUBYSHOP เครื่องพ่นสีแรงดันสูง แบบพกพา รุ่น RB-HD-2100 แรงดูดสี 2 ลิตรต่อนาที', '<ul><li>พกพาสะดวก: ขนาดเล็ก น้ำหนักเบา เคลื่อนย้ายง่าย</li><li>แรงดูดสีสูง: 2 ลิตรต่อนาที พ่นสีได้อย่างรวดเร็วและมีประสิทธิภาพ</li><li>มอเตอร์ทรงพลัง: มอเตอร์ประสิทธิภาพสูง ให้แรงดันที่สม่ำเสมอ</li><li>แรงดันสูงสุด 3000 Psi: เหมาะสำหรับงานพ่นสีหลากหลายประเภท</li><li>ระบบ Pressure switch: ตัดการทำงานเมื่อหยุดพ่นสี ปลอดภัยและประหยัดพลังงาน</li><li>ใช้งานง่าย: เหมาะสำหรับทั้งมืออาชีพและผู้ใช้งานทั่วไป</li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><ul><li>แรงดูดสี 2 ลิตรต่อนาที พร้อมพ่นสีบ้านและงานพ่นสีทุกประเภท</li><li>ดีไซน์กะทัดรัด น้ำหนักเพียง 6 กิโลกรัม</li><li>มาพร้อมการทำงานแบบ Pressure switch เพื่อการทำงานที่ต่อเนื่อง</li><li>Airless Sprayer แรง 1010 วัตต์</li><li>ความดันสูงสุด 3000 Psi</li><li>สายพ่นสีความยาว 10 เมตร</li><li>โครงสร้างผลิตจากวัสดุคุณภาพสูง แข็งแรง ทนทาน</li></ul><h5> </h5><h5><strong>อุปกรณ์ในชุด</strong></h5><ul><li>ปืนพ่นสี</li><li>Spray tip 515</li><li>สายพ่นสี 10 เมตร</li></ul><p> </p><h5><strong>ฟังก์ชันพิเศษ</strong></h5><ul><li>แรงดูดสี 2 ลิตรต่อนาที</li><li>น้ำหนักเบา เคลื่อนย้ายสะดวก</li><li>มอเตอร์รอบเร็ว ประสิทธิภาพสูง</li><li>พลังแรงสูงสุด 3000 Psi</li><li>ระบบ Pressure switch ตัดการทำงานอัตโนมัติเมื่อหยุดพ่นสี</li></ul><p> </p><h5><strong>วิธีการใช้งานเครื่องพ่นสีแรงดันสูง</strong></h5><h5><strong>1. การเตรียมอุปกรณ์</strong></h5><ul><li>ตรวจสอบว่าเครื่องพ่นสีอยู่ในสภาพพร้อมใช้งาน</li><li>เตรียมสีที่จะใช้ โดยกรองและผสมตามคำแนะนำของผู้ผลิต</li><li>สวมอุปกรณ์ป้องกัน เช่น แว่นตา หน้ากาก และถุงมือ</li></ul><h5><strong>2. การตั้งค่าเครื่อง</strong></h5><ul><li>เชื่อมต่อสายยางและปืนพ่นสีเข้ากับเครื่อง</li><li>ปรับแรงดันให้เหมาะสมกับประเภทของสีและพื้นผิว</li><li>เลือกหัวพ่นที่เหมาะสม</li></ul><h5><strong>3. การทดสอบ</strong></h5><ul><li>พ่นสีลงบนกระดาษหรือวัสดุทดสอบ</li><li>ปรับระยะห่างและความเร็วในการพ่นให้เหมาะสม</li></ul><h5><strong>4. เทคนิคการพ่น</strong></h5><ul><li>ถือปืนพ่นสีให้ตั้งฉากกับพื้นผิว</li><li>รักษาระยะห่างที่สม่ำเสมอ (ประมาณ 15-30 ซม.)</li><li>เคลื่อนปืนพ่นสีในแนวนอนหรือแนวตั้งอย่างต่อเนื่อง</li><li>ทับซ้อนแต่ละแนวประมาณ 50%</li></ul><h5><strong>5. การทำความสะอาด</strong></h5><ul><li>ทำความสะอาดเครื่องพ่นสีทันทีหลังใช้งาน</li><li>ใช้น้ำยาทำความสะอาดที่เหมาะสมกับประเภทของสี</li></ul><p> </p><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ห้ามพ่นสีใกล้เปลวไฟหรือประกายไฟ</li><li>ทำงานในพื้นที่ที่มีอากาศถ่ายเทสะดวก</li><li>ระวังการพ่นสีเกินพื้นที่ที่ต้องการ</li></ul><h5><strong>หมายเหตุ:</strong> รับประกันมอเตอร์ <strong>1 ปี</strong> (ไม่รวมอะไหล่)</h5><p> </p>', 'published', '[\"products\\/rr.jpg\",\"products\\/rb-hd-21007.webp\",\"products\\/rb-hd-2100-9.webp\",\"products\\/rb-hd-2100-5.webp\",\"products\\/rb-hd-21006.webp\",\"products\\/rb-hd-2100-8.webp\",\"products\\/rb-hd-2100-10.webp\"]', NULL, 'NN-2443-NMIH3', 0, 9, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 9900, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1012, '2025-03-12 20:53:03', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/rr-1.jpg', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(231, 'เทปฟิล์มกันเปื้อนสำหรับงานพ่นสี Masking Tape ขนาด 55 ซม.', '<p>ใช้สำหรับงานพ่นสี ปกป้องพื้นผิวจากสีและฝุ่น ลดการเปื้อนระหว่างพ่นสี<br>เนื้อเทปกาวคุณภาพดี ผ่านกระบวนการผลิตที่ได้มาตรฐาน<br>ลอกออกง่าย ไม่ทิ้งคราบกาว หลังใช้งาน<br>ใช้งานสะดวก ติดแน่น และไม่ทำลายพื้นผิว</p>', '<h5><strong>รายละเอียดสินค้า</strong></h5><ul><li>เทปพ่นสี ใช้สำหรับปกป้องพื้นผิวจากสีและฝุ่น</li><li>เหมาะสำหรับงานพ่นสี เช่น<ul><li>   งานพ่นสีรถยนต์</li><li>   งานตกแต่งชิ้นงาน</li><li>   งานพ่นสีโมเดล</li></ul></li><li>เนื้อกาวคุณภาพสูง ไม่ทิ้งคราบกาวหลังใช้งาน</li><li>รูปแบบม้วน ใช้งานง่าย พกพาสะดวก</li><li>ขนาด: 50 ซม.</li><li><p>สี: ใส</p><p> </p></li></ul>', 'published', '[\"products\\/lw.jpg\"]', NULL, 'NN-2443-YTAGP', 0, 10, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 39, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 829, '2025-03-12 20:53:05', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/lw-1.jpg', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(232, 'เทปฟิล์มกันเปื้อนสำหรับงานทาสี Masking Tape ขนาด 110x150 ซม. สีใส', '<ul><li><h5>เทปฟิล์มกันเปื้อนเป็นอุปกรณ์ที่ใช้ในงานทาสีหรือพ่นสี </h5></li><li><h5>ป้องกันไม่ให้สีเปื้อนในพื้นที่ที่ไม่ต้องการ</h5></li><li><h5>เชื่อมต่อไปกับพื้นผิวเรียบและช่วยในการกำหนดขอบเขตของงานสี </h5></li><li><h5>กาวของเทปมีคุณภาพดี หนาแน่นและไม่ทิ้งคราบกาวเมื่อทำการลอกออก </h5></li><li><h5>นอกจากนี้ยังผลิตจากวัสดุที่ทนทานและไม่ขาดง่าย ทำให้สะดวกต่อการใช้งาน</h5></li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><ul><li>เทปฟิล์มกันเปื้อน ขนาด 110x150 ซม. สีใส</li><li>ใช้สำหรับงานทาสีหรือพ่นสี</li><li>กันเปื้อนบริเวณที่ต้องการ</li><li>ปกป้องพื้นผิวจากสีและฝุ่น</li><li>เนื้อเทปกาวคุณภาพดี</li><li>ลอกออกง่าย ไม่ทิ้งคราบกาว</li></ul><p> </p><h5><strong>รายละเอียดเพิ่มเติม</strong></h5><ul><li>เทปฟิล์มกันเปื้อนสำหรับงานทาสี Masking Tape</li><li>ขนาด 110x150 ซม. สีใส</li></ul><p> </p><h5><strong>คุณสมบัติสินค้า</strong></h5><ul><li>เทปฟิล์มกันเปื้อน ขนาด 110x150 ซม. สีใส</li><li>ใช้สำหรับงานทาสีหรือพ่นสี</li><li>กันเปื้อนบริเวณที่ต้องการ</li><li>ปกป้องพื้นผิวจากสีและฝุ่น</li><li>เนื้อเทปกาวคุณภาพดี</li><li>ลอกออกง่าย ไม่ทิ้งคราบกาว</li></ul><p> </p><h5><strong>การใช้งานเทปฟิล์ม</strong></h5><ul><li>ใช้แปะบริเวณรอยต่อขอบที่จะพ่นสี</li><li>ควรทำความสะอาดพื้นผิวให้แห้ง สะอาด ปราศจากเศษขี้ฝุ่น</li><li>เทปที่มีความยืดหยุ่นจะง่ายต่อการติดในพื้นที่โค้งหรือมุม</li></ul>', 'published', '[\"products\\/yj.jpg\"]', NULL, 'NN-2443-KLT0S', 0, 11, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 89, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 842, '2025-03-12 20:53:06', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/yj-1.jpg', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
