(256, 'RUBYSHOP กระดาษทราย 50 แผ่น เบอร์ 320 ขนาด 7 นิ้ว สำหรับเครื่องขัดผนัง รุ่น RB-DWS-180S | sandpaper', '', '<h5><strong>รายละเอียดสินค้า</strong></h5><ul><li>กระดาษทรายขนาด 7 นิ้ว เบอร์ 320</li><li>สำหรับขัดผนังสกิมโค้ท แบบเรียบ เตรียมพื้นผิว ก่อนลงสีจริง ใช้กับเครื่องขัดผนังด้ามสั้น  </li><li>เบอร์ 320 (ละเอียด)  </li><li>มี 8 รู หน้ากวว้าง 7 นิ้ว  </li><li>ขัดพื้นผิวสกิมโค้ท ได้เรียบเนียร ลบรอยตามดได้เป็นอย่างดี  </li><li>หลังกระดาษทรายเป็นสักหลาด หรือเรียกว่าตีนตุ๊กแก  </li><li>สินค้าใหม่ 100%</li></ul>', 'published', '[\"products\\/1-25.webp\",\"products\\/4-12.webp\",\"products\\/5-7.webp\",\"products\\/6-4.webp\",\"products\\/3-16.webp\",\"products\\/2-21.webp\"]', NULL, 'NN-2443-XBA75-6SCBx-v0WFB-PELQt-9cuh5', 0, 32, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 600, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 807, '2025-03-12 20:54:08', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/1-26.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(257, 'RUBYSHOP  เครื่องขัดผนังไร้ฝุ่น มือจับสั้น ระบบดูดฝุ่นในตัว RB-DWS700F แรงวัตต์ 800W หน้ากว้าง 9 นิ้ว', '<h5>เครื่องขัดผนัง RB-DWS700F ช่วยให้การขัดพื้นผิวเป็นเรื่องง่ายและมีประสิทธิภาพ ไม่ว่าจะเป็นผนังหรือพื้น ด้วยเครื่องดูดฝุ่นในตัวที่มีความสามารถในการเก็บฝุ่นได้สูงถึง 95% และถุงเก็บฝุ่นที่มีขนาดใหญ่พอที่จะเก็บฝุ่นได้มากพอสำหรับการใช้งานทั้งวัน เป็นเครื่องมือที่มีคุณภาพและประสิทธิภาพสูง ที่จะช่วยให้งานของคุณกลายเป็นเรื่องง่ายและรวดเร็วขึ้น</h5>', '<h5><strong>รายละเอียดสินค้า </strong></h5><ul><li>เครื่องขัดผนังช่วยขัดพื้นผิวให้เรียบเนียน</li><li>กำลังไฟฟ้า 800W</li><li>ความดันไฟฟ้า 220V~50Hz</li><li>มีเครื่องดูดฝุ่นในตัว</li><li>สามารถเก็บฝุ่นได้ถึง 95%</li><li>ถุงเก็บฝุ่นใหญ่ สะพายหลังได้</li><li>ความเร็ว 1000-1800 r/min</li><li>ปรับระดับการใช้งานได้ถึง 6 ระดับ</li><li>เส้นผ่าศูนย์กลางใบขัด 9 นิ้ว</li><li>มือจับสั้น ไม่มีด้ามจับ</li><li>สินค้าใหม่ 100%</li></ul><h5> </h5><h5><strong>ข้อมูลจำเพาะ</strong></h5><ul><li>แรงดันไฟฟ้า: 220 โวลต์</li><li>กระดาษทราย: 225 มม. (9 นิ้ว)</li><li>ความเร็วรอบ: 1000-1800 รอบ/นาที</li><li>กำลังมอเตอร์: 800 วัตต์</li><li>ความยาวสายไฟ: 3 เมตร</li></ul><h5> </h5><h5><strong>อุปกรณ์ภายในชุดประกอบด้วย</strong></h5><ul><li>เครื่องขัดผนัง</li><li>ถุงเก็บฝุ่น</li><li>แปรงถ่าน</li><li>ท่อดูดฝุ่น 2 เมตร</li><li>กระดาษทราย 6 เบอร์ 6 แผ่น</li></ul><p> </p>', 'published', '[\"products\\/03-copy-r.jpg\",\"products\\/01-r.jpg\",\"products\\/06-r.jpg\",\"products\\/07-r.jpg\",\"products\\/05-r.jpg\"]', NULL, 'NN-2443-W4B0V', 0, 33, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 4994, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 810, '2025-03-12 20:54:09', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/03-copy-r-1.jpg', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
