(263, 'RUBYSHOP ตลับเมตรเลเซอร์ รุ่น RB-LS001: วัดแม่นยำ รวดเร็ว จบงานง่าย', '<ul><li>ปรับระดับอัตโนมัติ: ช่วยให้การวัดระดับเป็นเรื่องง่ายและแม่นยำ</li><li>ใช้งานต่อเนื่องยาวนาน: ใช้งานได้ต่อเนื่องถึง 1 ชั่วโมง</li><li>ค่าความคาดเคลื่อนต่ำ: ±0.6 มม. ให้ผลลัพธ์ที่แม่นยำ</li><li>ระยะวัดสูงสุด 10 เมตร: ครอบคลุมการใช้งานหลากหลาย</li><li><p>แบตเตอรี่ใช้งานได้นาน: 20 ชั่วโมง ใช้งานได้ต่อเนื่อง</p><p> </p></li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><p>RUBYSHOP ตลับเมตรเลเซอร์ รุ่น RB-LS001 เป็นเครื่องวัดระยะทางด้วยเลเซอร์ที่ออกแบบมาเพื่อตอบโจทย์งานวัดที่ต้องการความแม่นยำ รวดเร็ว และสะดวกสบาย ด้วยคุณสมบัติที่หลากหลายและใช้งานง่าย ทำให้เป็นเครื่องมือที่เหมาะสำหรับทั้งมืออาชีพและผู้ใช้งานทั่วไป</p><h5> </h5><h5><strong>คุณสมบัติเด่น</strong></h5><ul><li>ปรับระดับอัตโนมัติ</li><li>ใช้งานต่อเนื่อง 1 ชั่วโมง</li><li>ค่าความคาดเคลื่อน ±0.6 มม.</li><li>ระยะวัดสูงสุด 10 เมตร</li><li>แบตเตอรี่ใช้งานได้ 20 ชั่วโมง</li><li>เลเซอร์ปลอดภัย</li><li>ใช้ถ่าน AAA</li></ul><p> </p><h5><strong>เหมาะสำหรับ</strong></h5><ul><li>งานก่อสร้าง</li><li>งานสำรวจ</li><li>งานออกแบบ</li><li>งาน DIY ทั่วไป</li></ul><h2> </h2>', 'published', '[\"products\\/2-27.webp\",\"products\\/1-35.webp\",\"products\\/3-21.webp\"]', NULL, 'NN-2443-UO0ST', 0, 39, 0, NULL, 0, 0, 'in_stock', 0, 0, 0, 0, 100, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 702, '2025-03-12 20:54:34', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/2-28.webp', 'physical', '', NULL, 0, 0, 0, 0, NULL),
(264, 'RUBYSHOP ตลับเมตรเลเซอร์ รุ่น RB-D80: วัดแม่นยำ รวดเร็ว จบงานง่าย', '<ul><li>วัดระยะทางแม่นยำ: ด้วยเลเซอร์ที่มีความแม่นยำสูง ช่วยให้การวัดระยะทางเป็นเรื่องง่ายและแม่นยำ</li><li>วัดพื้นที่และปริมาตร: คำนวณพื้นที่และปริมาตรได้โดยอัตโนมัติ ช่วยประหยัดเวลาและลดความผิดพลาด</li><li>เปลี่ยนหน่วยวัดได้: เลือกหน่วยวัดที่ต้องการได้ตามความสะดวก (เมตร, นิ้ว, ฟุต)</li><li>ใช้งานง่าย: ปุ่มควบคุมใช้งานง่าย ไม่ซับซ้อน</li><li><p>พกพาสะดวก: ขนาดเล็ก น้ำหนักเบา พกพาไปใช้งานได้ทุกที่</p><p> </p></li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><p>RUBYSHOP ตลับเมตรเลเซอร์ รุ่น RB-D80 เป็นเครื่องวัดระยะทางด้วยเลเซอร์ที่ออกแบบมาเพื่อตอบโจทย์งานวัดที่ต้องการความแม่นยำ รวดเร็ว และสะดวกสบาย ด้วยคุณสมบัติที่หลากหลายและใช้งานง่าย ทำให้เป็นเครื่องมือที่เหมาะสำหรับทั้งมืออาชีพและผู้ใช้งานทั่วไป</p><h5> </h5><h5><strong>คุณสมบัติเด่น</strong></h5><ul><li>วัดระยะทางด้วยเลเซอร์ที่มีความแม่นยำสูง</li><li>คำนวณพื้นที่และปริมาตรโดยอัตโนมัติ</li><li>เปลี่ยนหน่วยวัดได้ (เมตร, นิ้ว, ฟุต)</li><li>ใช้งานง่าย</li><li>พกพาสะดวก</li><li>ทนทาน</li></ul><h5> </h5><h5><strong>ข้อมูลทางเทคนิค</strong></h5><ul><li>(ข้อมูลทางเทคนิคเพิ่มเติมสามารถสอบถามได้จากทางร้าน)</li></ul><h2> </h2><h5><strong>เหมาะสำหรับ</strong></h5><ul><li>งานก่อสร้าง</li><li>งานสำรวจ</li><li>งานออกแบบ</li><li>งาน DIY ทั่วไป</li></ul><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ระมัดระวังเลเซอร์ ไม่ควรให้เลเซอร์เข้าตา</li></ul><h2> </h2>', 'published', '[\"products\\/rb-d80m-01.webp\",\"products\\/rb-d80m-05.webp\",\"products\\/rb-d80m-04.webp\",\"products\\/rb-d80m-03.webp\",\"products\\/rb-d80m-06.webp\",\"products\\/rb-d80m-02.webp\"]', NULL, 'NN-2443-BE7JO', 0, 40, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 1300, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 817, '2025-03-12 20:54:37', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/rb-d80m-01-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(265, 'RUBYSHOP เครื่องลอกสีผนัง เครื่องลอกสีเก่า เครื่องขัดผนังปูนเก่า Paint remover 1200W รุ่น RB-SP01', '<ul><li>เครื่องลอกผนังสีเก่าออก  เป็นเครื่องมือที่จำเป็นสำหรับการซ่อมแซมหรือทาสีผนังใหม่</li><li>ตอบโจทย์การทำงานของช่างสี โดยตัวเครื่องมีขนาดกะทัดรัด</li><li>เหมาะใช้งานในที่แคบ มีน้ำหนักเบา ช่วยเพิ่มความสะดวกคล่องตัวในการใช้งานต่อเนื่อง หรือเคลื่อนย้าย</li></ul>', '<h5><strong>คุณสมบัติ</strong></h5><ul><li>กำจัดหรือลอกสีเก่าหรือสีที่หลุดร่อนออกจากผนังก่อนที่จะทาสีใหม่</li><li>ปรับความหนา-ลึก ของพื้นผิวที่ต้องการลอกออกได้ตั้งแต่ 1 มม. - 3.5 มม.</li><li>มีประสิทธิภาพดีในการลอกสีเก่าออกอย่างรวดเร็ว</li><li>สามารถติดตั้ง เครื่องดูดฝุ่น+ถุงเก็บฝุ่น ได้ ลดปัญหามลภาวะหน้างาน</li><li><h5>กะทัดรัด สะดวกในการใช้งาน, จัดเก็บ หรือเคลื่อนย้าย</h5></li></ul><h5><strong>ข้อมูลเฉพาะสินค้า</strong></h5><ul><li>มอเตอร์: 1200W</li><li>แรงดันไฟฟ้า: 220V</li><li>รอบความเร็ว: 1000-4000 rpm</li><li>ลอกผนังได้กว้าง: 140 มม.</li><li>ลอกผนังได้ลึก: 1 มม. - 3.5 มม.</li></ul><h5><strong>อุปกรณ์ในชุดประกอบด้วย</strong></h5><ul><li>ตัวเครื่องลอกผนัง จำนวน 1 เครื่อง</li><li>ใบมีดลอกผนังผลิตจากอัลลอยพิเศษ 1 ชุด</li></ul><h5><strong>หมายเหตุ</strong></h5><p>รับประกันมอเตอร์ 1 ปี (ไม่รวมอะไหล่)</p><h2> </h2>', 'published', '[\"products\\/1-36.webp\",\"products\\/2-29.webp\",\"products\\/3-22.webp\",\"products\\/4-14.webp\"]', NULL, 'NN-2443-KGGLP', 0, 41, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 7500, 5500, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 864, '2025-03-12 20:54:39', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/1-37.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(266, 'RUBYSHOP เครื่องขัดผนัง รุ่น DWS-225G: ขัดผนังเนียนกริ๊บ เตรียมพร้อมสกิมโค้ท', '<ul><li><h5>ขัดผนังเรียบเนียน: ขจัดความไม่เรียบ ขี้ปูน และสิ่งสกปรกบนผนังได้อย่างหมดจด เตรียมพื้นผิวให้พร้อมสำหรับการสกิมโค้ท</h5></li><li><h5>เก็บฝุ่น 99%: ระบบเก็บฝุ่นประสิทธิภาพสูง ช่วยลดฝุ่นละอองขณะทำงาน ทำให้สภาพแวดล้อมสะอาดและปลอดภัย</h5></li><li><h5>ใช้งานง่าย: ออกแบบมาให้ใช้งานสะดวก ไม่ยุ่งยากซับซ้อน</h5></li><li><h5>น้ำหนักเบา: พกพาสะดวก เคลื่อนย้ายง่าย</h5></li><li><h5>ทนทาน: ผลิตจากวัสดุคุณภาพดี ทนทานต่อการใช้งาน</h5></li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><p>RUBYSHOP เครื่องขัดผนัง รุ่น DWS-225G เป็นเครื่องขัดผนังที่ออกแบบมาเพื่อช่วยให้งานเตรียมพื้นผิวก่อนการสกิมโค้ทเป็นเรื่องง่ายและรวดเร็ว ด้วยระบบเก็บฝุ่นที่มีประสิทธิภาพสูง ทำให้มั่นใจได้ว่าฝุ่นละอองจะไม่ฟุ้งกระจายขณะทำงาน</p><h2> </h2><h5><strong>คุณสมบัติเด่น</strong></h5><ul><li>ขัดผนังให้เรียบเนียน</li><li>เก็บฝุ่นได้ถึง 99%</li><li>ใช้งานง่าย</li><li>น้ำหนักเบา</li><li><p>ทนทาน</p><p> </p></li></ul><h5><strong>อุปกรณ์ภายในชุด</strong></h5><ul><li>เครื่องขัดผนัง รุ่น DWS-225G</li><li>ถุงเก็บฝุ่น</li><li>ท่อเก็บฝุ่น</li></ul><h2> </h2><h5><strong>เหมาะสำหรับ</strong></h5><ul><li>งานเตรียมพื้นผิวก่อนการสกิมโค้ท</li><li>งานขัดผนังที่ไม่เรียบเนียน</li><li>งานขัดขี้ปูน</li></ul><h2> </h2><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรสวมใส่อุปกรณ์ป้องกันความปลอดภัยที่เหมาะสมขณะใช้งาน เช่น หน้ากากกันฝุ่น แว่นตาป้องกัน</li></ul>', 'published', '[\"products\\/1-38.webp\",\"products\\/2-30.webp\"]', NULL, 'NN-2443-AEFDF', 0, 43, 0, NULL, 0, 0, 'in_stock', 0, 0, 0, 0, 10900, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 711, '2025-03-12 20:54:40', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/1-39.webp', 'physical', '', NULL, 0, 0, 0, 0, NULL),
(267, 'พัดลมไร้สาย แบตเตอรี่ 20V รุ่น RB-F01 (รวมแบต 1 ก้อน )', '<ul><li><h5>พัดลมไร้สาย RB-F01 เป็นพัดลมแบบพกพาที่ใช้พลังงานจากแบตเตอรี่ 20V</h5></li><li><h5>สามารถใช้งานได้สะดวกโดยไม่ต้องกังวลเรื่องสายไฟ เหมาะสำหรับใช้งานทั้งภายในและภายนอกอาคาร</h5></li></ul>', '<h5><strong>คุณสมบัติ</strong></h5><ul><li>ไร้สายและพกพาสะดวก: ใช้พลังงานจากแบตเตอรี่ 20V ทำให้สามารถเคลื่อนย้ายและใช้งานได้สะดวกทุกที่</li><li>ปรับระดับความแรงลมได้: สามารถปรับระดับความแรงลมได้ตามต้องการ</li><li>ทนทานและมีอายุการใช้งานยาวนาน: ผลิตจากวัสดุคุณภาพดี ทนทานต่อการใช้งาน</li><li>ใช้งานง่าย: มีปุ่มควบคุมการทำงานที่ใช้งานง่าย</li><li>แบตเตอรี่ใช้งานได้นาน: แบตเตอรี่ 20V สามารถใช้งานได้นานต่อการชาร์จหนึ่งครั้ง (ขึ้นอยู่กับระดับความแรงลมที่ใช้)</li></ul><h5> </h5><h5><strong>ข้อมูลจำเพาะ</strong></h5><ul><li>แรงดันไฟฟ้า: 20V</li><li>ประเภทแบตเตอรี่: Lithium-ion</li><li>ขนาด: (ระบุขนาดของพัดลม)</li><li>น้ำหนัก: (ระบุน้ำหนักของพัดลม)</li></ul><h5> </h5><h5><strong>สิ่งที่จะได้รับ</strong></h5><ul><li>พัดลมไร้สาย รุ่น RB-F01 จำนวน 1 เครื่อง</li><li>แบตเตอรี่ 20V จำนวน 1 ก้อน</li><li>แท่นชาร์จแบตเตอรี่ จำนวน 1 อัน</li></ul>', 'published', '[\"products\\/1-40.webp\"]', NULL, 'NN-2443-VI6CP', 0, 44, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 1990, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 853, '2025-03-12 20:54:42', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/1-41.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(268, 'RUBYSHOP เครื่องปรับระดับพื้นคอนกรีต แบบไร้สาย ใช้คู่กับแบตเตอรี่ Li-ion 48V 25000mh', '<ul><li><h5>เครื่องปรับระดับพื้นคอนกรีต </h5></li><li><h5>เครื่องปาดหน้าคอนกรีต </h5></li><li><h5>เครื่องสั่นปาดหน้าคอนกรีต แบบไร้สาย</h5></li></ul>', '<h5><strong>คุณสมบัติทั่วไป</strong></h5><ul><li><strong>การทำงานไร้สาย:</strong> ใช้พลังงานจากแบตเตอรี่ Li-ion ขนาด 48V ซึ่งมีกำลังไฟสูง ช่วยให้เครื่องทำงานได้ต่อเนื่องและมีประสิทธิภาพ</li><li><strong>แบตเตอรี่ขนาด 25000mh:</strong> สามารถใช้งานได้นานอย่างต่อเนื่อง</li><li><strong>ระบบปรับระดับอัตโนมัติ:</strong> ช่วยให้พื้นผิวคอนกรีตเรียบเนียน</li><li><strong>การประหยัดพลังงาน:</strong> ถูกออกแบบให้ใช้พลังงานอย่างมีประสิทธิภาพมากที่สุด</li><li><strong>ลดเวลาและแรงงาน:</strong> การปรับระดับอัตโนมัติทำให้ทำงานได้เร็วขึ้นและใช้แรงงานน้อยลง</li><li><strong>เหมาะสำหรับงานก่อสร้าง:</strong> หรือปรับปรุงพื้นคอนกรีตที่ต้องการความสะดวกในการทำงาน</li></ul><h5> </h5><h5><strong>ข้อมูลจำเพาะ</strong></h5><ul><li><strong>ขนาด:</strong> 150 x 8 x 150 (หน่วยระบุ)</li><li><strong>แผ่นปรับระดับคอนกรีต:</strong> ผลิตจากอะลูมิเนียมอย่างดี</li><li><strong>แบตเตอรี่:</strong> Li-ion 48V 25000mh</li><li><strong>น้ำหนัก:</strong> 5 กก.</li></ul><h2> </h2>', 'published', '[\"products\\/dsc07035.webp\",\"products\\/dsc07034.webp\",\"products\\/dsc07026.webp\",\"products\\/dsc07023.webp\",\"products\\/dsc07015.webp\",\"products\\/dsc07000.webp\"]', NULL, 'NN-2443-7NKSL', 0, 45, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 2888, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 783, '2025-03-12 20:54:53', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/dsc07035-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(269, 'RUBY SHOP เครื่องผสมสี ผสมปูนซีเมนต์ HAND MIXER หัวแฉก รุ่น RB-HM161', '<ul><li><h5>มอเตอร์ประสิทธิภาพสูงช่วยให้การผสมสีและปูนซีเมนต์เป็นไปอย่างรวดเร็วและทั่วถึง</h5></li><li><h5>หัวแฉกออกแบบมาเป็นพิเศษเพื่อการผสมที่มีประสิทธิภาพ ลดการจับตัวเป็นก้อน</h5></li><li><h5>สามารถปรับระดับความเร็วในการผสมได้ตามความเหมาะสมของวัสดุ</h5></li><li><h5> ด้ามจับออกแบบตามหลักสรีรศาสตร์ จับถนัดมือ ลดความเมื่อยล้าในการใช้งาน</h5></li><li><h5>ผลิตจากวัสดุคุณภาพดี ทนทานต่อการใช้งานหนัก</h5></li></ul>', '<h5><strong>การใช้งาน</strong></h5><ol><li>ประกอบหัวแฉกเข้ากับตัวเครื่อง</li><li>ใส่ส่วนผสมที่ต้องการผสมลงในภาชนะ</li><li>จุ่มหัวแฉกของเครื่องผสมลงในส่วนผสม</li><li>เปิดเครื่องและปรับระดับความเร็วตามต้องการ</li><li>ผสมส่วนผสมจนเข้ากันได้ดี</li></ol><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรสวมใส่อุปกรณ์ป้องกันความปลอดภัย เช่น แว่นตาและถุงมือ ขณะใช้งาน</li><li>ควรทำความสะอาดเครื่องผสมหลังการใช้งานทุกครั้ง</li></ul>', 'published', '[\"products\\/1-42.webp\",\"products\\/2-31.webp\"]', NULL, 'NN-2443-KROZX', 0, 46, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 2700, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 840, '2025-03-12 20:54:54', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/1-43.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(270, 'RUBYSHOP เครื่องพ่นปูนมือถือ รุ่น RB-CM18: ฉาบปูนง่ายๆ ด้วยมือคุณ', '<ul><li>ออกแบบมาให้ใช้งานง่าย พกพาสะดวก เหมาะสำหรับทั้งมืออาชีพและผู้ใช้งานทั่วไป</li><li>สามารถใช้งานร่วมกับปั๊มลมขนาดเล็กที่มีอยู่ได้ง่าย</li><li>ผลิตจากวัสดุคุณภาพดี ไม่ขึ้นสนิม ทนทานต่อการใช้งาน</li><li>ช่วยให้การพ่นปูนเป็นเรื่องง่ายและรวดเร็ว ประหยัดเวลาในการทำงาน</li><li>เหมาะสำหรับงานขนาดเล็กและขนาดกลาง ไม่ต้องเติมปูนบ่อย</li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><h6>RUBYSHOP เครื่องพ่นปูนมือถือ รุ่น RB-CM18 เป็นอุปกรณ์พ่นปูนฉาบแบบพกพาที่ออกแบบมาเพื่ออำนวยความสะดวกในการทำงานฉาบปูนให้ง่ายและรวดเร็วยิ่งขึ้น ด้วยขนาดที่เล็กกะทัดรัด น้ำหนักเบา ทำให้สามารถพกพาไปใช้งานได้ทุกที่ สามารถต่อกับปั๊มลมขนาดเล็กได้ง่าย และผลิตจากวัสดุคุณภาพดี ทนทานต่อการใช้งาน เหมาะสำหรับงานขนาดเล็กและขนาดกลาง</h6><h6> </h6><h5><strong>คุณสมบัติเด่น</strong></h5><ul><li>ใช้งานง่ายและสะดวก</li><li>ต่อกับปั๊มลมขนาดเล็กได้</li><li>วัสดุคุณภาพดี ทนทาน</li><li>ช่วยประหยัดเวลา</li><li>บรรจุปูนได้ 1 ลิตร</li></ul><h2> </h2><h5><strong>เหมาะสำหรับ</strong></h5><ul><li>งานฉาบปูนขนาดเล็กและขนาดกลาง</li><li>งานซ่อมแซมผนัง</li><li>งาน DIY ทั่วไป</li></ul><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรสวมใส่อุปกรณ์ป้องกันความปลอดภัยที่เหมาะสมขณะใช้งาน เช่น ถุงมือ หน้ากากกันฝุ่น</li></ul><h2> </h2>', 'published', '[\"products\\/1-44.webp\",\"products\\/2-32.webp\",\"products\\/3-23.webp\"]', NULL, 'NN-2443-PPPLP', 0, 47, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 1290, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 911, '2025-03-12 20:54:55', '2026-04-10 10:17:12', 1, 'Botble\\ACL\\Models\\User', 'products/2-33.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(271, 'RUBYSHOP เครื่องพ่นปูนฉาบ รุ่น RB-M30L เครื่องบรรจุปูน 30 ลิตร', '<ul><li>พ่นปูนได้รวดเร็ว ช่วยประหยัดเวลาและเพิ่มประสิทธิภาพในการทำงาน</li><li>ถังบรรจุปูน 30 ลิตร สามารถบรรจุปูนได้ในปริมาณมาก ลดความถี่ในการเติมปูน</li><li>มอเตอร์ทรงพลัง 4000W   ช่วยให้พ่นปูนได้อย่างราบรื่นและมีประสิทธิภาพ</li></ul>', '<h5><strong>รายละเอียดสินค้า </strong>RUBYSHOP เครื่องพ่นปูนฉาบ รุ่น RB-M30L</h5><h5><strong>ข้อมูลทั่วไป:</strong></h5><ul><li><strong>ชื่อสินค้า</strong>: RUBYSHOP เครื่องพ่นปูนฉาบ</li><li><strong>รุ่น</strong>: RB-M30L</li><li><strong>ประเภท</strong>: เครื่องพ่นปูนฉาบแบบไฟฟ้า</li><li><strong>การใช้งาน</strong>: เหมาะสำหรับงานฉาบปูนผนัง, เพดาน, และงานก่อสร้างทั่วไป</li></ul><p> </p><h5><strong>คุณสมบัติ:</strong></h5><ul><li><strong>ความสามารถในการพ่นปูน</strong>: พ่นปูนได้รวดเร็ว ช่วยประหยัดเวลาและเพิ่มประสิทธิภาพในการทำงาน</li><li><strong>ความจุถังบรรจุปูน</strong>: 30 ลิตร สามารถบรรจุปูนได้ในปริมาณมาก ลดความถี่ในการเติมปูน</li><li><strong>กำลังมอเตอร์</strong>: 4000W มอเตอร์ทรงพลัง ช่วยให้พ่นปูนได้อย่างราบรื่นและมีประสิทธิภาพ</li><li><strong>แรงม้า</strong>: 4HP</li><li><strong>แรงดันไฟฟ้า</strong>: 220V</li><li><strong>แรงดันสูงสุด</strong>: 20mpa</li><li><strong>ประสิทธิภาพ</strong>: พ่นได้เร็วกว่าการขึ้นปูนด้วยมือหลายเท่า ช่วยให้งานเสร็จไวตามกำหนด</li><li><strong>วัสดุ</strong>: ผลิตจากวัสดุคุณภาพดี ทนทานต่อการใช้งาน</li><li><strong>การบำรุงรักษา</strong>: ดูแลรักษาง่าย</li></ul><p> </p><h5><strong>ข้อควรระวัง:</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>สวมใส่อุปกรณ์ป้องกันความปลอดภัย เช่น แว่นตาและถุงมือ ขณะใช้งาน</li><li>ตรวจสอบสภาพเครื่องก่อนใช้งานทุกครั้ง</li><li>ทำความสะอาดเครื่องหลังใช้งาน</li></ul><p> </p>', 'published', '[\"products\\/m30l-02.webp\",\"products\\/m30l-01.webp\",\"products\\/m30l-03.webp\",\"home\\/rb-m30l-1.webp\",\"home\\/rb-m30l-1-1.webp\",\"home\\/rb-m30l-3.webp\",\"home\\/rb-m30l-2.webp\"]', NULL, 'NN-2443-CLVKA', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 79000, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 975, '2025-03-12 20:54:57', '2025-11-06 10:46:58', 1, 'Botble\\ACL\\Models\\User', 'products/m30l-01-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL);
INSERT INTO `ec_products` (`id`, `name`, `description`, `content`, `status`, `images`, `video_media`, `sku`, `order`, `sort_order_product_page`, `sort_order_category_page`, `quantity`, `allow_checkout_when_out_of_stock`, `with_storehouse_management`, `stock_status`, `is_featured`, `brand_id`, `is_variation`, `sale_type`, `price`, `sale_price`, `start_date`, `end_date`, `length`, `wide`, `height`, `weight`, `tax_id`, `views`, `created_at`, `updated_at`, `created_by_id`, `created_by_type`, `image`, `product_type`, `barcode`, `cost_per_item`, `generate_license_code`, `minimum_order_quantity`, `maximum_order_quantity`, `notify_attachment_updated`, `specification_table_id`) VALUES
(272, 'RUBYSHOP เครื่องพ่นปูนฉาบ รุ่น RB-MR004 บรรจุปูน 70 ลิตร พ่นเร็วถึง 30 วินาที/ถุง', '<ul><li><h5>เครื่องพ่นปูนฉาบ รุ่น RB-MR004 เป็นเครื่องพ่นปูนฉาบคุณภาพสูง</h5></li><li><h5>ออกแบบมาเพื่อตอบโจทย์ความต้องการของช่างก่อสร้างมืออาชีพ</h5></li><li><h5> ด้วยความสามารถในการพ่นปูนได้เร็วถึง 30 วินาทีต่อถุง </h5><h5> </h5></li></ul>', '<h5><strong>คุณสมบัติเด่น</strong></h5><ul><li>พ่นปูนได้รวดเร็ว: ด้วยมอเตอร์กำลังสูง 7500W และแรงดันสูงสุด 30bar ทำให้เครื่องพ่นปูน RB-MR004 สามารถพ่นปูนได้เร็วถึง 30 วินาทีต่อถุง ช่วยประหยัดเวลาและแรงงานในการทำงาน</li><li>ความจุขนาดใหญ่: ถังบรรจุปูนขนาด 70 ลิตร ช่วยให้คุณสามารถทำงานได้อย่างต่อเนื่องโดยไม่ต้องเติมปูนบ่อยๆ</li><li>ทนทานและเชื่อถือได้: เครื่องพ่นปูน RB-MR004 ผลิตจากวัสดุคุณภาพสูง ทนทานต่อการใช้งานหนัก และรับประกันมอเตอร์นานถึง 5 ปี (กรณีใช้ไฟปกติ)</li><li>ใช้งานง่าย: เครื่องพ่นปูน RB-MR004 ออกแบบมาให้ใช้งานง่าย ไม่ยุ่งยากซับซ้อน เหมาะสำหรับทั้งช่างมืออาชีพและผู้เริ่มต้น</li></ul><h5> </h5><h5><strong>ข้อมูลทางเทคนิค</strong></h5><ul><li>รุ่น: RB-MR004</li><li>ความจุ: 70 ลิตร</li><li>มอเตอร์: 7500W</li><li>แรงดันไฟฟ้า: 380V</li><li>แรงดันสูงสุด: 30bar</li><li>ความเร็วในการพ่น: 30 วินาที/ถุง</li></ul><h5> </h5><h5><strong>การรับประกัน</strong></h5><ul><li>รับประกันมอเตอร์: 5 ปี (กรณีใช้ไฟปกติ ไม่รวมไฟตก ไฟเกิน ไฟไม่พอ)</li><li>รับประกันซ่อมฟรี: 1 ปี (ไม่รวมอะไหล่)</li></ul><h5> </h5><h5><strong>เหมาะสำหรับ</strong></h5><ul><li>งานก่อสร้างทั่วไป</li><li>งานฉาบผนัง</li><li>งานปรับปรุงบ้าน</li><li>งาน DIY</li></ul><h5> </h5><h5><strong>คำแนะนำ</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรตรวจสอบสภาพเครื่องก่อนใช้งานทุกครั้ง</li><li>ควรทำความสะอาดเครื่องหลังใช้งาน</li></ul><h3> </h3>', 'published', '[\"products\\/4-15.webp\",\"products\\/3-24.webp\",\"products\\/2-34.webp\",\"products\\/1-45.webp\",\"products\\/hp30\\/rb-mr004-2.webp\",\"products\\/hp30\\/rb-mr004.webp\",\"products\\/hp30\\/rb-mr004-1.webp\"]', NULL, 'NN-2443-YJIS1', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 130000, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 946, '2025-03-12 20:54:58', '2025-11-06 10:45:40', 1, 'Botble\\ACL\\Models\\User', 'products/4-16.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(273, 'เครื่องพ่นปูนฉาบผสมในตัว RUBYSHOP รุ่น RB-MT-M6: จบงานไว สบาย แรง', '<ul><li><h5>ผสมปูนในตัว: ไม่ต้องเสียเวลาผสมปูนเอง</h5></li><li><h5>กำลังไฟ 380V: เหมาะสำหรับงานหนักและต่อเนื่อง</h5></li><li><h5>พร้อมช่างเทคนิคสอนหน้างาน: มั่นใจ ใช้งานได้เต็มประสิทธิภาพ</h5></li><li><h5>ประหยัดเวลาและแรงงาน: จบงานได้ไวกว่าการฉาบด้วยมือ</h5></li><li><h5>คุณภาพงานสูง: ฉาบปูนได้เรียบเนียน สม่ำเสมอ</h5></li></ul>', '<h5><strong>รายละเอียดสินค้า:</strong></h5><ul><li>เครื่องพ่นปูนฉาบผสมในตัว รุ่น RB-MTM6 ไฟ 3 เฟส (380v) คุณภาพดีจาก RUBY SHOP ใช้งานง่าย สะดวกรวดเร็ว</li><li>เครื่องจะผสมปูนกับน้ำแล้วลำเลียงปูนให้ผสมออกมาเป็นปูนผ่านสเปย์เพื่อพ่นปูนได้ทันที</li><li>ลดขั้นตอนการผสมปูน โดยที่ไม่ต้องใช้โม่ผสมปูน ทำให้งานฉาบปูนเสร็จเร็วกว่าเดิม 10 เท่า</li><li>ผลิตจากวัสดุคุณภาพดี แข็งแรง และทนทานต่อการใช้งาน</li><li>พ่นปูนเสร็จรวดเร็ว ใช้งานได้ต่อเนื่องมากกว่า 1 ชั่วโมงติดต่อกัน</li><li>เครื่องพ่นปูนฉาบขึ้นปูนได้ที่ความหนา 1.5 ซม (รอบแรก)</li><li>แรงอัดปูน สามารถอัดผนัง ทำให้ลดการแตกรอยร้าว</li></ul><p> </p><h5><strong>ข้อมูลทางเทคนิค:</strong></h5><ul><li>พ่นปูนได้เร็ว: 1 นาที/ถุง</li><li>ถังบรรจุปูนได้: 115 ลิตร</li><li>รอบความเร็ว: 390rpm</li><li>มอเตอร์ปูน: 5500W</li><li>มอเตอร์ลม: 3000W</li><li>แรงดันไฟฟ้า: 380V/50Hz/3phase</li><li>แรงดันสูงสุด: 50bar</li><li>สายพ่นปูน: 10 เมตร</li><li>Max. vertical conveying distance: 20M</li><li>Max. horizontal conveying distance: 40M</li><li>Hopper Capacity: 115L</li></ul><h5> </h5><h5><strong>คุณสมบัติเด่น:</strong></h5><ul><li>ช่วยให้งานขึ้นปูนเป็นเรื่องที่ง่ายขึ้น</li><li>ไม่ต้องใช้โม่ผสมปูน เพียงแค่เทปูนลงโถก็ผสมได้เองพร้อมพ่นทันที</li><li>สะดวกสบายจบงานได้ในเครื่องเดียว</li><li>ไม่ต้องใช้เครื่องผสมปูนแยกให้เสียเวลา เพราะพ่นได้เร็วกว่าขึ้นปูนด้วยมือหลายเท่า ช่วยให้งานเสร็จไวตามที่กำหนด</li><li>ใส่ปูนสำเร็จ ได้ต่อเนื่อง 3 ถุง ขนาด 50 กก.</li></ul>[media url=https://youtu.be/MTuqZemyqUw][/media]<p> </p>', 'published', '[\"products\\/rubyshop-rb-mt-m6-11.webp\",\"products\\/rubyshop-rb-mt-m6-3.webp\",\"products\\/rubyshop-rb-mt-m6.webp\",\"products\\/rubyshop-rb-mt-m6-7.webp\",\"products\\/rubyshop-rb-mt-m6-5.webp\",\"products\\/rubyshop-rb-mt-m6-6.webp\",\"products\\/rubyshop-rb-mt-m6-4.webp\"]', NULL, 'NN-2443-XRMPF', 0, 0, 0, NULL, 0, 0, 'in_stock', 1, NULL, 0, 0, 250000, 190000, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1070, '2025-03-12 20:55:28', '2025-10-28 11:26:17', 1, 'Botble\\ACL\\Models\\User', 'products/rubyshop-rb-mt-m6-11-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(274, 'RUBY SHOP เครื่องปั่นหน้าปูนฉาบ วัสดุเกรดดี แรงวัตต์ 750 w รุ่น RB-WPS80 Premium หน้ากว้าง 15 นิ้ว', '<ul><li>เครื่องปั่นหน้าปูนผลิตจากพลาสติกเกรด PP หรือโพลิโพรพิลีน</li><li>ทนต่อความร้อน มีความยืดหยุ่นสูง แข็งแรง ทนทาน</li><li>วัสดุมีความหนา ทนต่อแรงกระแทก ไม่แตกหักง่าย</li><li><p>แผ่นฟองน้ำ มีความยืดหยุ่นสูง เนื้อหนา ใช้งานได้นาน ไม่ยุบตัวง่าย</p><p> </p></li></ul><p> </p>', '<h5><strong>รายละเอียดทางเทคนิค</strong></h5><ul><li>มอเตอร์ : 750W</li><li>ความเร็วรอบ : 95 รอบ/นาที</li><li>ความยาวสายไฟ : 4 เมตร</li><li>วัสดุ : พลาสติกเกรด PP หรือโพลิโพรพิลีน</li></ul><p> </p><h5><strong>อุปกรณ์ภายในกล่อง</strong></h5><ul><li>แผ่นฟองน้ำขนาด : 40 ซม.</li><li>แผ่นพลาสติกขนาด : 38 ซม.</li><li>แผ่นกระดาษทรายขนาด : 38 ซม.</li><li>ถาดรองขนาด : 38 ซม.</li><li>ถ่านคาร์บอนสำรอง</li><li>น็อตล็อดถาดรอง</li><li>ไขควง</li></ul><p> </p><h5><strong>การทำงาน</strong></h5><ul><li>หัวปั่นจะหมุนด้วยความเร็วสูง ทำให้ผิวปูนเรียบเนียน</li><li>สามารถปรับความเร็วรอบได้ตามความต้องการของงาน</li><li>มีระบบป้องกันการสั่นสะเทือนเพื่อให้ควบคุมได้ง่าย</li></ul><p> </p><h5><strong>ประโยชน์การใช้งาน</strong></h5><ul><li>ใช้ปั่นผิวปูนฉาบให้เรียบก่อนการตกแต่งขั้นสุดท้าย</li><li>เหมาะสำหรับงานปูนฉาบพื้นที่ขนาดใหญ่</li><li>ช่วยลดเวลาและแรงงานในการทำงานเมื่อเทียบกับการใช้เกรียงมือ</li></ul><p> </p><h5><strong>วิธีการใช้งาน</strong></h5><ul><li>เตรียมพื้นผิวปูนให้มีความชื้นที่เหมาะสม</li><li>เปิดเครื่องและวางหัวปั่นแนบกับผิวปูน</li><li>เคลื่อนเครื่องในลักษณะวงกลมหรือซิกแซกอย่างสม่ำเสมอ</li><li>ปรับความเร็วและแรงกดตามสภาพของปูนและผลลัพธ์ที่ต้องการ</li></ul><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li>สวมอุปกรณ์ป้องกัน เช่น แว่นตา หน้ากากกันฝุ่น และถุงมือ</li><li>ระวังไม่ให้เครื่องทำงานบนพื้นผิวเดิมนานเกินไป เพราะอาจทำให้ปูนบางเกินไป</li><li>ตรวจสอบสภาพเครื่องและสายไฟก่อนใช้งานทุกครั้ง</li></ul><p> </p><h5><strong>การบำรุงรักษา</strong></h5><ul><li>ทำความสะอาดเครื่องและหัวปั่นหลังใช้งาน</li><li>ตรวจสอบและเปลี่ยนแปรงคาร์บอนตามระยะเวลาที่กำหนด</li><li>หล่อลื่นชิ้นส่วนที่เคลื่อนไหวตามคำแนะนำของผู้ผลิต</li></ul><p> </p><h5><strong>ข้อดีของการใช้เครื่อง</strong></h5><ul><li>ทำงานได้เร็วและมีประสิทธิภาพสูง</li><li>ให้ผิวงานที่เรียบเนียนสม่ำเสมอ</li><li>ลดความเมื่อยล้าของผู้ปฏิบัติงาน</li></ul><p> </p><p><strong>หมายเหตุ:</strong> รับประกันซ่อมฟรี 1 ปี (ไม่รวมอะไหล่)</p><p> </p>', 'published', '[\"products\\/3-25.webp\",\"products\\/1-46.webp\"]', NULL, 'NN-2443-BTLFD', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 5500, 3500, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 818, '2025-03-12 20:55:30', '2025-05-13 03:01:34', 1, 'Botble\\ACL\\Models\\User', 'products/3-26.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(275, 'RUBY SHOP เครื่องปั่นหน้าปูนฉาบ วัสดุเกรดดี แรงวัตต์ รุ่น RB-WPS90 จับสองมือ มีไฟส่องสว่าง', '<h5><strong>เครื่องปั่นหน้าปูนฉาบ รุ่น RB-WPS90 เป็นเครื่องมือไฟฟ้าที่ออกแบบมาเพื่อใช้ในการปั่นและขัดผิวปูนฉาบให้เรียบเนียน ด้วยมอเตอร์กำลังสูงและหัวปั่นแบบจานหมุนขนาดใหญ่ ทำให้เครื่อง RB-WPS90 สามารถทำงานได้อย่างรวดเร็วและมีประสิทธิภาพ ช่วยประหยัดเวลาและแรงงานในการทำงาน</strong></h5>', '<h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>หัวปั่นขนาดใหญ่:</strong> หัวปั่นแบบจานหมุนขนาดใหญ่ ช่วยให้สามารถทำงานได้ครอบคลุมพื้นที่กว้าง</li><li><strong>วัสดุคุณภาพสูง:</strong> ผลิตจากวัสดุเกรดดี มีความแข็งแรง ทนทาน และทนต่อการใช้งานหนัก</li><li><strong>ด้ามจับสองมือ:</strong> ด้ามจับสองมือออกแบบมาให้จับถนัดมือ ช่วยให้ควบคุมเครื่องได้ง่ายและมั่นคง</li><li><strong>ไฟส่องสว่าง:</strong> มีไฟส่องสว่างในตัว ช่วยให้มองเห็นได้ชัดเจนแม้ในที่แสงน้อย</li><li><strong>ใช้งานง่าย:</strong> ใช้งานง่าย ไม่ยุ่งยากซับซ้อน เหมาะสำหรับทั้งช่างมืออาชีพและผู้เริ่มต้น</li></ul><h5> </h5><h5><strong>อุปกรณ์ภายในกล่อง</strong></h5><ul><li>เครื่องปั่นหน้าปูนฉาบ RB-WPS90</li><li>คู่มือการใช้งาน</li></ul><h5> </h5><h5><strong>เหมาะสำหรับ</strong></h5><ul><li>งานฉาบปูนทั่วไป</li><li>งานปรับปรุงบ้าน</li><li>งาน DIY</li></ul><h5> </h5><h5><strong>คำแนะนำ</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรตรวจสอบสภาพเครื่องก่อนใช้งานทุกครั้ง</li><li>ควรทำความสะอาดเครื่องหลังใช้งาน</li></ul><h3> </h3>', 'published', '[\"products\\/3-27.webp\",\"products\\/2-35.webp\",\"products\\/1-47.webp\"]', NULL, 'NN-2443-EIT32', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 5500, 3500, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 856, '2025-03-12 20:55:31', '2025-05-13 03:00:35', 1, 'Botble\\ACL\\Models\\User', 'products/3-28.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(276, 'RUBY SHOP เครื่องปั่นหน้าปูนฉาบ สายไฟ 5 เมตร แรงวัตต์ 750w รุ่น RB-PSM370-5M', '<h5>เหมาะสำหรับงานปาดปูนให้เรียบหลังจากการเทปูน ขึ้นปูน สำหรับงานทำพื้นถนนคอนกรีต / พื้นคอนกรีตโรงงานหรือคลังสินค้า / ผนังคอนกรีต</h5>', '<h5><strong>รายละเอียดสินค้า</strong></h5><h6>เครื่องปั่นหน้าปูนฉาบ สายไฟ 5 เมตร รุ่น RB-PSM370</h6><ul><li>สายไฟยาว 5 เมตร ไม่ต้องเปลี่ยนที่เสียบปลั๊กบ่อย</li><li>เครื่องปั่นหน้าปูนผลิตจากพลาสติกเกรด ABS</li><li>วัสดุมีความหนา ทนต่อแรงกระแทก ไม่แตกหักง่าย</li><li>แผ่นฟองน้ำ เนื้อเนียนละเอียด ใช้งานได้นาน</li><li>เหมาะสำหรับงานปาดปูนให้เรียบหลังจากการเทปูน ขึ้นปูน สำหรับงานทำพื้นถนนคอนกรีต / พื้นคอนกรีตโรงงานหรือคลังสินค้า / ผนังคอนกรีต</li><li>ทำงานด้วยระบบการสั่นสะเทือน ขนาดกระทัดรัดสะดวกต่อหน้างาน มีน้ำหนักเบาง่ายต่อการเคลื่อนย้าย และทำความสะอาด</li><li>ทำให้การปรับผิวปูนเป็นเรื่องที่ง่ายขึ้น ปาดหน้าปูนได้เรียบ เร็ว ประหยัดเวลา ด้วยเครื่องปั่นหน้าปูน</li></ul><h5> </h5><h5><strong>รายละเอียดทางเทคนิค</strong></h5><ul><li>มอเตอร์ : 750W</li><li>ปรับความเร็ว : 6 ระดับ</li><li>ความเร็วรอบ : 140-230 รอบ/นาที</li><li>ความยาวสายไฟ : 10 เมตร</li><li>วัสดุ : พลาสติกเกรด ABS</li></ul><h5> </h5><h5><strong>อุปกรณ์ภายในกล่อง</strong></h5><ul><li>แผ่นฟองน้ำขนาด : 40 ซม.</li><li>แผ่นพลาสติกขนาด : 38 ซม.</li><li>แผ่นกระดาษทรายขนาด : 38 ซม.</li><li>ถาดรองขนาด : 38 ซม.</li><li>ถ่านคาร์บอนสำรอง</li><li>น็อตล็อดถาดรอง</li><li>ไขควง</li></ul><h5> </h5><h5><strong>การทำงาน</strong></h5><ul><li>หัวปั่นจะหมุนด้วยความเร็วสูง ทำให้ผิวปูนเรียบเนียน</li><li>สามารถปรับความเร็วรอบได้ตามความต้องการของงาน</li><li>มีระบบป้องกันการสั่นสะเทือนเพื่อให้ควบคุมได้ง่าย</li></ul><h5> </h5><h5><strong>ประโยชน์การใช้งาน</strong></h5><ul><li>ใช้ปั่นผิวปูนฉาบให้เรียบก่อนการตกแต่งขั้นสุดท้าย</li><li>เหมาะสำหรับงานปูนฉาบพื้นที่ขนาดใหญ่</li><li>ช่วยลดเวลาและแรงงานในการทำงานเมื่อเทียบกับการใช้เกรียงมือ</li></ul><h5> </h5><h5><strong>วิธีการใช้งาน</strong></h5><ul><li>เตรียมพื้นผิวปูนให้มีความชื้นที่เหมาะสม</li><li>เปิดเครื่องและวางหัวปั่นแนบกับผิวปูน</li><li>เคลื่อนเครื่องในลักษณะวงกลมหรือซิกแซกอย่างสม่ำเสมอ</li><li>ปรับความเร็วและแรงกดตามสภาพของปูนและผลลัพธ์ที่ต้องการ</li></ul><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li>สวมอุปกรณ์ป้องกัน เช่น แว่นตา หน้ากากกันฝุ่น และถุงมือ</li><li>ระวังไม่ให้เครื่องทำงานบนพื้นผิวเดิมนานเกินไป เพราะอาจทำให้ปูนบางเกินไป</li><li>ตรวจสอบสภาพเครื่องและสายไฟก่อนใช้งานทุกครั้ง</li></ul><h5> </h5><h5><strong>การบำรุงรักษา</strong></h5><ul><li>ทำความสะอาดเครื่องและหัวปั่นหลังใช้งาน</li><li>ตรวจสอบและเปลี่ยนแปรงคาร์บอนตามระยะเวลาที่กำหนด</li><li>หล่อลื่นชิ้นส่วนที่เคลื่อนไหวตามคำแนะนำของผู้ผลิต</li></ul><h5> </h5><h5><strong>ข้อดีของการใช้เครื่อง</strong></h5><ul><li>ทำงานได้เร็วและมีประสิทธิภาพสูง</li><li>ให้ผิวงานที่เรียบเนียนสม่ำเสมอ</li><li>ลดความเมื่อยล้าของผู้ปฏิบัติงาน</li></ul><h5> </h5><h5><strong>หมายเหตุ:</strong> รับประกันซ่อมฟรี 1 ปี (ไม่รวมอะไหล่)</h5>', 'published', '[\"products\\/3-29.webp\",\"products\\/2-36.webp\",\"products\\/1-48.webp\"]', NULL, 'NN-2443-VF3LH', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 3000, 2700, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 838, '2025-03-12 20:55:33', '2025-05-13 02:51:50', 1, 'Botble\\ACL\\Models\\User', 'products/3-30.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(277, 'RUBY SHOP เครื่องจี้ปูน รุ่น RB-35-1 มาพร้อมสายพ่นปูนยาว 150 ซม. หัวจี้ปูนขนาด 3.5 ซม. ผลิตจากทองแดงไม่ทำให้เกิดสนิม', '<ul><li><h5>ครื่องจี้ปูน สำหรับไล่ฟองอากาศในคอนกรีต </h5></li><li><h5>ใช้เพื่อไล่อากาศเพื่อไม่ให้เกิดรอยแตกร้าวเมื่อปูนแห้ง </h5></li><li><h5>มาพร้อมสายพ่นปูนยาว 150 ซม. หัวจี้ปูนขนาด 3.5 ซม. </h5></li><li><h5>ผลิตจากทองแดงไม่ทำให้เกิดสนิม ตัวเครื่องเป็นอลูมิเนียม แข็งแรงทนทาน </h5></li></ul>', '<h4>NEW ITEM เครื่องจี้ปูน สำหรับไล่ฟองอากาศในคอนกรีต</h4><h5><strong>รายละเอียดสินค้า</strong></h5><ul><li>ใช้เพื่อไล่อากาศเพื่อไม่ให้เกิดรอยแตกร้าวเมื่อปูนแห้ง</li><li>มาพร้อมสายพ่นปูนยาว 150 ซม.</li><li>หัวจี้ปูนขนาด 3.5 ซม. ผลิตจากทองแดงไม่ทำให้เกิดสนิม</li><li>ตัวเครื่องเป็นอลูมิเนียม แข็งแรงทนทาน</li><li>ทำงานด้วยระบบเกลียวหมุน</li><li>มีช่องระบายความร้อนด้านหลัง ช่วยให้เครื่องทำงานได้นานยิ่งขึ้น</li></ul><p> </p><h5><strong>รายละเอียดทางเทคนิค</strong></h5><ul><li>ความเร็วรอบ : 4500r/min</li><li>กำลังไฟ : 1000W</li><li>แรงดันไฟฟ้า : 220V</li><li>ความถี่ : 50Hz</li><li>น้ำหนัก : 2.2 Kg</li><li>ขนาดตัวเครื่อง : 31x13 cm</li></ul><h5> </h5><h5><strong>ช่องทางการติดต่อ</strong></h5><ul><li>สั่งซื้อสินค้า : 089-666-7802 (ฝ่ายขาย)</li><li>Line ID : @rubyshop168</li><li>Line ID : rubyshop168 (ฝ่ายขาย)</li><li>บริการหลังการขาย โทร. 089-6667802 หรือ 063-9192260 (ตั้งแต่ 08.30 - 17.30 น.)</li></ul><p> </p><p> </p>', 'published', '[\"products\\/1-49.webp\",\"products\\/2-37.webp\"]', NULL, 'NN-2443-SPMIW', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 1290, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 745, '2025-03-12 20:55:34', '2025-05-06 05:49:46', 1, 'Botble\\ACL\\Models\\User', 'products/1-50.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(278, 'RUBYSHOP เครื่องปั่นหน้าปูนฉาบ พร้อมด้ามต่อ รุ่น RB-PSW-370 สายไฟยาว 5 เมตร', '', '<h5><strong>รายละเอียดสินค้า</strong></h5><ul><li>เหมาะสำหรับงานปาดปูนให้เรียบหลังจากการเทปูน ขึ้นปูน</li><li>สำหรับงานทำพื้นถนนคอนกรีต</li><li>พื้นคอนกรีตโรงงานหรือคลังสินค้า ผนังคอนกรีต</li><li>ทำงานด้วยระบบการสั่นสะเทือน</li><li>ขนาดกระทัดรัดสะดวกต่อหน้างาน</li><li>มีน้ำหนักเบา ง่ายต่อการเคลื่อนย้าย และทำความสะอาด</li><li>ทำให้การปรับผิวปูนเป็นเรื่องที่ง่ายขึ้น ปาดหน้าปูนได้เรียบ เร็ว ประหยัดเวลา</li></ul><p> </p>', 'published', '[\"products\\/1739256926.webp\",\"products\\/3-31.webp\",\"products\\/5-9.webp\",\"products\\/2-38.webp\"]', NULL, 'NN-2443-QICKG', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 3700, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 855, '2025-03-12 20:55:36', '2025-05-05 10:16:48', 1, 'Botble\\ACL\\Models\\User', 'products/1739256926-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(279, 'RUBYSHOP แผ่นลาสติกเครื่องปาดหน้าปูนฉาบ ใช้ขัดหยาบแทนเกรียง ขนาด 410 มม.', '', '<h5>RUBYSHOP แผ่นพลาสติกเครื่องปาดหน้าปูนฉาบ ใช้ขัดหยาบแทนเกรียง ขนาด 410 มม.</h5><h5><strong>รายละเอียดสินค้า</strong></h5><ul><li>แผ่นพลาสติกเครื่องปาดหน้าปูน ใช้แทนเกรียง แบบขัดหยาบ</li><li>ผลิตจากวัสดุคุณภาพดี</li><li>มีตีนตุ๊กแกช่วยยึดเกาะ แข็งแรง ทนทาน</li><li>ใช้งานได้นาน</li><li>ขนาดประมาณ 410 มม.</li></ul>', 'published', '[\"products\\/2-39.webp\",\"products\\/1-51.webp\"]', NULL, 'NN-2443-ZKNJH', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 450, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 869, '2025-03-12 20:55:37', '2025-05-06 05:54:23', 1, 'Botble\\ACL\\Models\\User', 'products/1-52.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
