(281, 'RUBYSHOP เครื่องปั่นหน้าปูนรุ่นใหม่ล่าสุด RB-370CL กำลังไฟ 850W จับเหมือนพวงมาลัยรถยนต์ Wall plaster smooth machine Cement smooth machine', '', '<h5>RUBYSHOP เครื่องปั่นหน้าปูน รุ่น RB-370CL</h5><h5><strong>รายละเอียดสินค้า</strong></h5><ul><li>จับง่ายถนัดมือเหมือนจับพวงมาลัยรถยนต์</li><li>มีไฟ LED 2 ข้าง</li><li>สายไฟยาว 2.5 เมตร</li><li>มอเตอร์ 850W</li><li>รอบความเร็ว 100r/min</li><li>ปรับความเร็วได้ 6 ระดับ</li><li>ตัวเครื่องเป็นสวิทช์เปิด-ปิดเครื่อง</li><li>วัสดุเป็นแบบเกรดราคาประหยัด เหมาะกับผู้เริ่มต้นใช้งาน</li><li>มีอุปกรณ์ในชุดครบเซ็ต</li></ul>', 'published', '[\"products\\/rb-370cl-01.webp\",\"products\\/rb-370cl-02-large.webp\"]', NULL, 'NN-2443-GBZGO', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 2290, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 850, '2025-03-12 20:55:44', '2025-05-05 10:14:52', 1, 'Botble\\ACL\\Models\\User', 'products/rb-370cl-01-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(284, 'RUBY SHOP หัวแพ็คเกอร์-Packer A8 ขนาด 73x14 cm ชุด 50 หัว', '<h5>RUBY SHOP หัวแพ็คเกอร์-Packer A8 เป็นอุปกรณ์สำคัญที่ใช้ในงานซ่อมรอยร้าวคอนกรีตและงานป้องกันน้ำรั่วซึม ผลิตจากวัสดุคุณภาพดี มีความแข็งแรง ทนทาน และสามารถใช้งานได้ยาวนาน</h5>', '<h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>ขนาดเหมาะสม:</strong> ขนาด 73x14 cm เหมาะสำหรับการใช้งานกับรอยร้าวขนาดกลางและใหญ่</li><li><strong>จำนวนคุ้มค่า:</strong> บรรจุ 50 หัวต่อชุด ช่วยให้คุณมีหัวแพ็คเกอร์สำรองเพียงพอสำหรับงานซ่อมแซม</li><li><strong>วัสดุคุณภาพ:</strong> ผลิตจากวัสดุที่มีความแข็งแรง ทนทานต่อการใช้งาน และไม่เป็นสนิม</li><li><strong>ใช้งานง่าย:</strong> ออกแบบมาให้ใช้งานง่าย สะดวก และรวดเร็ว</li></ul><h3> </h3><h5><strong>ข้อมูลทางเทคนิค</strong></h5><ul><li><strong>ขนาด:</strong> 73x14 cm</li><li><strong>จำนวน:</strong> 50 หัว/ชุด</li><li><strong>วัสดุ:</strong> (ข้อมูลจำเพาะ)</li></ul><h5> </h5><h5><strong>เหมาะสำหรับ</strong></h5><ul><li>งานซ่อมแซมรอยร้าวในคอนกรีต</li><li>งานป้องกันน้ำรั่วซึม</li><li>งานเสริมความแข็งแรงของโครงสร้าง</li></ul><h5> </h5><h5><strong>คำแนะนำ</strong></h5><ul><li><p>ควรเลือกขนาดของหัวแพ็คเกอร์ให้เหมาะสมกับขนาดของรอยร้าว</p><p> </p></li></ul>', 'published', '[\"products\\/1-57.webp\",\"products\\/3-36.webp\",\"products\\/2-43.webp\",\"products\\/5-10.webp\",\"products\\/4-18.webp\",\"products\\/6-8.webp\"]', NULL, 'NN-2443-USDDB', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 600, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 835, '2025-03-12 20:55:50', '2025-05-06 07:04:22', 1, 'Botble\\ACL\\Models\\User', 'products/1-58.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(285, 'RUBY SHOP หัวแพ็คเกอร์-Packer A10 ขนาด 90x14 cm ชุด 50 หัว', '<h5>RUBY SHOP หัวแพ็คเกอร์-Packer A10 เป็นอุปกรณ์สำคัญที่ใช้ในงานซ่อมรอยร้าวคอนกรีตและงานป้องกันน้ำรั่วซึม ผลิตจากวัสดุคุณภาพดี มีความแข็งแรง ทนทาน และสามารถใช้งานได้ยาวนาน</h5>', '<h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>ขนาดเหมาะสม:</strong> ขนาด 90x14 cm เหมาะสำหรับการใช้งานกับรอยร้าวขนาดใหญ่</li><li><strong>จำนวนคุ้มค่า:</strong> บรรจุ 50 หัวต่อชุด ช่วยให้คุณมีหัวแพ็คเกอร์สำรองเพียงพอสำหรับงานซ่อมแซม</li><li><strong>วัสดุคุณภาพ:</strong> ผลิตจากวัสดุที่มีความแข็งแรง ทนทานต่อการใช้งาน และไม่เป็นสนิม</li><li><strong>ใช้งานง่าย:</strong> ออกแบบมาให้ใช้งานง่าย สะดวก และรวดเร็ว</li></ul><h3> </h3><h5><strong>ข้อมูลทางเทคนิค</strong></h5><ul><li>ขนาด: 90x14 cm</li><li><p>จำนวน: 50 หัว/ชุด</p><p> </p></li></ul><h5><strong>เหมาะสำหรับ</strong></h5><ul><li>งานซ่อมแซมรอยร้าวในคอนกรีต</li><li>งานป้องกันน้ำรั่วซึม</li><li>งานเสริมความแข็งแรงของโครงสร้าง</li></ul><h3> </h3><h5><strong>คำแนะนำ</strong></h5><ul><li><p>ควรเลือกขนาดของหัวแพ็คเกอร์ให้เหมาะสมกับขนาดของรอยร้าว</p><p> </p></li></ul>', 'published', '[\"products\\/1-59.webp\",\"products\\/7-4.webp\",\"products\\/5-11.webp\",\"products\\/4-19.webp\",\"products\\/3-37.webp\",\"products\\/6-9.webp\",\"products\\/2-44.webp\"]', NULL, 'NN-2443-USDDB-E1XXC', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 600, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 815, '2025-03-12 20:55:54', '2025-05-06 07:03:58', 1, 'Botble\\ACL\\Models\\User', 'products/1-60.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
