(287, 'RUBY SHOP หัวแพ็คเกอร์-Packer B8 ขนาด 80x10 cm ชุด 50 หัว', '<h5>หัวแพ็คเกอร์ขนาดใหญ่พิเศษ สำหรับงานซ่อมรอยร้าวคอนกรีตขนาดใหญ่และงานป้องกันน้ำรั่วซึมRUBY SHOP หัวแพ็คเกอร์-Packer A15 เป็นอุปกรณ์สำคัญที่ใช้ในงานซ่อมรอยร้าวคอนกรีตขนาดใหญ่และงานป้องกันน้ำรั่วซึม ผลิตจากวัสดุคุณภาพดี มีความแข็งแรง ทนทาน และสามารถใช้งานได้ยาวนาน</h5>', '<h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>ขนาดใหญ่:</strong> ขนาด 80x14 cm เหมาะสำหรับการใช้งานกับรอยร้าวขนาดใหญ่มาก</li><li><strong>จำนวนคุ้มค่า:</strong> บรรจุ 50 หัวต่อชุด ช่วยให้คุณมีหัวแพ็คเกอร์สำรองเพียงพอสำหรับงานซ่อมแซมขนาดใหญ่</li><li><strong>วัสดุคุณภาพ:</strong> ผลิตจากวัสดุที่มีความแข็งแรง ทนทานต่อการใช้งาน และไม่เป็นสนิม</li><li><strong>ใช้งานง่าย:</strong> ออกแบบมาให้ใช้งานง่าย สะดวก และรวดเร็ว</li></ul><h3> </h3><h5><strong>ข้อมูลทางเทคนิค</strong></h5><ul><li><strong>ขนาด:</strong> 80x10 cm</li><li><strong>จำนวน:</strong> 50 หัว/ชุด</li></ul><h3> </h3><h5><strong>เหมาะสำหรับ</strong></h5><ul><li>งานซ่อมแซมรอยร้าวในคอนกรีตขนาดใหญ่</li><li>งานป้องกันน้ำรั่วซึมในโครงสร้างขนาดใหญ่</li><li>งานเสริมความแข็งแรงของโครงสร้างขนาดใหญ่</li></ul><h3> </h3><h3>คำแนะนำ</h3><ul><li><p>ควรเลือกขนาดของหัวแพ็คเกอร์ให้เหมาะสมกับขนาดของรอยร้าว</p><p> </p></li></ul>', 'published', '[\"products\\/1-63.webp\"]', NULL, 'NN-2443-RP21U-lXlx6', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 800, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 797, '2025-03-12 20:55:56', '2025-05-06 07:02:04', 1, 'Botble\\ACL\\Models\\User', 'products/1-64.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(288, 'RUBY SHOP ปืนอัดฉีด เครื่องยิงโฟม-Long gun head of grouting machine รุ่น PU-GUN01', '<h5>ปืนอัดฉีด เครื่องยิงโฟม RUBY SHOP รุ่น PU-GUN01 เป็นเครื่องมือที่จำเป็นสำหรับงานก่อสร้างและซ่อมแซมต่างๆ ด้วยหัวฉีด Long gun head ที่ออกแบบมาเป็นพิเศษ ทำให้การฉีดโฟมเป็นไปอย่างแม่นยำและมีประสิทธิภาพ ช่วยประหยัดปริมาณโฟมที่ใช้ และให้ผลงานที่มีคุณภาพสูง ตัวเครื่องผลิตจากวัสดุคุณภาพสูง ทนทานต่อการใช้งานหนัก เหมาะสำหรับทั้งมืออาชีพและผู้ใช้งานทั่วไป</h5>', '<h5>รายละเอียดสินค้า</h5><ul><li><strong>ใช้งานง่าย</strong>: ออกแบบมาให้ใช้งานง่าย เหมาะสำหรับทั้งมืออาชีพและผู้ใช้งานทั่วไป</li><li><strong>ทนทาน</strong>: ผลิตจากวัสดุคุณภาพสูง ทนทานต่อการใช้งานหนัก</li><li><strong>อเนกประสงค์</strong>: ใช้ได้กับงานหลากหลายประเภท เช่น งานก่อสร้าง งานซ่อมแซม งานอุดรอยรั่ว</li><li><strong>ประสิทธิภาพสูง</strong>: หัวฉีดออกแบบพิเศษ ช่วยให้การฉีดโฟมเป็นไปอย่างแม่นยำและมีประสิทธิภาพ</li><li><strong>ประหยัด</strong>: ช่วยประหยัดปริมาณโฟมที่ใช้</li></ul><h5> </h5><h5>ข้อมูลทางเทคนิค</h5><ul><li><strong>รุ่น</strong>: PU-GUN01</li><li><strong>ประเภท</strong>: ปืนอัดฉีด / เครื่องยิงโฟม</li><li><strong>หัวฉีด</strong>: Long gun head</li><li><strong>วัสดุ</strong>: วัสดุคุณภาพสูง</li><li><strong>การใช้งาน</strong>: งานก่อสร้าง, งานซ่อมแซม, งานอุดรอยรั่ว</li></ul><h5> </h5><h5>คำแนะนำ</h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรทำความสะอาดปืนอัดฉีดหลังการใช้งานทุกครั้ง</li><li>ควรเก็บรักษาในที่แห้งและพ้นจากมือเด็ก</li></ul><h3> </h3><p> </p>', 'published', '[\"products\\/1-65.webp\",\"products\\/3-38.webp\",\"products\\/4-20.webp\",\"products\\/2-45.webp\"]', NULL, 'NN-2443-42V4I', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 650, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 806, '2025-03-12 20:55:58', '2025-05-05 09:40:33', 1, 'Botble\\ACL\\Models\\User', 'products/1-66.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(289, 'RUBY SHOP กระบอกใส่สารเคมี เครื่องยิงโฟม - Material cup injection pump', '<h5>กระบอกใส่สารเคมีสำหรับเครื่องยิงโฟม รุ่น PU-CUP-01 จาก RUBY SHOP เป็นอุปกรณ์สำคัญสำหรับงานฉีดพ่นโฟม polyurethane (PU) ที่มีคุณภาพสูง ทนทาน และใช้งานง่าย เหมาะสำหรับช่างมืออาชีพและผู้ใช้งานทั่วไป</h5>', '<h5><strong>คุณสมบัติ:</strong></h5><ul><li><strong>วัสดุคุณภาพ:</strong> ผลิตจากวัสดุที่ทนทานต่อสารเคมีและการกัดกร่อน ทำให้มีอายุการใช้งานยาวนาน</li><li><strong>ใช้งานง่าย:</strong> ออกแบบมาให้ใช้งานง่าย สะดวก และรวดเร็ว</li><li><strong>ความจุที่เหมาะสม:</strong> มีขนาดที่เหมาะสมกับการใช้งานทั่วไป ทำให้ไม่ต้องเติมสารเคมีบ่อยๆ</li><li><p><strong>หลากหลายการใช้งาน:</strong> เหมาะสำหรับใช้กับเครื่องยิงโฟมในงานต่างๆ เช่น งานก่อสร้าง งานซ่อมแซม และงานอุตสาหกรรม</p><p> </p></li></ul><h5><strong>คำแนะนำ:</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรทำความสะอาดกระบอกใส่สารเคมีหลังการใช้งานทุกครั้ง</li><li>ควรเก็บรักษากระบอกใส่สารเคมีในที่แห้งและพ้นจากแสงแดด</li></ul>', 'published', '[\"products\\/material-cup-injection-pump-1.webp\",\"products\\/material-cup-injection-pump-2.webp\",\"products\\/material-cup-injection-pump-3.webp\"]', NULL, 'NN-2443-KFBOL', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, 0, 0, 0, 650, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 706, '2025-03-12 20:55:59', '2025-03-12 20:55:59', 1, 'Botble\\ACL\\Models\\User', 'products/material-cup-injection-pump-1-1.webp', 'physical', '', NULL, 0, 0, 0, 0, NULL),
(290, 'RUBY SHOP ตัวกรองกระบอกใส่เคมี เครื่องยิงโฟม - Filter Material cup injection pump PU-FILTER-01', '<p>ตัวกรองกระบอกใส่เคมีสำหรับเครื่องยิงโฟม รุ่น PU-FILTER-01 จาก RUBY SHOP เป็นอุปกรณ์เสริมที่ช่วยกรองสิ่งสกปรกและเศษผงต่างๆ ที่อาจปะปนอยู่ในสารเคมี ทำให้มั่นใจได้ว่าสารเคมีที่ใช้มีความสะอาดและมีคุณภาพสูง ส่งผลให้งานฉีดพ่นโฟมมีประสิทธิภาพและผลลัพธ์ที่ดี</p><p> </p>', '<h5><strong>คุณสมบัติ:</strong></h5><ul><li><strong>กรองสิ่งสกปรก:</strong> ช่วยกรองสิ่งสกปรกและเศษผงต่างๆ ที่อาจปะปนอยู่ในสารเคมี</li><li><strong>ป้องกันการอุดตัน:</strong> ช่วยป้องกันการอุดตันของหัวฉีดและอุปกรณ์อื่นๆ ของเครื่องยิงโฟม</li><li><strong>ยืดอายุการใช้งาน:</strong> ช่วยยืดอายุการใช้งานของเครื่องยิงโฟม</li><li><strong>วัสดุคุณภาพ:</strong> ผลิตจากวัสดุที่ทนทานต่อสารเคมีและการกัดกร่อน ทำให้มีอายุการใช้งานยาวนาน</li><li><strong>ใช้งานง่าย:</strong> ออกแบบมาให้ใช้งานง่าย สะดวก และรวดเร็ว</li></ul><p> </p><h5><strong>คำแนะนำ:</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรเปลี่ยนตัวกรองตามระยะเวลาที่กำหนด หรือเมื่อเห็นว่าตัวกรองสกปรก</li><li>ควรเก็บรักษาตัวกรองในที่แห้งและพ้นจากแสงแดด</li></ul>', 'published', '[\"products\\/filter-material-cup-injection-pump-3.webp\",\"products\\/filter-material-cup-injection-pump-2.webp\",\"products\\/filter-material-cup-injection-pump-1.webp\"]', NULL, 'NN-2443-7ZVJR', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, 0, 0, 0, 150, 80, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 773, '2025-03-12 20:56:01', '2025-03-12 20:56:01', 1, 'Botble\\ACL\\Models\\User', 'products/filter-material-cup-injection-pump-3-1.webp', 'physical', '', NULL, 0, 0, 0, 0, NULL),
(291, 'RUBY SHOP เกจวัดแรงดัน เครื่องยิงโฟม - Gauge injection pump รุ่น PU-GAUGE-01', '<h5>เกจวัดแรงดันสำหรับเครื่องยิงโฟม รุ่น PU-GAUGE-01 จาก RUBY SHOP เป็นอุปกรณ์ที่สำคัญสำหรับงานฉีดพ่นโฟม polyurethane (PU) ที่ช่วยให้ผู้ใช้งานสามารถตรวจสอบและควบคุมแรงดันในการฉีดพ่นได้อย่างแม่นยำ ทำให้มั่นใจได้ว่าการฉีดพ่นโฟมเป็นไปอย่างมีประสิทธิภาพและได้ผลลัพธ์ที่ดี</h5>', '<h5><strong>คุณสมบัติ:</strong></h5><ul><li><strong>ความแม่นยำสูง:</strong> สามารถวัดแรงดันได้อย่างแม่นยำ ทำให้ผู้ใช้งานสามารถควบคุมแรงดันในการฉีดพ่นได้อย่างเหมาะสม</li><li><strong>ทนทาน:</strong> ผลิตจากวัสดุที่มีคุณภาพสูง ทนทานต่อการใช้งาน และสามารถใช้งานได้ในสภาพแวดล้อมที่หลากหลาย</li><li><strong>ใช้งานง่าย:</strong> ออกแบบมาให้ใช้งานง่าย สะดวก และรวดเร็ว</li><li><strong>อ่านค่าได้ง่าย:</strong> หน้าปัดเกจวัดแรงดันมีขนาดใหญ่ มองเห็นตัวเลขได้ชัดเจน ทำให้ผู้ใช้งานสามารถอ่านค่าแรงดันได้อย่างง่ายดาย</li></ul><p> </p><p> </p>', 'published', '[\"products\\/pu-gauge-01.webp\",\"products\\/pu-gauge-01-5.webp\",\"products\\/pu-gauge-01-3.webp\",\"products\\/pu-gauge-01-2.webp\"]', NULL, 'NN-2443-5IEYY', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 550, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 767, '2025-03-12 20:56:03', '2025-05-13 10:16:45', 1, 'Botble\\ACL\\Models\\User', 'products/pu-gauge-01-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(292, 'RUBY SHOP หัวอัดจารบี เครื่องยิงโฟม - Phosset injection pump สีทอง รุ่น PU-Phosset-01', '<h5>หัวอัดจารบีสำหรับเครื่องยิงโฟม รุ่น PU-Phosset-01 จาก RUBY SHOP เป็นอุปกรณ์สำคัญที่ใช้ร่วมกับปืนยิงโฟม เพื่อช่วยในการอัดจารบีเข้าไปในเครื่องยิงโฟม ทำให้เครื่องทำงานได้อย่างราบรื่นและมีประสิทธิภาพ</h5><p> </p>', '<h5><strong>คุณสมบัติ:</strong></h5><ul><li><strong>วัสดุคุณภาพ:</strong> ผลิตจากวัสดุที่ทนทาน ทำให้มีอายุการใช้งานยาวนาน</li><li><strong>สีทอง:</strong> สีทองช่วยให้มองเห็นได้ง่าย และเพิ่มความสวยงามให้กับอุปกรณ์</li><li><strong>1 แพ็ค 10 อัน:</strong> บรรจุ 10 อันต่อแพ็ค ทำให้คุ้มค่าและสะดวกในการใช้งาน</li><li><strong>ใช้ต่อกับปืนยิงโฟม:</strong> ออกแบบมาให้ใช้ร่วมกับปืนยิงโฟมได้อย่างลงตัว</li><li><strong>ปลายหัวอัดจารบีเกลียวด้านใน 1/8:</strong> ขนาดเกลียวมาตรฐาน ทำให้สามารถใช้งานร่วมกับอุปกรณ์อื่นๆ ได้ง่าย</li></ul>', 'published', '[\"products\\/pu-phosset-01-1.webp\",\"products\\/pu-phosset-01-4.webp\",\"products\\/pu-phosset-01-6.webp\",\"products\\/pu-phosset-01-3.webp\",\"products\\/pu-phosset-01-2.webp\"]', NULL, 'NN-2443-AJISG', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 700, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 820, '2025-03-12 20:56:08', '2025-05-06 07:01:06', 1, 'Botble\\ACL\\Models\\User', 'products/pu-phosset-01-1-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(293, 'RUBY SHOP หัวอัดจารบี เครื่องยิงโฟม-Phosset injection pump สีดำ รุ่น PU-Phosset-02', '<h5>หัวอัดจารบีสำหรับเครื่องยิงโฟม รุ่น PU-Phosset-02 จาก RUBY SHOP เป็นอุปกรณ์ที่ใช้ร่วมกับปืนยิงโฟม ทำหน้าที่อัดจารบีเข้าไปในเครื่องยิงโฟม เพื่อให้เครื่องทำงานได้อย่างมีประสิทธิภาพและราบรื่น จารบีช่วยลดแรงเสียดทานและป้องกันการสึกหรอของชิ้นส่วนต่างๆ ภายในเครื่องยิงโฟม ทำให้เครื่องมีอายุการใช้งานยาวนานขึ้น</h5>', '<h5><strong>คุณสมบัติ:</strong></h5><ul><li><strong>วัสดุคุณภาพสูง:</strong> ผลิตจากวัสดุที่ทนทานต่อแรงดันและสารเคมี ทำให้มีอายุการใช้งานยาวนาน</li><li><strong>สีดำ:</strong> สีดำช่วยป้องกันการเกิดสนิม และทำให้มองเห็นสิ่งสกปรกได้ง่าย</li><li><strong>ใช้งานง่าย:</strong> ออกแบบมาให้ใช้งานง่าย สามารถติดตั้งและถอดออกได้ง่าย</li><li><strong>ขนาดมาตรฐาน:</strong> มีขนาดมาตรฐาน ทำให้สามารถใช้งานร่วมกับปืนยิงโฟมและอุปกรณ์อื่นๆ ได้อย่างลงตัว</li><li><strong>แพ็คประหยัด:</strong> บรรจุหลายชิ้นต่อแพ็ค ทำให้คุ้มค่าและสะดวกในการใช้งาน</li></ul><p> </p>', 'published', '[\"products\\/pu-phosset-02.webp\",\"products\\/pu-phosset-02-5.webp\",\"products\\/pu-phosset-02-4.webp\",\"products\\/pu-phosset-02-3.webp\",\"products\\/pu-phosset-02-2.webp\"]', NULL, 'NN-2443-OW5IW', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 700, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 808, '2025-03-12 20:56:10', '2025-05-06 07:00:37', 1, 'Botble\\ACL\\Models\\User', 'products/pu-phosset-02-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(294, 'RUBY SHOP สายไฮโดรอลิค เครื่องยิงโฟม-Hose of grouting machine รุ่น PU-Hose 01', '<ul><li><h5>สายไฮโดรอลิคสำหรับเครื่องยิงโฟม รุ่น PU-Hose 01 จาก RUBY SHOP</h5></li><li><h5> เป็นอุปกรณ์สำคัญที่ใช้ในการลำเลียงสารเคมีไปยังหัวฉีดของเครื่องยิงโฟม </h5></li><li><h5>ทำหน้าที่เป็นตัวกลางในการส่งผ่านแรงดันและสารเคมีเหลวไปยังเครื่องพ่นโฟม </h5></li><li><h5>ทำให้เครื่องพ่นโฟมสามารถทำงานได้อย่างมีประสิทธิภาพ</h5></li></ul>', '<h5><strong>คุณสมบัติ:</strong></h5><ul><li><strong>ทนทานต่อแรงดัน:</strong> ผลิตจากวัสดุที่มีคุณภาพสูง ทนทานต่อแรงดันสูง ทำให้สามารถใช้งานได้อย่างปลอดภัยและมีประสิทธิภาพ</li><li><strong>ทนทานต่อสารเคมี:</strong> วัสดุที่ใช้มีความทนทานต่อสารเคมีที่ใช้ในงานพ่นโฟม ทำให้สายไฮโดรอลิคไม่ผุพังหรือเสียหายจากการสัมผัสกับสารเคมี</li><li><strong>ยืดหยุ่น:</strong> สายไฮโดรอลิคมีความยืดหยุ่น ทำให้สามารถโค้งงอได้ง่าย และสะดวกในการใช้งานในพื้นที่จำกัด</li><li><strong>ขนาดมาตรฐาน:</strong> มีขนาดมาตรฐาน ทำให้สามารถใช้งานร่วมกับเครื่องยิงโฟมและอุปกรณ์อื่นๆ ได้อย่างลงตัว</li><li><strong>อายุการใช้งานยาวนาน:</strong> วัสดุคุณภาพสูงและการผลิตที่ได้มาตรฐาน ทำให้สายไฮโดรอลิคมีอายุการใช้งานยาวนาน</li></ul>', 'published', '[\"products\\/pu-hose-01.webp\"]', NULL, 'NN-2443-VDBP8', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, 0, 0, 0, 690, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 715, '2025-03-12 20:56:12', '2025-03-12 20:56:12', 1, 'Botble\\ACL\\Models\\User', 'products/pu-hose-01-1.webp', 'physical', '', NULL, 0, 0, 0, 0, NULL),
(295, 'RUBY SHOP Filter Spray Gun ไส้กรองสี', '<p>ไส้กรองสีคุณภาพสูงจาก RUBY SHOP ออกแบบมาสำหรับใช้กับหัวพ่นสเปรย์ (Spray Gun) เพื่อช่วยกรองสิ่งสกปรกและสิ่งเจือปนที่อยู่ในเนื้อสี เช่น ฝุ่น เศษตะกอน หรือก้อนสีที่จับตัวกัน ช่วยลดปัญหา <strong>หัวพ่นอุดตัน</strong> และทำให้เนื้อสีที่พ่นออกมา <strong>เรียบเนียน สม่ำเสมอ</strong></p>', '<p><strong>RUBY SHOP Filter Spray Gun – ไส้กรองสีสำหรับหัวพ่นสเปรย์</strong></p><p>ไส้กรองสีคุณภาพสูงจาก RUBY SHOP ออกแบบมาสำหรับใช้กับหัวพ่นสเปรย์ (Spray Gun) <br>เพื่อช่วยกรองสิ่งสกปรกและสิ่งเจือปนที่อยู่ในเนื้อสี เช่น ฝุ่น เศษตะกอน หรือก้อนสีที่จับตัวกัน ช่วยลดปัญหา หัวพ่นอุดตัน และทำให้เนื้อสีที่พ่นออกมา เรียบเนียน สม่ำเสมอ</p><p><strong>คุณสมบัติเด่น:</strong><br>- ช่วยยืดอายุหัวพ่นสี โดยลดการอุดตันจากสิ่งปนเปื้อน<br>- ให้ผลงานพ่นสีที่เนียนเรียบ ไม่มีเม็ดฝุ่นหรือสีจับก้อน<br>- เปลี่ยนง่าย ใช้งานสะดวก เหมาะสำหรับใช้ซ้ำหรือเปลี่ยนตามรอบ<br>- ใช้ได้กับหัวพ่นสีหลากหลายรุ่น ทั้งแบบแรงดันต่ำและแรงดันสูง<br>- เหมาะสำหรับช่างพ่นสี, งานพ่นรถ, งานไม้ และงานตกแต่งทั่วไป</p><p><br><strong>เหมาะสำหรับ:</strong><br>- งานพ่นสีรถยนต์<br>- งานพ่นสีเฟอร์นิเจอร์ไม้<br>- งานพ่นสีอุตสาหกรรม<br>- งานพ่นสีภายในอาคาร<br>- ผู้ใช้งานหัวพ่นสเปรย์เป็นประจำ</p>', 'published', '[\"products\\/flter-spray\\/we410-2.png\",\"products\\/flter-spray\\/flter-spray-3.webp\",\"products\\/flter-spray\\/flter-spray-4.webp\",\"products\\/flter-spray\\/flter-spray-2.webp\"]', NULL, 'NN-2443-2U0IO', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, 6, 0, 0, 100, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 804, '2025-03-12 20:56:12', '2025-05-13 10:50:37', 1, 'Botble\\ACL\\Models\\User', 'products/flter-spray/we410-2.png', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(296, 'RUBY SHOP ชุดสปริง เครื่องยิงโฟม-Spring of grouting machine รุ่น PU-Spring-01', '<h5>ชุดสปริงสำหรับเครื่องยิงโฟม รุ่น PU-Spring-01 จาก RUBY SHOP เป็นอะไหล่ทดแทนที่สำคัญสำหรับเครื่องยิงโฟม ทำหน้าที่เป็นตัวช่วยในการดันลูกสูบหรือส่วนประกอบอื่นๆ ภายในเครื่องยิงโฟม ทำให้เครื่องทำงานได้อย่างมีประสิทธิภาพและราบรื่น การเปลี่ยนสปริงเมื่อมีการชำรุดหรือหมดสภาพ จะช่วยรักษาประสิทธิภาพของเครื่องยิงโฟมและยืดอายุการใช้งาน</h5>', '<h5><strong>คุณสมบัติ:</strong></h5><ul><li><strong>วัสดุคุณภาพสูง:</strong> ผลิตจากวัสดุที่มีความทนทานต่อแรงกดและแรงดึง ทำให้มีอายุการใช้งานยาวนาน</li><li><strong>ตรงรุ่น:</strong> ออกแบบมาให้ตรงกับรุ่นของเครื่องยิงโฟม ทำให้สามารถติดตั้งได้อย่างง่ายดายและพอดี</li><li><strong>ประสิทธิภาพสูง:</strong> ช่วยให้เครื่องยิงโฟมทำงานได้อย่างมีประสิทธิภาพและราบรื่น</li><li><strong>ง่ายต่อการเปลี่ยน:</strong> สามารถเปลี่ยนสปริงได้ง่ายด้วยตัวเอง โดยไม่ต้องใช้อุปกรณ์พิเศษ</li></ul>', 'published', '[\"products\\/bx.webp\"]', NULL, 'NN-2443-621FK', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, 0, 0, 0, 450, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 718, '2025-03-12 20:56:13', '2025-03-12 20:56:13', 1, 'Botble\\ACL\\Models\\User', 'products/bx-1.webp', 'physical', '', NULL, 0, 0, 0, 0, NULL),
(297, 'RUBY SHOP ลูกสูบ เครื่องยิงโฟม- Piston of grouting machine รุ่น Part-RB-WE-02', '<h5>ลูกสูบสำหรับเครื่องยิงโฟม รุ่น Part-RB-WE-02 จาก RUBY SHOP เป็นอะไหล่ทดแทนที่สำคัญ ทำหน้าที่เป็นตัวขับเคลื่อนสารเคมีภายในเครื่องยิงโฟม การเลือกใช้ลูกสูบที่มีคุณภาพจะช่วยให้เครื่องยิงโฟมทำงานได้อย่างมีประสิทธิภาพและมีอายุการใช้งานยาวนาน</h5>', '<h5><strong>คุณสมบัติ:</strong></h5><ul><li><strong>วัสดุคุณภาพสูง:</strong> ผลิตจากวัสดุที่มีความทนทานต่อแรงกด แรงเสียดทาน และสารเคมี ทำให้มีอายุการใช้งานยาวนาน</li><li><strong>ขนาดแม่นยำ:</strong> ผลิตด้วยความแม่นยำสูง ทำให้สามารถติดตั้งเข้ากับเครื่องยิงโฟมได้อย่างพอดี</li><li><strong>ประสิทธิภาพสูง:</strong> ช่วยให้เครื่องยิงโฟมทำงานได้อย่างมีประสิทธิภาพและราบรื่น</li><li><strong>ง่ายต่อการติดตั้ง:</strong> สามารถติดตั้งได้ง่ายด้วยตัวเอง</li></ul><p> </p>', 'published', '[\"products\\/1-1-2.webp\"]', NULL, 'NN-2443-DG9I3', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, 0, 0, 0, 990, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 729, '2025-03-12 20:56:14', '2025-03-12 20:56:14', 1, 'Botble\\ACL\\Models\\User', 'products/1-1-3.webp', 'physical', '', NULL, 0, 0, 0, 0, NULL),
(298, 'RUBY SHOP ลูกสูบ เครื่องยิงโฟม- Piston of grouting machine รุ่น Part-RB-WE-01', '<h5>ลูกสูบสำหรับเครื่องยิงโฟม รุ่น Part-RB-WE-01 จาก RUBY SHOP เป็นอะไหล่ทดแทนที่สำคัญสำหรับเครื่องยิงโฟม ทำหน้าที่เป็นตัวขับเคลื่อนสารเคมีภายในเครื่องยิงโฟม ทำให้เครื่องทำงานได้อย่างมีประสิทธิภาพและราบรื่น การเลือกใช้ลูกสูบที่มีคุณภาพจะช่วยยืดอายุการใช้งานของเครื่องยิงโฟม</h5><h5> </h5>', '<h5><strong>คุณสมบัติ:</strong></h5><ul><li><strong>วัสดุคุณภาพสูง:</strong> ผลิตจากวัสดุที่มีความทนทานต่อแรงกด แรงเสียดทาน และสารเคมี ทำให้มีอายุการใช้งานยาวนาน</li><li><strong>ขนาดแม่นยำ:</strong> ผลิตด้วยความแม่นยำสูง ทำให้สามารถติดตั้งเข้ากับเครื่องยิงโฟมได้อย่างพอดี</li><li><strong>ประสิทธิภาพสูง:</strong> ช่วยให้เครื่องยิงโฟมทำงานได้อย่างมีประสิทธิภาพและราบรื่น</li><li><strong>ง่ายต่อการติดตั้ง:</strong> สามารถติดตั้งได้ง่ายด้วยตัวเอง</li></ul>', 'published', '[\"products\\/1-2-1.webp\"]', NULL, 'NN-2443-DGRZY', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, 0, 0, 0, 990, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 705, '2025-03-12 20:56:15', '2025-03-12 20:56:15', 1, 'Botble\\ACL\\Models\\User', 'products/1-2-2.webp', 'physical', '', NULL, 0, 0, 0, 0, NULL),
(299, 'RUBY SHOP เครื่องพ่นพียู สีกันซึม - Cement injection pump รุ่น PU-Form-03', '<ul><li><h5>เครื่องพ่นพียู สีกันซึม รุ่น PU-Form-03 จาก RUBY SHOP </h5></li><li><h5>เป็นเครื่องมือที่ออกแบบมาสำหรับการใช้งานพ่นโพลียูรีเทน (PU) และสีกันซึม </h5></li><li><h5>เหมาะสำหรับงานหลากหลายประเภท เช่น งานก่อสร้าง งานซ่อมแซม และงานอุตสาหกรรม </h5></li><li><h5>เครื่องพ่นรุ่นนี้ใช้งานง่าย พกพาสะดวก และมีประสิทธิภาพสูง</h5></li><li><h5> </h5></li></ul>', '<h5><strong>คุณสมบัติ:</strong></h5><ul><li><strong>ใช้งานง่าย:</strong> ออกแบบมาให้ใช้งานง่าย ไม่ซับซ้อน เหมาะสำหรับทั้งมืออาชีพและผู้ใช้งานทั่วไป</li><li><strong>พกพาสะดวก:</strong> มีขนาดกะทัดรัดและน้ำหนักเบา ทำให้สะดวกในการเคลื่อนย้ายและใช้งานในสถานที่ต่างๆ</li><li><strong>ประสิทธิภาพสูง:</strong> สามารถพ่นพียูและสีกันซึมได้อย่างมีประสิทธิภาพ ทำให้งานเสร็จรวดเร็วและมีคุณภาพ</li><li><strong>ทนทาน:</strong> ผลิตจากวัสดุที่มีคุณภาพสูง ทนทานต่อการใช้งานและมีอายุการใช้งานยาวนาน</li><li><strong>หลากหลายการใช้งาน:</strong> เหมาะสำหรับงานพ่นพียูและสีกันซึมในงานต่างๆ เช่น งานกันซึม งานเคลือบผิว และงานซ่อมแซม</li></ul>', 'published', '[\"products\\/pu-form-03-2.webp\",\"products\\/pu-form-03-7.webp\",\"products\\/pu-form-03-8.webp\",\"products\\/pu-form-03-6.webp\",\"products\\/pu-form-03-5.webp\",\"products\\/pu-form-03-3.webp\"]', NULL, 'NN-2443-IZ50O', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 15000, 12000, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 818, '2025-03-12 20:56:17', '2025-05-05 10:27:38', 1, 'Botble\\ACL\\Models\\User', 'products/pu-form-03-2-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(300, 'RUBY SHOP เครื่องพ่นกันซึม - Waterproof Coating Putty รุ่น RB-WE-850', '<ul><li><h5>เครื่องพ่นกันซึมรุ่น RB-WE-850 จาก RUBY SHOP </h5></li><li><h5>เป็นเครื่องมือที่ออกแบบมาสำหรับการพ่นวัสดุกันซึมประเภทต่างๆ เช่น สีกันซึม โพลียูรีเทน และอะคริลิค </h5></li><li><h5>เหมาะสำหรับงานหลากหลายประเภท ตั้งแต่งานก่อสร้างขนาดใหญ่ไปจนถึงงานซ่อมแซมบ้านทั่วไป </h5></li><li><h5>เครื่องพ่นรุ่นนี้ใช้งานง่าย พกพาสะดวก และมีประสิทธิภาพสูง ทำให้งานกันซึมเป็นเรื่องง่ายและรวดเร็ว</h5><p> </p></li></ul>', '<h5><strong>คุณสมบัติ:</strong></h5><ul><li><strong>ใช้งานง่าย:</strong> ออกแบบมาให้ใช้งานง่าย ไม่ซับซ้อน เหมาะสำหรับทั้งมืออาชีพและผู้ใช้งานทั่วไป</li><li><strong>พกพาสะดวก:</strong> มีขนาดกะทัดรัดและน้ำหนักเบา ทำให้สะดวกในการเคลื่อนย้ายและใช้งานในสถานที่ต่างๆ</li><li><strong>ประสิทธิภาพสูง:</strong> สามารถพ่นวัสดุกันซึมได้อย่างมีประสิทธิภาพ ทำให้งานเสร็จรวดเร็วและมีคุณภาพ</li><li><strong>ทนทาน:</strong> ผลิตจากวัสดุที่มีคุณภาพสูง ทนทานต่อการใช้งานและมีอายุการใช้งานยาวนาน</li><li><strong>หลากหลายการใช้งาน:</strong> เหมาะสำหรับงานพ่นวัสดุกันซึมประเภทต่างๆ เช่น งานกันซึมหลังคา งานกันซึมผนัง และงานกันซึมพื้น</li></ul>', 'published', '[\"products\\/rb-we-850.webp\"]', NULL, 'NN-2443-YMGKO', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 55000, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 823, '2025-03-12 20:56:18', '2025-05-05 10:28:18', 1, 'Botble\\ACL\\Models\\User', 'products/rb-we-850-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(301, 'RUBYSHOP เครื่องยิงโฟม ยิงอิพ๊อกซี่ ขนาดเล็ก ยิง PU Foam Injection กันรั่วซึม ปิดรอยต่างๆรุ่น RB-WE02', '<ul><li><h5>เครื่องยิงโฟมอิงค์เจ็ทชั่น คือเครื่องมือที่ใช้ในการฉีดอัดสารเคมีพิเศษ เช่น อีพ็อกซี่และโพลียูรีเทนโฟม </h5></li><li><h5>มักใช้ในงานซ่อมรอยร้าวคอนกรีต หรืองานที่ต้องการป้องกันน้ำรั่ว </h5></li><li><h5>อัตราการใช้งานทั่วไปจะอยู่ที่มากกว่า 8,000 psi</h5></li><li><h5>เหมาะสำหรับงานซ่อมแซมที่ต้องการความแข็งแรงและความทนทานสูง</h5></li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><ul><li>เครื่องยิงโฟมขนาดเล็ก พกพาสะดวก</li><li>ใช้สำหรับอุดรอยรั่วน้ำซึม รอยแตกร้าวของคอนกรีต</li><li>ใช้ปิดรอยร้าวของผนัง / รอยน้ำซึมจากผนัง / ปิดรอยจุดต่างๆ จากการเจาะผนัง</li><li>เหมาะกับเคมีภัณฑ์ที่เป็น Part เดียว เพราะเป็นโถเดี่ยว (ไม่สามารถใช้กับเคมีภัณฑ์ที่ผสมแล้วฟูทันที)</li><li>รองรับ PU Foam อีพ็อกซี่ เรซิ่น น้ำยาโพลียูรีเทนฯ</li></ul><p> </p><h5><strong>การซ่อมรอยร้าวด้วยโฟม</strong></h5><ul><li>เหมาะสำหรับรอยร้าวขนาดใหญ่หรือช่องว่างที่ต้องการอุด</li><li>โฟม PU สามารถขยายตัวเพื่อเติมเต็มพื้นที่ได้ดี</li><li>ให้คุณสมบัติในการกันน้ำและความร้อน</li></ul><p> </p><h5><strong>การซ่อมรอยร้าวด้วยอีพ็อกซี่</strong></h5><ul><li>เหมาะสำหรับรอยร้าวขนาดเล็กถึงปานกลาง</li><li>ให้ความแข็งแรงสูง เหมาะสำหรับพื้นผิวที่ต้องรับน้ำหนัก</li><li>สามารถขัดแต่งให้เรียบเนียนได้หลังแห้ง</li></ul><p> </p><h5><strong>รายละเอียด</strong></h5><ul><li>กำลังไฟ : 900W</li><li>แรงดันไฟฟ้า : 220V</li><li>อัตราการพ่น : 0-1L/min</li><li>ถังบรรจุได้ : 2 ลิตร</li><li>รอบความเร็ว : 0-2800r/min</li><li>แรงดันเริ่มต้น : &lt;7500Psi</li><li>แรงดันสูงสุด : 15000Psi</li><li>ขนาดเครื่อง ; 60x40x44cm</li><li>น้ำหนักเครื่อง : 6.8 Kg</li></ul><p> </p><h5><strong>ขั้นตอนการซ่อม</strong></h5><ul><li>ทำความสะอาดรอยร้าวให้ปราศจากฝุ่นและสิ่งสกปรก</li><li>ใช้เครื่องยิงโฟมหรืออีพ็อกซี่ฉีดเข้าไปในรอยร้าว</li><li>ปาดแต่งให้เรียบร้อยหลังวัสดุแห้ง</li></ul><p> </p><h5><strong>อุปกรณ์ในชุด</strong></h5><ul><li>เครื่องยิงโฟม RB-WE02 x1</li><li>สายยิงโฟม x1</li><li>ปืนยิงโฟม x1</li><li>ตะแกรงกรอง x1</li><li>ไขควง x1</li><li>ซีลยาง x2</li></ul><p> </p><h5><strong>ข้อควรระวัง</strong></h5><ul><li>สวมอุปกรณ์ป้องกันส่วนบุคคล เช่น ถุงมือ แว่นตา และหน้ากาก</li><li>ทำงานในพื้นที่ที่มีอากาศถ่ายเทสะดวก</li><li>ปฏิบัติตามคำแนะนำของผู้ผลิตอย่างเคร่งครัด</li></ul><p> </p><h5><strong>หมายเหตุ :</strong> รับประกันซ่อมฟรี 1 ปี (ไม่รวมอะไหล่) ค่าฟรี 1 ปี</h5>', 'published', '[\"products\\/rb-we02-1.webp\",\"products\\/rb-we02-2.webp\",\"products\\/rb-we02-4.webp\",\"products\\/rb-we02-3.webp\",\"products\\/rb-we02-5.webp\"]', NULL, 'NN-2443-45AKN', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 12000, 9900, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 886, '2025-03-12 20:56:24', '2025-05-05 09:39:06', 1, 'Botble\\ACL\\Models\\User', 'products/rb-we02-1-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL);
INSERT INTO `ec_products` (`id`, `name`, `description`, `content`, `status`, `images`, `video_media`, `sku`, `order`, `sort_order_product_page`, `sort_order_category_page`, `quantity`, `allow_checkout_when_out_of_stock`, `with_storehouse_management`, `stock_status`, `is_featured`, `brand_id`, `is_variation`, `sale_type`, `price`, `sale_price`, `start_date`, `end_date`, `length`, `wide`, `height`, `weight`, `tax_id`, `views`, `created_at`, `updated_at`, `created_by_id`, `created_by_type`, `image`, `product_type`, `barcode`, `cost_per_item`, `generate_license_code`, `minimum_order_quantity`, `maximum_order_quantity`, `notify_attachment_updated`, `specification_table_id`) VALUES
(302, 'RUBYSHOP เครื่องยิงโฟม ยิง PU Foam Injection ยิงอิพ๊อกซี่ ขนาดเล็ก หน้าจอดิจิทัล ระบบรีโมท รุ่น RB-WE01', '<h5>เครื่องยิงโฟม PU รุ่น RB-WE01 เป็นเครื่องขนาดเล็กที่สามารถพกพาได้สะดวก ใช้ในการยิงโฟมและอีพอกซี่ โดยมีฟังก์ชันสำหรับปิดรอยรั่ว รอยแตกร้าวในโครงสร้างคอนกรีต และมีหน้าจอดิจิทัลแสดงค่า</h5>', '<h5><strong>รายละเอียดสินค้า</strong></h5><ul><li>เครื่องยิงโฟมขนาดเล็ก พกพาสะดวก</li><li>ควบคุมเครื่องได้ด้วยรีโมท</li><li>ใช้สำหรับอุดรอยรั่วน้ำซึม รอยแตกร้าวของคอนกรีต</li><li>ใช้ปิดรอยร้าวของผนัง / รอยน้ำซึมจากผนัง / ปิดรอยจุดต่างๆ จากการเจาะผนัง</li><li>เหมาะกับเคมีภัณฑ์ที่เป็น Part เดียว เพราะเป็นโถเดี่ยว (ไม่สามารถใช้กับเคมีภัณฑ์ที่ผสมแล้วฟูทันที)</li><li>รองรับ PU Foam อีพ็อกซี่ เรซิ่น น้ำยาโพลียูรีเทนฯ</li></ul><p> </p><h5><strong>รายละเอียดทางทคนิค</strong></h5><ul><li>ควบคุมด้วยรีโมท หรือเปิดปิดที่เครื่องได้เช่นกัน</li><li>กำลังไฟ : 900W</li><li>แรงดันไฟฟ้า : 220V</li><li>อัตราการพ่น : 0-1L/min</li><li>ขนาดนุภาคในการพ่น : 2mm</li><li>แรงดันเริ่มต้น : &lt;8000Psi</li><li>แรงดันสูงสุด : 12000Psi</li><li>ขนาดเครื่อง : 37.5x20x43.5cm</li><li>น้ำหนักเครื่อง : 6 Kg</li></ul><p> </p><h5><strong>อุปกรณ์ในชุด</strong></h5><ul><li>เครื่องยิงโฟม RB-WE01 x1</li><li>รีโมท x1</li><li>สายยิงโฟม x1</li><li>ปืนยิงโฟม x1</li><li>ตะแกรงกรอง x1</li><li>ไขควง x1</li><li>ซีลยาง x2</li></ul><p> </p><h5><strong>ขั้นตอนการใช้งานเครื่องยิงโฟม PU</strong></h5><ol><li><strong>เตรียมอุปกรณ์</strong><ul><li>ตรวจสอบว่าเครื่องยิงโฟม ภาชนะ และอุปกรณ์ที่เกี่ยวข้องอยู่ในสภาพดี</li><li>เตรียมโฟม PU และอีพ๊อกซี่ที่ต้องการใช้งาน</li></ul></li><li><strong>ตั้งค่าเครื่อง</strong><ul><li>เสียบปลั๊กเครื่องเข้าไปในเต้ารับไฟฟ้า</li><li>เปิดเครื่องและตั้งค่าด้วยรีโมท ควบคุมแรงดันและอัตราการไหลตามที่ต้องการ</li></ul></li><li><strong>ทดสอบการทำงาน</strong><ul><li>ทำการทดสอบยิงโฟมที่พื้นผิวที่ไม่สำคัญเพื่อตรวจสอบความสามารถของเครื่อง</li><li>ตรวจสอบการทำงานของปืนยิงโฟมว่าเป็นปกติหรือไม่</li></ul></li><li><strong>ยิงโฟม</strong><ul><li>ขึ้นอยู่กับการใช้งาน ยิงโฟมไปยังจุดที่ต้องการ โดยทำตามความหนาของโฟมที่ต้องการพ่น</li><li>ควรทำการยิงในมุมที่เหมาะสม เพื่อให้โฟมกระจายได้ดี</li></ul></li><li><strong>ทำความสะอาดหลังการใช้งาน</strong><ul><li>เปิดเครื่องให้ทำงานเพื่อให้โฟมที่เหลืออยู่ภายในระบบถูกพ่นออก</li><li>ทำความสะอาดหลอดและหัวพ่นด้วยตัวทำละลายที่เหมาะสม ตามคำแนะนำของผู้ผลิต</li></ul></li></ol><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li>สวมอุปกรณ์ป้องกัน เช่น หน้ากากและถุงมือ เพื่อป้องกันสารเคมีที่อาจเป็นอันตราย</li><li>ตรวจสอบให้แน่ใจว่าพื้นที่ทำงานมีการระบายอากาศที่ดี</li><li>ไม่ควรให้เด็กหรือสัตว์เข้าไปในพื้นที่ทำงานขณะที่กำลังใช้งาน</li></ul><p>หลังจากใช้เครื่องยิงโฟม PU ควรทำความสะอาดและเก็บรักษาเครื่องให้เรียบร้อย เพื่อยืดอายุการใช้งานของเครื่องและความปลอดภัยในการใช้งานครั้งต่อไป</p><p> </p>', 'published', '[\"products\\/3-39.webp\",\"products\\/2-46.webp\",\"products\\/1-69.webp\"]', NULL, 'NN-2443-FB6SH', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 18000, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 676, '2025-03-12 20:56:25', '2025-05-05 09:39:44', 1, 'Botble\\ACL\\Models\\User', 'products/3-40.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(303, 'RUBYSHOP เครื่องยิงโฟม RB-WE-900 ยิง PU Foam Injection ยิงอิพ็อกซี่ ขนาดเล็ก อุดน้ำรั่วซึม', '', '<h5><strong>รายละเอียดสินค้า</strong></h5><ul><li>เป็นเครื่องยิงโฟมแบบพกพา ใช้งานสะดวก</li><li>ออกแบบมาเพื่อยิงซีเมนต์กันซึมโดยเฉพาะ</li><li>สามารถใช้งานได้ทั้งในแนวตั้งและแนวนอน</li><li>ใช้ปิดรอยร้าวของผนัง / รอยน้ำซึมจากผนัง / ปิดรอยจุดต่างๆ จากการเจาะผนัง</li><li>ใช้กับอีพ็อกซี่และ PU Foam Injection ได้</li><li>เหมาะสำหรับซ่อมแซมรอยรั่วในผนัง พื้น หรือหลังคา</li><li>สามารถใช้กับรอยแตกร้าวขนาดเล็กถึงปานกลาง</li><li>ให้ประสิทธิภาพในการกันน้ำได้ดี</li></ul><p> </p><h5><strong>ข้อมูลทางเทคนิค</strong></h5><ul><li>กำลังไฟ : 1000W</li><li>กระแสไฟ : 220V</li><li>ความถี่ : 50Hz</li><li>พ่นได้ : 1-10L/min</li><li>แรงดันสูงสุด : 0.6Mpa</li><li>บรรจุเคมีภัณฑ์ได้ : 10 ลิตร</li></ul><h5> </h5><h5><strong>ขั้นตอนการใช้งาน</strong></h5><ol><li>ทำความสะอาดบริเวณที่จะซ่อมแซม</li><li>เตรียมซีเมนต์กันซึมตามคำแนะนำของผู้ผลิต</li><li>บรรจุซีเมนต์ลงในเครื่อง RB-WE-900</li><li>ปรับหัวฉีดและแรงดันให้เหมาะสม</li><li>ยิงซีเมนต์ลงบนรอยรั่วซึม</li></ol><h5> </h5><h5><strong>ข้อดีของการใช้เครื่อง RB-WE-900</strong></h5><ul><li>ประหยัดเวลาและแรงงานในการซ่อมแซม</li><li>ให้ความแม่นยำในการยิงซีเมนต์</li><li>สามารถเข้าถึงพื้นที่ที่ยากลำบากได้</li></ul><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรสวมอุปกรณ์ป้องกันส่วนบุคคล เช่น แว่นตาและถุงมือ</li><li>ทำความสะอาดเครื่องหลังใช้งานทุกครั้ง</li><li>ปฏิบัติตามคำแนะนำของผู้ผลิตอย่างเคร่งครัด</li></ul><h5> </h5><h5><strong>หมายเหตุ:</strong> รับประกันซ่อมฟรี 1 ปี (ไม่รวมอะไหล่)</h5>', 'published', '[\"products\\/messageimage-1660980692961.webp\",\"products\\/1671781066111.webp\",\"products\\/1671781081892.webp\",\"products\\/1671781049595.webp\"]', NULL, 'NN-2443-8NLBQ', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 5900, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 949, '2025-03-12 20:56:27', '2025-11-06 10:38:36', 1, 'Botble\\ACL\\Models\\User', 'products/messageimage-1660980692961-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(304, 'RUBYSHOP เครื่องยิงโฟม RB-WE-780 พ่นกันซึม ยิง PU Foam Injection ยิงอิพ็อกซี่', '<h5>เครื่องยิงโฟม RB-WE-780 จาก RUBYSHOP เป็นเครื่องมืออเนกประสงค์ที่ออกแบบมาสำหรับงานพ่นโฟม PU, งานกันซึม และงานฉีดอีพ็อกซี่ เหมาะสำหรับงานหลากหลายประเภท ตั้งแต่งานก่อสร้างขนาดใหญ่ไปจนถึงงานซ่อมแซมบ้านทั่วไป เครื่องพ่นรุ่นนี้มีกำลังสูง ถังบรรจุขนาดใหญ่ และใช้งานง่าย ทำให้งานของคุณเป็นเรื่องง่ายและรวดเร็ว</h5>', '<h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>กำลังไฟสูง:</strong> 2850W ให้พลังในการพ่นที่แรงและต่อเนื่อง เหมาะสำหรับวัสดุที่มีความหนืดสูง</li><li><strong>ความจุถังขนาดใหญ่:</strong> 25 ลิตร ทำให้สามารถทำงานได้อย่างต่อเนื่องโดยไม่ต้องเติมวัสดุบ่อยๆ</li><li><strong>แรงดันสูง:</strong> 2Mpa สามารถพ่นวัสดุได้ไกลและทั่วถึง</li><li><strong>ใช้งานอเนกประสงค์:</strong> สามารถใช้กับ PU Foam Injection, อีพ็อกซี่ และวัสดุกันซึมประเภทต่างๆ</li><li><strong>เหมาะสำหรับงานหลากหลายประเภท:</strong> ใช้ปิดรอยร้าวของผนัง, รอยน้ำซึมจากผนัง, ปิดรอยจุดต่างๆ จากการเจาะผนัง และงานกันซึมทั่วไป</li></ul><p> </p><h5><strong>ข้อมูลทางเทคนิค</strong></h5><ul><li>กำลังไฟ : 2850W</li><li>กระแสไฟ : 220V</li><li>ความถี่ : 50Hz</li><li>อัตราการพ่น : 10L/min</li><li>แรงดันสูงสุด : 2Mpa</li><li>ความจุถัง : 25L</li></ul><p> </p><h5><strong>การใช้งาน</strong></h5><h5>เครื่องยิงโฟม RB-WE-780 เหมาะสำหรับงานหลากหลายประเภท เช่น</h5><ul><li><strong>งานพ่น PU Foam Injection:</strong> ใช้สำหรับอุดรอยรั่ว รอยร้าวในคอนกรีต และงานซ่อมแซมโครงสร้าง</li><li><strong>งานพ่นกันซึม:</strong> ใช้สำหรับพ่นวัสดุกันซึมบนหลังคา ผนัง และพื้น เพื่อป้องกันการรั่วซึมของน้ำ</li><li><strong>งานฉีดอีพ็อกซี่:</strong> ใช้สำหรับงานซ่อมแซมและเสริมความแข็งแรงของโครงสร้าง</li></ul><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรเลือกใช้วัสดุที่เหมาะสมกับงาน</li><li><p>ควรทำความสะอาดเครื่องหลังการใช้งานทุกครั้ง</p><p> </p></li></ul>', 'published', '[\"products\\/2-47.webp\",\"products\\/1-70.webp\"]', NULL, 'NN-2443-M7WRW', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, 0, 0, 0, 45000, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 748, '2025-03-12 20:56:29', '2025-03-12 20:56:29', 1, 'Botble\\ACL\\Models\\User', 'products/1-71.webp', 'physical', '', NULL, 0, 0, 0, 0, NULL),
(305, 'RUBY SHOP Drywall stilt - อุปกรณ์ขาต่อ ปรับความสูงได้ถึง 78 ซม. ผลิตจากอลูมิเนียม รุ่น RB-Drywall stilt', '<ul><li>อุปกรณ์ขาต่อที่ช่วยให้คุณทำงานบนที่สูงได้อย่างสะดวกและปลอดภัย </li><li>เหมาะสำหรับงานติดตั้ง drywall, งานทาสี, งานฝ้าเพดาน และงานก่อสร้างอื่นๆ ที่ต้องทำงานในที่สูง</li></ul><p> </p>', '<h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>ปรับความสูงได้:</strong> สามารถปรับความสูงได้ตั้งแต่ 47 ซม. ถึง 78 ซม. ทำให้เหมาะกับความสูงที่หลากหลาย</li><li><strong>วัสดุคุณภาพ:</strong> ผลิตจากอลูมิเนียมคุณภาพดี แข็งแรง ทนทาน และน้ำหนักเบา</li><li><strong>มั่นคงและปลอดภัย:</strong> มีตัวล็อคขาและเท้าที่แข็งแรง ช่วยให้คุณทรงตัวได้อย่างมั่นคงและปลอดภัยขณะทำงาน</li><li><strong>ใช้งานง่าย:</strong> ออกแบบมาให้ใช้งานง่าย สะดวก และรวดเร็ว</li><li><strong>อเนกประสงค์:</strong> เหมาะสำหรับงานหลากหลายประเภท เช่น งานติดตั้ง drywall, งานทาสี, งานฝ้าเพดาน และงานก่อสร้างอื่นๆ</li></ul><h5> </h5><h5><strong>ข้อมูลจำเพาะ</strong></h5><ul><li><strong>รุ่น:</strong> RB-Drywall stilt</li><li><strong>วัสดุ:</strong> อลูมิเนียม</li><li><p><strong>ความสูง:</strong> ปรับได้ 47-78 ซม.</p><p> </p></li></ul><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรตรวจสอบอุปกรณ์ก่อนใช้งานทุกครั้ง</li><li>ควรสวมอุปกรณ์ป้องกันความปลอดภัย เช่น หมวกนิรภัยและเข็มขัดนิรภัย</li><li>ควรใช้งานในพื้นที่ที่ปลอดภัยและมั่นคง</li></ul><p> </p><h5><strong>คำแนะนำ</strong></h5><ul><li>ควรฝึกฝนการใช้งานอุปกรณ์ในพื้นที่ที่ปลอดภัยก่อนใช้งานจริง</li><li>ควรปรับความสูงของอุปกรณ์ให้เหมาะสมกับความสูงของพื้นที่ทำงาน</li><li>ควรระมัดระวังขณะใช้งานอุปกรณ์ในที่สูง</li></ul><p> </p>', 'published', '[\"products\\/rb-drywall-stilt-5.webp\",\"products\\/rb-drywall-stilt-3.webp\",\"products\\/rb-drywall-stilt-2.webp\",\"products\\/rb-drywall-stilt-1.webp\"]', NULL, 'NN-2443-ZOD7V', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 5900, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 752, '2025-03-12 20:56:33', '2025-05-05 10:23:07', 1, 'Botble\\ACL\\Models\\User', 'products/rb-drywall-stilt-1-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(306, 'RUBY SHOP ปั๊มลมคู่ แรงเกินต้านนนน ของคู่ใจที่นายช่างต้องมี', '<ul><li><h5>ปั๊มลมคู่รุ่นนี้จาก RUBY SHOP เป็นปั๊มลมที่ทรงพลัง </h5></li><li><h5>เหมาะสำหรับช่างมืออาชีพและผู้ใช้งานทั่วไป </h5></li><li><h5>ด้วยกำลังมอเตอร์ที่สูงถึง 3600W ทำให้ปั๊มลมสามารถผลิตลมได้อย่างรวดเร็วและมีแรงดันสูง </h5></li><li><h5>เหมาะสำหรับงานที่ต้องการลมปริมาณมากและแรงดันสูง เช่น งานเติมลมยางรถยนต์ขนาดใหญ่ </h5></li></ul>', '<h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>กำลังมอเตอร์สูง:</strong> 3600W ให้พลังในการผลิตลมที่รวดเร็วและต่อเนื่อง</li><li><strong>แรงดันลมสูง:</strong> 145 Psi เหมาะสำหรับงานที่ต้องการแรงดันลมสูง</li><li><strong>ปริมาณลมมาก:</strong> 480L/min ทำให้สามารถใช้งานได้อย่างต่อเนื่อง</li><li><strong>ใช้งานอเนกประสงค์:</strong> เหมาะสำหรับงานเติมลม เป่าฝุ่น พ่นสี และงานอื่นๆ</li><li><strong>เคลื่อนย้ายสะดวก:</strong> มีล้อคู่และน้ำหนักเพียง 30 กก. ทำให้เคลื่อนย้ายได้ง่าย</li><li><strong>ใช้กับถังแรงดันสูงได้:</strong> สามารถใช้งานร่วมกับถังแรงดันสูงเพื่อเพิ่มปริมาณลมและแรงดัน</li><li><strong>ที่จับพับได้:</strong> สะดวกในการจัดเก็บและพกพา</li></ul><h5> </h5><h5><strong>ข้อมูลจำเพาะ</strong></h5><ul><li>กำลังมอเตอร์: 3600W</li><li>แรงดันลม: 145 Psi</li><li>ปริมาณลม: 480L/min</li><li>น้ำหนัก: 30 กก.</li></ul><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรตรวจสอบปั๊มลมก่อนใช้งานทุกครั้ง</li><li>ควรสวมอุปกรณ์ป้องกันความปลอดภัย เช่น แว่นตาและถุงมือ ขณะใช้งาน</li><li>ควรใช้งานในพื้นที่ที่มีอากาศถ่ายเทสะดวก</li></ul><h5> </h5><h5><strong>คำแนะนำ</strong></h5><ul><li>ควรเลือกใช้ปั๊มลมให้เหมาะสมกับงาน</li><li>ควรดูแลรักษาปั๊มลมอย่างสม่ำเสมอ เพื่อยืดอายุการใช้งาน</li></ul>', 'published', '[\"products\\/1-72.webp\"]', NULL, 'NN-2443-ZUBHD', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 12000, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 546, '2025-03-12 20:56:34', '2025-05-05 10:23:54', 1, 'Botble\\ACL\\Models\\User', 'products/1-73.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(307, 'RUBYSHOP กระเป๋าเครื่องมือช่าง รุ่น RB-1002 คาดเอว พร้อมเข็มขัด กระเป๋าหนัง กระเป๋าคาดเอวช่าง', '<h5>กระเป๋าเครื่องมือช่าง RUBYSHOP รุ่น RB-1002 เป็นกระเป๋าคาดเอวที่ออกแบบมาสำหรับช่างมืออาชีพและผู้ใช้งานทั่วไปที่ต้องการความสะดวกในการพกพาเครื่องมือช่างติดตัว</h5>', '<h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>วัสดุคุณภาพ:</strong> ทำจากหนังแท้คุณภาพสูง มีความทนทานและใช้งานได้ยาวนาน</li><li><strong>ขนาดเหมาะสม:</strong> ขนาดกว้าง 12 x สูง 35 ซม. มีช่องเสียบขนาดใหญ่ 1 ช่อง เหมาะสำหรับใส่สว่าน กระป๋องสี หรือลวดเชื่อม</li><li><strong>สะดวกในการใช้งาน:</strong> มาพร้อมเข็มขัดคาดเอว ทำให้สะดวกในการพกพาเครื่องมือและใช้งานได้ทันที</li><li><strong>อเนกประสงค์:</strong> เหมาะสำหรับใช้เก็บเครื่องมือช่างและอุปกรณ์ต่างๆ เช่น คีม ไขควง ค้อน ตลับเมตร และอื่นๆ</li></ul><h5> </h5><h5><strong>ข้อมูลจำเพาะ</strong></h5><ul><li><strong>รุ่น:</strong> RB-1002</li><li><strong>วัสดุ:</strong> หนังแท้</li><li><strong>ขนาด:</strong> กว้าง 12 x สูง 35 ซม.</li><li><strong>จำนวนช่อง:</strong> 1 ช่องใหญ่</li></ul><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรดูแลรักษาและทำความสะอาดกระเป๋าหนังอย่างสม่ำเสมอ เพื่อยืดอายุการใช้งาน</li><li>ไม่ควรบรรทุกสิ่งของที่มีน้ำหนักเกินกว่าที่กระเป๋าสามารถรับได้</li></ul><p> </p><h5><strong>คำแนะนำ</strong></h5><ul><li>ควรเลือกใช้กระเป๋าเครื่องมือช่างให้เหมาะสมกับประเภทงานและจำนวนเครื่องมือที่ต้องการพกพา</li><li>ควรจัดเก็บเครื่องมือให้เป็นระเบียบ เพื่อความสะดวกในการใช้งานและป้องกันการสูญหาย</li></ul>', 'published', '[\"products\\/1-74.webp\",\"products\\/7-5.webp\",\"products\\/6-10.webp\",\"products\\/5-12.webp\",\"products\\/8-2.webp\"]', NULL, 'NN-2443-U8NF6', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 390, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 851, '2025-03-12 20:56:38', '2025-05-13 10:16:05', 1, 'Botble\\ACL\\Models\\User', 'products/1-75.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(308, 'RUBYSHOP เครื่องวัดความเร็วลม รุ่น RB-GM816 แบบดิจิทัล เครื่องวัดปริมาณลม อุณหภูมิลม', '<p>เครื่องวัดความเร็วลมรุ่น RB-GM816 จาก RUBYSHOP เป็นอุปกรณ์ที่ออกแบบมาเพื่อวัดความเร็วลม ปริมาณลม และอุณหภูมิ เหมาะสำหรับใช้งานในหลากหลายสถานการณ์ เช่น การตรวจสอบสภาพอากาศ การใช้งานในงานอุตสาหกรรม หรือกิจกรรมกลางแจ้งต่างๆ</p>', '<h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>ขนาดกะทัดรัดและน้ำหนักเบา:</strong> พกพาสะดวก มาพร้อมเชือกสำหรับคล้องคอ</li><li><strong>จอแสดงผล LCD:</strong> อ่านค่าได้ง่ายและชัดเจน</li><li><strong>หน่วยวัดหลากหลาย:</strong><ul><li>อุณหภูมิ: °C, °F</li><li>ความเร็วลม: M/S, FT/Min, Knots, Km/hr, MPH</li></ul></li><li><strong>ช่วงการวัดความเร็วลม:</strong> 0.8-30 m/s</li><li><strong>ใช้งานง่าย:</strong> มีปุ่มควบคุมที่ใช้งานสะดวก</li></ul><h5> </h5><h5><strong>ข้อมูลจำเพาะ</strong></h5><ul><li><strong>รุ่น:</strong> RB-GM816</li><li><strong>ประเภท:</strong> เครื่องวัดความเร็วลมแบบดิจิทัล</li><li><strong>ช่วงการวัดความเร็วลม:</strong> 0.8-30 m/s</li><li><strong>หน่วยวัดความเร็วลม:</strong> M/S, FT/Min, Knots, Km/hr, MPH</li><li><strong>ช่วงการวัดอุณหภูมิ:</strong> (ระบุช่วง)</li><li><strong>หน่วยวัดอุณหภูมิ:</strong> °C, °F</li><li><p><strong>จอแสดงผล:</strong> LCD</p><p> </p></li></ul><h5><strong>การใช้งาน</strong></h5><h5>เครื่องวัดความเร็วลม RB-GM816 เหมาะสำหรับใช้งานในสถานการณ์ต่างๆ เช่น</h5><ul><li><strong>การตรวจสอบสภาพอากาศ:</strong> ใช้เพื่อวัดความเร็วลมและอุณหภูมิ เพื่อพยากรณ์อากาศหรือวางแผนกิจกรรมกลางแจ้ง</li><li><strong>การใช้งานในงานอุตสาหกรรม:</strong> ใช้เพื่อตรวจสอบความเร็วลมในระบบระบายอากาศ หรือตรวจสอบประสิทธิภาพของพัดลม</li><li><strong>กิจกรรมกลางแจ้ง:</strong> ใช้สำหรับกิจกรรมต่างๆ เช่น การเล่นเรือใบ การเล่นวินด์เซิร์ฟ หรือการเดินป่า</li></ul><p> </p><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรตรวจสอบอุปกรณ์ก่อนใช้งานทุกครั้ง</li><li>ควรใช้งานในสภาพแวดล้อมที่เหมาะสม</li><li>ควรเก็บรักษาอุปกรณ์ในที่แห้งและพ้นจากแสงแดด</li></ul><h5> </h5><h5><strong>คำแนะนำ</strong></h5><ul><li>ควรเลือกใช้เครื่องวัดความเร็วลมให้เหมาะสมกับช่วงการวัดที่ต้องการ</li><li>ควรสอบเทียบเครื่องวัดความเร็วลมเป็นประจำ เพื่อให้ได้ค่าที่แม่นยำ</li></ul>', 'published', '[\"products\\/8-3.webp\",\"products\\/7-6.webp\",\"products\\/6-11.webp\",\"products\\/5-13.webp\",\"products\\/4-21.webp\",\"products\\/3-41.webp\",\"products\\/2-48.webp\",\"products\\/1-76.webp\"]', NULL, 'NN-2443-I2H73', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 490, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 852, '2025-03-12 20:56:41', '2025-05-13 10:15:37', 1, 'Botble\\ACL\\Models\\User', 'products/8-4.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(309, 'RUBYSHOP เครื่องวัดความเร็วลม  LCD แบบดิจิทัล เครื่องวัดปริมาณลม อุณหภูมิลม เครื่องมือช่าง', '<h5>เครื่องวัดความเร็วลมรุ่นนี้จาก RUBYSHOP เป็นอุปกรณ์ที่ใช้งานได้หลากหลาย เหมาะสำหรับวัดความเร็วลม ปริมาณลม และอุณหภูมิ มาพร้อมฟังก์ชั่นที่ตอบโจทย์การใช้งานที่หลากหลาย</h5><h5> </h5>', '<h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>ขนาดกะทัดรัดและน้ำหนักเบา:</strong> พกพาสะดวก มาพร้อมเชือกคล้องคอ</li><li><strong>จอแสดงผล LCD พร้อมไฟแบ็คไลท์:</strong> อ่านค่าได้ง่ายและชัดเจน แม้ในสภาวะแสงน้อย</li><li><strong>วัดความเร็วลมได้หลากหลายหน่วย:</strong> M/S, ft/s, Knots, Km/h, mile/h</li><li><strong>ช่วงการวัดความเร็วลมกว้าง:</strong> 0.8-30m/s</li><li><strong>วัดปริมาณลม (CFM) ได้:</strong> เหมาะสำหรับตรวจสอบปริมาณลมในระบบต่างๆ</li><li><strong>วัดอุณหภูมิได้:</strong> °C</li><li><strong>ใช้งานง่าย:</strong> มีปุ่มควบคุมที่ใช้งานสะดวก</li></ul><p> </p><h5><strong>การใช้งาน</strong></h5><h5>เครื่องวัดความเร็วลมรุ่นนี้เหมาะสำหรับใช้งานในสถานการณ์ต่างๆ เช่น</h5><ul><li><strong>การตรวจสอบสภาพอากาศ:</strong> วัดความเร็วลมและอุณหภูมิเพื่อพยากรณ์อากาศ</li><li><strong>งานอุตสาหกรรม:</strong> ตรวจสอบความเร็วลมในระบบระบายอากาศ</li><li><strong>กิจกรรมกลางแจ้ง:</strong> ใช้สำหรับกิจกรรมต่างๆ เช่น การเล่นเรือใบ</li></ul><p> </p><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรตรวจสอบอุปกรณ์ก่อนใช้งานทุกครั้ง</li><li>ควรใช้งานในสภาพแวดล้อมที่เหมาะสม</li><li>ควรเก็บรักษาอุปกรณ์ในที่แห้งและพ้นจากแสงแดด</li></ul><p> </p><h5><strong>คำแนะนำ</strong></h5><ul><li>ควรเลือกใช้เครื่องวัดความเร็วลมให้เหมาะสมกับช่วงการวัดที่ต้องการ</li><li>ควรสอบเทียบเครื่องวัดความเร็วลมเป็นประจำ เพื่อให้ได้ค่าที่แม่นยำ</li></ul><p> </p>', 'published', '[\"products\\/8-5.webp\",\"products\\/7-7.webp\",\"products\\/6-12.webp\",\"products\\/5-14.webp\",\"products\\/4-22.webp\",\"products\\/3-42.webp\",\"products\\/2-49.webp\"]', NULL, 'NN-2443-2CO1J', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 1600, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 834, '2025-03-12 20:56:44', '2025-05-13 10:14:53', 1, 'Botble\\ACL\\Models\\User', 'products/8-6.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(310, 'RUBYSHOP กระเป๋าเครื่องมือช่าง คาดเอว รุ่น RB-1021 พร้อมเข็มขัด กระเป๋าหนัง กระเป๋าคาดเอวช่าง', '<h5>กระเป๋าเครื่องมือช่าง RUBYSHOP รุ่น RB-1021 เป็นกระเป๋าคาดเอวที่ออกแบบมาสำหรับช่างมืออาชีพและผู้ใช้งานทั่วไปที่ต้องการความสะดวกในการพกพาเครื่องมือช่างติดตัว ด้วยขนาดที่เหมาะสมและช่องเก็บของที่หลากหลาย ทำให้คุณสามารถจัดเก็บเครื่องมือได้อย่างเป็นระเบียบและเข้าถึงได้ง่าย</h5>', '<h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>วัสดุคุณภาพ:</strong> ทำจากหนังแท้คุณภาพสูง มีความทนทานและใช้งานได้ยาวนาน ทนทานต่อการสึกหรอ และง่ายต่อการดูแลรักษา</li><li><strong>ขนาดเหมาะสม:</strong> ขนาดกว้าง 19 x สูง 22 ซม. ไม่ใหญ่หรือเล็กจนเกินไป เหมาะสำหรับการพกพาเครื่องมือที่จำเป็น</li><li><strong>ช่องเก็บของหลากหลาย:</strong><ul><li>1 ช่องใหญ่ สำหรับใส่เครื่องมือขนาดใหญ่ เช่น สว่าน หรือค้อน</li><li>1 ช่องเล็ก สำหรับใส่เครื่องมือขนาดเล็ก หรืออุปกรณ์เสริมต่างๆ เช่น ไขควง คีม หรือตลับเมตร</li></ul></li><li><strong>สะดวกในการใช้งาน:</strong> มาพร้อมเข็มขัดคาดเอว ทำให้สะดวกในการพกพาเครื่องมือและใช้งานได้ทันที ไม่ต้องเสียเวลาหาเครื่องมือในกระเป๋า</li><li><strong>อเนกประสงค์:</strong> เหมาะสำหรับใช้เก็บเครื่องมือช่างและอุปกรณ์ต่างๆ เช่น คีม ไขควง ค้อน ตลับเมตร และอื่นๆ</li></ul><h5> </h5><h5><strong>ข้อมูลจำเพาะ</strong></h5><ul><li><strong>รุ่น:</strong> RB-1021</li><li><strong>วัสดุ:</strong> หนังแท้</li><li><strong>ขนาด:</strong> กว้าง 19 x สูง 22 ซม.</li><li><strong>จำนวนช่อง:</strong> 2 ช่อง (1 ช่องใหญ่, 1 ช่องเล็ก)</li><li><strong>อุปกรณ์เสริม:</strong> เข็มขัดคาดเอว</li></ul><p> </p><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรดูแลรักษาและทำความสะอาดกระเป๋าหนังอย่างสม่ำเสมอ เพื่อยืดอายุการใช้งาน</li><li>ไม่ควรบรรทุกสิ่งของที่มีน้ำหนักเกินกว่าที่กระเป๋าสามารถรับได้ อาจทำให้กระเป๋าเสียหายหรือฉีกขาดได้</li><li>ควรเก็บรักษากระเป๋าในที่แห้งและพ้นจากแสงแดด เพื่อป้องกันหนังจากการเสื่อมสภาพ</li></ul><p> </p><h5><strong>คำแนะนำ</strong></h5><ul><li>ควรเลือกใช้กระเป๋าเครื่องมือช่างให้เหมาะสมกับประเภทงานและจำนวนเครื่องมือที่ต้องการพกพา</li><li>ควรจัดเก็บเครื่องมือให้เป็นระเบียบ เพื่อความสะดวกในการใช้งานและป้องกันการสูญหาย</li><li>ก่อนใช้งาน ควรตรวจสอบสภาพของกระเป๋าและเข็มขัดว่าอยู่ในสภาพพร้อมใช้งานหรือไม่</li></ul>', 'published', '[\"products\\/2-50.webp\",\"products\\/1-77.webp\"]', NULL, 'NN-2443-NILZT', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 490, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 857, '2025-03-12 20:56:47', '2025-05-13 10:15:13', 1, 'Botble\\ACL\\Models\\User', 'products/2-51.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(311, 'RUBYSHOP เครื่องตัดกระเบื้อง เครื่องตัดกระจก แบบ 2 in 1 สีทอง เครื่องมือตัดเซรามิค', '<h5>เครื่องตัดกระเบื้องและกระจก RUBYSHOP แบบ 2 in 1 สีทอง เป็นเครื่องมืออเนกประสงค์ที่ออกแบบมาสำหรับช่างมืออาชีพและผู้ใช้งานทั่วไปที่ต้องการความสะดวกและแม่นยำในการตัดวัสดุต่างๆ ไม่ว่าจะเป็นกระเบื้อง กระจก หรือเซรามิก ด้วยการออกแบบที่ใช้งานง่ายและฟังก์ชั่น 2 in 1 ทำให้เครื่องมือนี้เป็นตัวเลือกที่คุ้มค่าสำหรับงานตัดที่หลากหลาย</h5>', '<h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>2 in 1:</strong> สามารถใช้ตัดได้ทั้งกระจก กระเบื้อง และเซรามิก ทำให้เป็นเครื่องมือที่คุ้มค่าและอเนกประสงค์</li><li><strong>ใช้งานง่าย:</strong> เพียงแค่วาดมีดลงบนวัสดุที่ต้องการตัด จากนั้นใช้ที่หนีบกดลงไป วัสดุก็จะหักตามแนวที่วาดไว้</li><li><strong>สีทอง:</strong> สีทองเพิ่มความสวยงามและโดดเด่นให้กับเครื่องมือ</li></ul><p> </p><h5><strong>ข้อมูลจำเพาะ</strong></h5><ul><li><strong>ประเภท:</strong> เครื่องตัดกระเบื้องและกระจก</li><li><strong>สี:</strong> ทอง</li><li><strong>ฟังก์ชั่น:</strong> 2 in 1 (ตัดกระจก กระเบื้อง เซรามิก)</li></ul><p> </p><h5><strong>อุปกรณ์ในชุด</strong></h5><ul><li>ใบกรีด 2 ใบ</li><li>น้ำยา (สำหรับหล่อลื่นขณะตัด)</li><li>ตลับเมตร (สำหรับวัดขนาด)</li></ul><p> </p><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรสวมอุปกรณ์ป้องกันความปลอดภัย เช่น แว่นตาและถุงมือ ขณะใช้งาน</li><li>ควรระมัดระวังในการใช้งาน เพื่อป้องกันการบาดเจ็บ</li></ul><p> </p><h5><strong>คำแนะนำ</strong></h5><ul><li>ควรเลือกใช้ใบกรีดที่เหมาะสมกับวัสดุที่ต้องการตัด</li><li>ควรทำความสะอาดเครื่องมือหลังใช้งานทุกครั้ง เพื่อยืดอายุการใช้งาน</li></ul><p> </p>', 'published', '[\"products\\/1-78.webp\",\"products\\/3-43.webp\",\"products\\/4-23.webp\",\"products\\/2-52.webp\",\"products\\/5-15.webp\"]', NULL, 'NN-2443-R9ONR', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 450, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 836, '2025-03-12 20:56:49', '2025-04-17 05:25:04', 1, 'Botble\\ACL\\Models\\User', 'products/1-79.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(312, 'RUBYSHOP กระเป๋าเครื่องมือช่างคาดเอว ขนาด 11.5x26.5 cm พร้อมเข็มขัด เหมาะสำหรับใช้จัดเก็บอุปกรณ์เครื่องมือช่าง', '<h5>กระเป๋าเครื่องมือช่างคาดเอว RUBYSHOP เป็นกระเป๋าที่ออกแบบมาเพื่อใช้ในการเก็บเครื่องมือและอุปกรณ์ต่างๆ ของช่าง มีลักษณะเป็นกระเป๋าที่คาดเอวไว้ เพื่อให้สะดวกต่อการใช้งานและเคลื่อนที่ ผลิตจากหนังคุณภาพดี ทนทานในการใช้งาน</h5>', '<h5><strong>คุณสมบัติสำคัญ</strong></h5><ul><li><strong>วัสดุคุณภาพสูง:</strong> ทำจากหนังวัวแท้ ทนทานต่อการใช้งาน</li><li><strong>ขนาดเหมาะสม:</strong> กว้าง 11.5 x สูง 26.5 ซม. เหมาะสำหรับการพกพาเครื่องมือ</li><li><strong>ช่องเก็บของหลากหลาย:</strong><ul><li>2 ช่องใหญ่ สำหรับใส่เครื่องมือขนาดใหญ่</li><li>ช่องเสียบอุปกรณ์อื่นๆ</li></ul></li><li><strong>สะดวกในการใช้งาน:</strong> มาพร้อมเข็มขัดคาดเอว ปรับระดับความกระชับได้</li><li><strong>น้ำหนักเบา:</strong> ไม่ทำให้รู้สึกหนักขณะทำงาน</li></ul><p> </p><h5><strong>รายละเอียด</strong></h5><ul><li>เหมาะสำหรับใช้จัดเก็บอุปกรณ์เครื่องมือช่าง</li><li>เพื่อความเป็นระเบียบเรียบร้อย สะดวกในการหยิบจับขณะใช้งาน</li><li>แข็งแรงทนทาน เหมาะสำหรับลุยงานหนัก</li><li>ขนาดกระทัดรัด ไม่เกะกะขณะทำงาน</li></ul><h5> </h5><h5><strong>ข้อมูลเฉพาะสินค้า</strong></h5><ul><li>วัสดุ : หนังวัว</li><li>ขนาด : กว้าง 11.5 x สูง 26.5 ซม.</li></ul><h5> </h5><h5><strong>ข้อดีของการใช้กระเป๋าคาดเอว</strong></h5><ul><li>จัดระเบียบเครื่องมือได้อย่างเป็นระบบ หยิบใช้งานได้รวดเร็ว</li><li>แบกรับน้ำหนักได้ดีกว่ากระเป๋าสะพายข้าง ลดอาการปวดหลัง</li><li>เคลื่อนย้ายได้คล่องตัว เนื่องจากติดกับลำตัวโดยตรง</li><li>สะดวกต่อการขึ้น-ลงที่สูงแคบ เช่น การปีนบันได</li><li>สามารถเลือกรุ่นและความจุตามลักษณะงาน</li></ul><p>กระเป๋าเครื่องมือช่างคาดเอวจึงเป็นอุปกรณ์ที่ตอบโจทย์ทั้งด้านความปลอดภัย ความคล่องตัว และการจัดระเบียบสิ่งของ ทำให้ช่างทำงานได้อย่างมีประสิทธิภาพและลดความเหนื่อยล้า</p>', 'published', '[\"products\\/8-7.webp\",\"products\\/7-8.webp\",\"products\\/6-13.webp\",\"products\\/5-16.webp\",\"products\\/4-24.webp\",\"products\\/3-44.webp\",\"products\\/2-53.webp\",\"products\\/1-80.webp\"]', NULL, 'NN-2443-NER7G', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 450, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 711, '2025-03-12 20:56:57', '2025-05-13 10:08:33', 1, 'Botble\\ACL\\Models\\User', 'products/8-8.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(313, 'RUBYSHOP กระเป๋าเครื่องมือช่าง คาดเอว รุ่น RB-BG1413 พร้อมเข็มขัด กระเป๋าหนัง กระเป๋าคาดเอวช่าง', '<h5>กระเป๋าเครื่องมือช่างคาดเอว RUBYSHOP รุ่น RB-BG1413 เป็นอุปกรณ์ที่ออกแบบมาเพื่อความสะดวกและคล่องตัวในการพกพาเครื่องมือช่าง เหมาะสำหรับช่างมืออาชีพและผู้ใช้งานทั่วไป</h5><p> </p>', '<h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>วัสดุคุณภาพ:</strong> ทำจากหนังแท้ ทนทานต่อการใช้งาน</li><li><strong>ขนาดเหมาะสม:</strong> กว้าง 13 x สูง 17 ซม. ไม่ใหญ่หรือเล็กจนเกินไป เหมาะสำหรับการพกพาเครื่องมือที่จำเป็น</li><li><strong>ช่องเก็บของหลากหลาย:</strong><ul><li>2 ช่องใหญ่ สำหรับใส่เครื่องมือขนาดใหญ่</li><li>ช่องเสียบอุปกรณ์อื่นๆ</li></ul></li><li><strong>สะดวกในการใช้งาน:</strong> มาพร้อมเข็มขัดคาดเอว ทำให้สะดวกในการพกพาและใช้งาน</li><li><strong>น้ำหนักเบา:</strong> ไม่ทำให้รู้สึกหนักขณะทำงาน</li></ul><p> </p><h5><strong>รายละเอียด</strong></h5><ul><li>เหมาะสำหรับใช้จัดเก็บอุปกรณ์เครื่องมือช่าง</li><li>เพื่อความเป็นระเบียบเรียบร้อย สะดวกในการหยิบจับขณะใช้งาน</li><li>แข็งแรงทนทาน เหมาะสำหรับลุยงานหนัก</li><li>ขนาดกระทัดรัด ไม่เกะกะขณะทำงาน</li></ul><p> </p><h5><strong>ข้อมูลเฉพาะสินค้า</strong></h5><ul><li>วัสดุ : หนังวัว</li><li>ขนาด : กว้าง 13 x สูง 17 ซม.</li></ul><p> </p><h5><strong>ข้อดีของการใช้กระเป๋าคาดเอว</strong></h5><ul><li>จัดระเบียบเครื่องมือได้อย่างเป็นระบบ หยิบใช้งานได้รวดเร็ว</li><li>แบกรับน้ำหนักได้ดีกว่ากระเป๋าสะพายข้าง ลดอาการปวดหลัง</li><li>เคลื่อนย้ายได้คล่องตัว เนื่องจากติดกับลำตัวโดยตรง</li><li>สะดวกต่อการขึ้น-ลงที่สูงแคบ เช่น การปีนบันได</li><li>สามารถเลือกรุ่นและความจุตามลักษณะงาน</li></ul><p> </p><h6>กระเป๋าเครื่องมือช่างคาดเอวจึงเป็นอุปกรณ์ที่ตอบโจทย์ทั้งด้านความปลอดภัย ความคล่องตัว และการจัดระเบียบสิ่งของ ทำให้ช่างทำงานได้อย่างมีประสิทธิภาพและลดความเหนื่อยล้า</h6>', 'published', '[\"products\\/9-2.webp\",\"products\\/7-9.webp\",\"products\\/6-14.webp\",\"products\\/5-17.webp\",\"products\\/4-25.webp\",\"products\\/3-45.webp\",\"products\\/2-54.webp\",\"products\\/1-81.webp\"]', NULL, 'NN-2443-AUFB1', 0, 0, 0, NULL, 0, 0, 'in_stock', 