(352, 'RUBYSHOP เกรียงฉาบปูน เกรียงฉาบสกิมโค้ท รุ่น RB-5304 ขนาด 30x9.5x9 cm ด้ามไม้ | Plastering trowel', '<ul><li>วัสดุ ทำจากสแตนเลสคุณภาพสูง ทนทานต่อการใช้งาน</li><li>ขนาด 30 x 9.5 x 9 เซนติเมตร  ขนาดกำลังพอเหมาะ</li><li>ด้ามจับ ด้ามจับทำจากไม้ จับถนัดมือ ไม่ลื่น</li><li>การใช้งาน เหมาะสำหรับงานฉาบปูนทั่วไป งานฉาบสกิมโค้ท และงานปูนอื่นๆ </li></ul>', '<h5><strong>รายละเอียดสินค้า:</strong></h5><ul><li><strong>ทนทาน:</strong> ทำจากสแตนเลสคุณภาพดี ทนทานต่อการใช้งานหนัก ไม่บิดงอหรือเสียหายง่าย</li><li><strong>ใช้งานง่าย:</strong> ด้ามจับออกแบบมาให้จับถนัดมือ ช่วยให้ควบคุมการทำงานได้ง่ายและแม่นยำ</li><li><strong>อเนกประสงค์:</strong> เหมาะสำหรับงานฉาบปูนและสกิมโค้ทหลากหลายประเภท ใช้งานได้คุ้มค่า</li><li><strong>ขนาดเหมาะสม:</strong> ขนาด 30x9.5x9 ซม. เหมาะสำหรับงานฉาบพื้นที่ขนาดกลาง</li></ul><p> </p><h5><strong>ข้อดี:</strong></h5><ul><li><strong>ทนทาน:</strong> ทำจากสแตนเลสคุณภาพดี ทนทานต่อการใช้งาน</li><li><strong>ใช้งานง่าย:</strong> ด้ามจับถนัดมือ ควบคุมง่าย</li><li><strong>อเนกประสงค์:</strong> เหมาะสำหรับงานฉาบปูนและสกิมโค้ทหลากหลายประเภท</li><li><strong>ขนาดเหมาะสม:</strong> เหมาะสำหรับงานฉาบพื้นที่ขนาดกลาง</li><li><strong>คุ้มค่า:</strong> ราคาไม่แพง คุ้มค่าคุ้มราคา</li></ul><h5> </h5><h5><strong>ข้อเสีย:</strong></h5><ul><li><strong>ต้องดูแลรักษา:</strong> ควรทำความสะอาดหลังการใช้งานเพื่อยืดอายุการใช้งาน</li></ul><h5> </h5><h5><strong>คำแนะนำ:</strong></h5><ul><li>หลังใช้งาน ควรทำความสะอาดเกรียงให้สะอาด เพื่อป้องกันการสะสมของปูนและสิ่งสกปรก</li><li>ควรเก็บรักษาในที่แห้ง เพื่อป้องกันการเกิดสนิมและยืดอายุการใช้งาน</li></ul>', 'published', '[\"products\\/w5-1.webp\",\"products\\/tz.webp\",\"products\\/g2.webp\",\"products\\/ej-4.webp\",\"products\\/31.webp\",\"products\\/8h.webp\",\"products\\/6w-1.webp\"]', NULL, 'NN-2443-Y6NNE', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 390, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 832, '2025-03-12 21:00:25', '2025-05-05 10:47:46', 1, 'Botble\\ACL\\Models\\User', 'products/w5-2.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(353, 'RUBY SHOP รอกยกแอร์ รอกยกคอยล์ร้อนแอร์ ขนาด 20 เมตร รับน้ำหนักได้ถึง 300 โล', '<ul><li>ปรับความสูงได้ 4 ระดับ: 100 ซม., 112 ซม., 124 ซม., และ 136 ซม.</li><li>ประหยัดแรงและเวลา: เปลี่ยนคอมเพรสเซอร์แอร์ได้ง่ายและรวดเร็ว</li><li>ปลอดภัย: ผลิตจากเหล็กหล่อ แข็งแรง ทนทาน พร้อมตัวล็อค 2 ทางเพื่อความปลอดภัยสูงสุด</li><li>รับน้ำหนักได้มาก: สลิงขนาด 5 มม. ยาว 15 ม. รับน้ำหนักได้ถึง 300 กก.</li><li>โครงสร้างมั่นคง: โครงสร้างสามเหลี่ยมช่วยรองรับน้ำหนักได้ดีเยี่ยม</li><li>ทนทานต่อการสึกหรอ: เฟืองเหล็กผสมโลหะภายในแข็งแรงทนทาน</li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><h6>รอกยกแอร์เป็นอุปกรณ์ที่ออกแบบมาเพื่อช่วยในการขนย้ายและติดตั้งเครื่องปรับอากาศได้อย่างปลอดภัยและมีประสิทธิภาพ ช่วยลดภาระงานหนัก และเพิ่มความปลอดภัยในการทำงาน</h6><ul><li>โครงสร้างแข็งแรงทำจากเหล็กกล่อง</li><li>รับน้ำหนักได้สูงสุด 300 กก.</li><li>สลิงยาว 20 เมตร</li></ul><h5> </h5><h5><strong>ขั้นตอนการใช้งาน</strong></h5><ol><li><strong>ตรวจสอบอุปกรณ์:</strong> ตรวจสอบความสมบูรณ์ของรอกและอุปกรณ์ทุกชิ้นก่อนใช้งาน</li><li><strong>วางแผนการใช้งาน:</strong> วางแผนเส้นทางการเคลื่อนย้ายและกำหนดจุดติดตั้ง</li><li><strong>เตรียมการติดตั้ง:</strong> ยกแอร์ในตำแหน่งที่เหมาะสมและตรวจสอบจุดยึด</li><li><strong>เริ่มการยก:</strong> ใช้มือหมุนหรือระบบควบคุมในการยกแอร์ขึ้นลงในแนวดิ่งเท่านั้น</li><li><strong>ติดตั้งแอร์:</strong> ปรับระดับและติดตั้งแอร์ให้แน่นหนาและปลอดภัย</li><li><strong>เสร็จสิ้นการทำงาน:</strong> ลดระดับแอร์ลงอย่างระมัดระวังและทำความสะอาดพื้นที่</li></ol><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li>สวมใส่อุปกรณ์ป้องกัน เช่น หมวกกันน็อคและถุงมือ</li><li>อย่าให้ผู้อื่นอยู่ใกล้บริเวณที่ทำงานขณะยกแอร์</li><li>อย่าให้น้ำหนักเกินกว่าที่รอกรับได้</li><li>ใช้เทคนิคการยกที่ถูกต้องเพื่อป้องกันการบาดเจ็บ</li></ul><h5> </h5><h5><strong>⚠️ โปรดอ่าน ⚠️</strong></h5><ul><li>เมื่อได้รับสินค้าแล้ว กรุณาถ่ายวิดีโอขณะแกะสินค้าเพื่อเป็นหลักฐาน หากสินค้ามีตำหนิ ใช้งานไม่ได้ หรืออุปกรณ์ไม่ครบ ต้องแจ้งภายใน 3 วันนับจากวันที่รับสินค้า</li><li>หากไม่มีวิดีโอขณะแกะสินค้า ทางร้านขอสงวนสิทธิ์ในการเปลี่ยนหรือคืนสินค้า</li></ul>', 'published', '[\"products\\/vq.webp\",\"products\\/qm.webp\",\"products\\/hs.webp\",\"products\\/fz.webp\",\"products\\/f4.webp\"]', NULL, 'NN-2443-H3BHM', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 2700, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 758, '2025-03-12 21:00:57', '2025-05-05 10:22:33', 1, 'Botble\\ACL\\Models\\User', 'products/vq-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(355, 'RUBYSHOP เครื่องฉาบฝ้า,เครื่องฉาบยิปซั่ม รุ่น RB-DP01 วัสดุเกรดพรีเมี่ยม อย่างดี', '<ul><li>วัสดุพรีเมี่ยม: ทนทาน ใช้งานได้ยาวนาน</li><li>กล่องใส่ยิปซั่มขนาดใหญ่: 9 นิ้ว ทำงานต่อเนื่อง ไม่ต้องเติมบ่อย</li><li>ด้ามจับปรับยืดหดได้: 102-162 ซม. เข้าถึงพื้นที่สูงและยากได้ง่าย</li><li>ปรับมุมได้: 90 องศา ใช้งานได้หลากหลาย</li><li>ใช้ได้ทั้งผนังและฝ้า: อเนกประสงค์</li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><h6>เครื่องฉาบฝ้าสีทองช่วยปิดรอยต่อผนังฝ้าและเพดานได้อย่างเรียบเนียน ด้ามจับเป็นยาง จับถนัดมือ ใช้งานง่าย</h6><h5> </h5><h5><strong>ข้อมูลทางเทคนิค</strong></h5><ul><li>กล่องใส่ปูนสำเร็จความจุขนาดใหญ่</li><li>ด้ามจับแบบยืดหดได้</li><li>แผ่นกดสปริงแม่นยำ ควบคุมปริมาณปูนได้เที่ยงตรง</li><li>ช่วยประหยัดเวลาและแรงงาน</li><li>ให้ผลงานที่เรียบเนียนสม่ำเสมอ</li></ul><h2> </h2><h5><strong>ประโยชน์การใช้งาน</strong></h5><ul><li>ใช้ฉาบปิดรอยต่อระหว่างแผ่นฝ้าเพดาน</li><li>ช่วยฉาบผิวเพดานให้เรียบเนียน</li><li>ใช้ซ่อมแซมรอยแตกบนเพดานได้</li></ul><h2> </h2><h5><strong>วิธีการใช้งาน</strong></h5><ol><li>เตรียมวัสดุฉาบให้มีความข้นที่เหมาะสม</li><li>บรรจุวัสดุฉาบในถังของเครื่อง</li><li>ปรับตั้งค่าความเร็วและปริมาณการฉีด</li><li>เคลื่อนหัวฉีดไปตามแนวรอยต่อหรือพื้นที่ที่ต้องการฉาบ</li><li>ใช้เกรียงปาดแต่งให้เรียบหลังจากฉีดวัสดุ</li></ol><h2> </h2><h5><strong>ข้อดีของการใช้เครื่อง</strong></h5><ul><li>ทำงานได้เร็วกว่าการฉาบด้วยมือ</li><li>ให้ความสม่ำเสมอในการฉาบ ลดการเกิดรอยต่อ</li><li>ลดความเมื่อยล้าของผู้ปฏิบัติงาน โดยเฉพาะงานเพดานสูง</li></ul><h5> </h5><h5><strong>การบำรุงรักษา</strong></h5><ul><li>ทำความสะอาดทุกครั้งหลังใช้งาน</li><li>ตรวจสอบและทำความสะอาดถังบรรจุวัสดุเป็นประจำ</li><li>หล่อลื่นชิ้นส่วนที่เคลื่อนไหว</li></ul>', 'published', '[\"products\\/az.webp\",\"products\\/po.webp\",\"products\\/8d.webp\",\"products\\/jw.webp\",\"products\\/s4-1.webp\"]', NULL, 'NN-2443-1ENTZ', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 3290, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 794, '2025-03-12 21:01:12', '2025-05-06 11:01:21', 1, 'Botble\\ACL\\Models\\User', 'products/az-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(356, 'RUBYSHOP เครื่องฉาบฝ้าเทปยิปซั่ม เครื่องเดินผ้าเทปยิปซั่ม เทปยิปซั่ม ปิดรอยต่อ', '<ul><li><h5>ใช้งานง่าย: น้ำหนักเบา ไม่ยุ่งยากซับซ้อน</h5></li><li><h5>ทนทาน: ผลิตจากพลาสติก ABS คุณภาพสูง ใช้งานได้ยาวนาน</h5></li><li><h5>รวดเร็ว: ตัวยิปซั่มออกมาพร้อมผ้าเทป ช่วยให้ทำงานได้รวดเร็วขึ้น</h5></li><li><h5>ปรับปริมาณได้: ปรับลดปริมาณยิปซั่มได้ 4 ระดับ</h5><h5> </h5></li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><h6>RUBYSHOP เครื่องฉาบฝ้าเทปยิปซั่ม เครื่องเดินผ้าเทปยิปซั่ม เทปยิปซั่ม ปิดรอยต่อ สำหรับปิดรอยต่อของฝ้าและแผ่นยิปซั่ม ช่วยให้งานฝ้าของคุณเรียบเนียนสวยงามได้อย่างรวดเร็วและง่ายดาย</h6><h6> </h6><h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>วัสดุ</strong>: พลาสติก ABS คุณภาพสูง ทนทานต่อการใช้งาน</li><li><strong>การใช้งาน</strong>: ใช้งานง่าย น้ำหนักเบา ไม่ยุ่งยากซับซ้อน เหมาะสำหรับทั้งมืออาชีพและผู้ใช้งานทั่วไป</li><li><strong>ความรวดเร็ว</strong>: ตัวยิปซั่มจะออกมาพร้อมกับผ้าเทป ช่วยให้การทำงานรวดเร็วและมีประสิทธิภาพยิ่งขึ้น</li><li><strong>การปรับปริมาณ</strong>: สามารถปรับลดปริมาณของยิปซั่มได้ถึง 4 ระดับ ช่วยให้ควบคุมปริมาณการใช้งานได้อย่างเหมาะสม</li><li><strong>การเข้ามุม</strong>: ออกแบบมาเป็นพิเศษให้สามารถใช้งานกับรอยต่อแบบเข้ามุมได้อย่างง่ายดาย</li><li><strong>ผ้าเทป</strong>: ใช้กับผ้าเทปกระดาษขนาดมาตรฐาน หน้ากว้าง 2 นิ้ว (5 ซม.) สามารถใช้ได้ยาว 150 เมตร ช่วยประหยัดค่าใช้จ่าย</li></ul><h5> </h5><h5> </h5><h5><strong>วิธีการใช้งาน</strong></h5><ol><li>เตรียมผ้าเทปยิปซั่มให้พร้อมใช้งาน</li><li>ใส่ผ้าเทปเข้าไปในเครื่องฉาบ</li><li>เติมยิปซั่มลงในช่องใส่</li><li>ปรับปริมาณยิปซั่มให้อยู่ในระดับที่ต้องการ</li><li>นำเครื่องฉาบไปทาบบนรอยต่อของฝ้าหรือแผ่นยิปซั่ม โดยให้ผ้าเทปและยิปซั่มสัมผัสกับพื้นผิว</li><li>กดเครื่องฉาบเบาๆ แล้วลากไปตามแนวรอยต่อ</li></ol><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรทำความสะอาดเครื่องฉาบหลังการใช้งานทุกครั้ง เพื่อยืดอายุการใช้งาน</li></ul>', 'published', '[\"products\\/ul.webp\",\"products\\/u4.webp\",\"products\\/nd.webp\",\"products\\/kl.webp\",\"products\\/d9-3.webp\",\"products\\/6r.webp\",\"products\\/6e.webp\"]', NULL, 'NN-2443-ACY23', 0, 0, 0, 145, 0, 0, 'in_stock', 0, NULL, 0, 0, 890, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 818, '2025-03-12 21:01:14', '2025-09-08 03:09:45', 1, 'Botble\\ACL\\Models\\User', 'products/ul-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(357, 'RUBYSHOP เครื่องขัดพื้นผิว คอนกรีต floor sander cement polishing machine รุ่น RB-FP01', '<ul><li>เหมาะสำหรับขัดปรับสภาพพื้นผิวคอนกรีตเก่าให้พร้อมใช้งาน</li><li>มีล้อขนาดใหญ่ 2 ล้อ เคลื่อนย้ายได้ง่าย</li><li>เครื่องดูดฝุ่นแรงถึง 0.75 KW ลดปัญหาฝุ่นฟุ้งกระจาย</li><li>มอเตอร์กำลังสูง ขัดพื้นผิวได้อย่างมีประสิทธิภาพ</li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><h6>RUBYSHOP เครื่องขัดพื้นผิวคอนกรีต รุ่น RB-FP01 เหมาะสำหรับงานขัดปรับสภาพพื้นผิวคอนกรีต ทั้งภายในและภายนอกอาคาร เช่น ผนังคอนกรีต พื้นทางเดิน หรือพื้นอุตสาหกรรม สามารถใช้กับใบขัดที่แตกต่างกัน ขึ้นอยู่กับสภาพของพื้นผิวก่อนการขัด</h6><h2> </h2><h5><strong>คุณสมบัติเด่น</strong></h5><ul><li>เหมาะสำหรับขัดปรับสภาพพื้นผิวเก่า</li><li>มีล้อขนาดใหญ่ 2 ล้อ เคลื่อนย้ายสะดวก</li><li>เครื่องดูดฝุ่นดูดฝุ่นได้แรงถึง 0.75 KW</li><li>มอเตอร์ทรงพลัง</li><li>แผ่นขัดเจียร์ เส้นผ่านศูนย์กลาง 0.3 ซม.</li><li>สวิตช์ป้องกันไฟรั่ว</li><li>มีถังเก็บฝุ่นภายในตัว</li></ul><h2> </h2><h5><strong>ข้อมูลทางเทคนิค</strong></h5><ul><li>แรงดันไฟฟ้า: 220 โวลต์</li><li>กำลังมอเตอร์: 3000 วัตต์</li><li>ขนาดหน้ากว้าง: 38 ซม.</li><li>ความลึกในการขูด: 1-3 มม.</li><li>ถังเก็บฝุ่น: 24 ลิตร</li></ul><h2> </h2><h5><strong>วิธีการใช้งาน</strong></h5><ol><li><strong>เตรียมพื้นที่:</strong> ทำความสะอาดพื้นให้ปราศจากฝุ่นและสิ่งสกปรก ปกคลุมหรือเคลื่อนย้ายสิ่งของใกล้เคียงออกจากพื้นที่</li><li><strong>เตรียมเครื่องมือ:</strong> ตรวจสอบเครื่องขัดให้อยู่ในสภาพดี ติดตั้งแผ่นขัดที่เหมาะสมกับพื้นผิวคอนกรีต</li><li><strong>ขัดพื้น:</strong> เปิดเครื่องและปรับความเร็วให้เหมาะสม เริ่มขัดจากมุมหนึ่งของพื้นที่ โดยให้เครื่องอยู่ในแนวตรงและเดินช้าๆ ทำซ้ำในจุดที่ยังไม่เรียบ</li><li><strong>ตรวจสอบและทำความสะอาด:</strong> ตรวจสอบพื้นว่าเรียบและเงาเพียงพอหรือไม่ ทำความสะอาดฝุ่นและเศษขัด</li><li><strong>บำรุงรักษาเครื่อง:</strong> ทำความสะอาดเครื่องและแผ่นขัดหลังใช้งาน เก็บเครื่องในที่แห้ง</li></ol><h2> </h2><h5><strong>ข้อควรระวัง</strong></h5><ul><li>สวมใส่อุปกรณ์ป้องกัน เช่น หน้ากาก, แว่นตา และรองเท้าที่ปลอดภัยขณะทำงาน</li><li>อ่านและศึกษาคู่มือการใช้งานของเครื่องแต่ละรุ่นให้เข้าใจอย่างละเอียด</li></ul>', 'published', '[\"products\\/bb.webp\",\"products\\/n8.webp\",\"products\\/er.webp\",\"products\\/0y.webp\",\"products\\/r0.webp\",\"products\\/es.webp\"]', NULL, 'NN-2443-DK17E', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 45000, 39000, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 834, '2025-03-12 21:01:20', '2025-05-13 04:21:46', 1, 'Botble\\ACL\\Models\\User', 'products/bb-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(358, 'RUBYSHOP เครื่องดูดสั่นกระเบื้องไร้สาย รุ่น RB-TT21V: ปูกระเบื้องง่าย เนียนกริ๊บ รวดเร็วทันใจ', '<ul><li>ไร้สาย ใช้งานสะดวก: ไม่ต้องกังวลเรื่องสายไฟ</li><li>แรงดูดสูง: ยึดติดกระเบื้องแน่น ไม่หล่น รองรับน้ำหนักได้ถึง 100 กก.</li><li>ระบบสั่นอัจฉริยะ: ปรับความถี่ได้ 5 ระดับ เหมาะกับกระเบื้องทุกขนาด</li><li>ปูเรียบเนียน: ช่วยให้กระเบื้องติดแน่น ไม่สะดุด</li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><h6>เครื่องดูดสั่นกระเบื้องไร้สาย RUBY SHOP รุ่น RB-TT21V ช่วยให้การปูกระเบื้องเป็นเรื่องง่ายและรวดเร็ว ด้วยระบบดูดและสั่นอัจฉริยะ ปรับความถี่ได้ 5 ระดับ รองรับน้ำหนักได้ถึง 100 กก. เหมาะสำหรับกระเบื้องปูผนังและพื้นขนาดเล็ก-ใหญ่ (60x60 ซม., 80x80 ซม., 100x100 ซม. และ 120x120 ซม. ที่มีความหนาไม่เกิน 20 มม.)</h6><h6> </h6><h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>วัสดุคุณภาพ</strong>: แข็งแรงทนทาน</li><li><strong>ระบบไร้สาย</strong>: ใช้งานสะดวก</li><li><strong>ระบบดูดและสั่น</strong>: ปูกระเบื้องง่ายและรวดเร็ว</li><li><strong>ปรับความเร็วได้</strong>: 5 ระดับ</li><li><strong>แรงดูดสูง</strong>: รองรับน้ำหนักได้ 100 กก.</li><li><strong>ใช้งานได้หลากหลาย</strong>: แนวตั้งและแนวนอน</li><li><strong>แบตเตอรี่ 21V</strong>: ใช้งานต่อเนื่อง</li></ul><h2> </h2><h5><strong>ข้อมูลทางเทคนิค</strong></h5><ul><li>แรงดันไฟฟ้า: 21 โวลต์</li><li>ความถี่ในการสั่น: 12000 rmp</li><li>แรงดูด: 100 กก.</li><li>ปรับความเร็ว: 5 ระดับ</li><li>หน้ากว้างตัวดูด: 130 มม.</li></ul><h5> </h5><h5><strong>อุปกรณ์ภายในชุด</strong></h5><ul><li>เครื่องดูดสั่นกระเบื้องไร้สาย</li><li>แบตเตอรี่ 21V 1 ก้อน</li><li>สายชาร์จแบตเตอรี่</li><li>กล่องเก็บอุปกรณ์ BMC</li></ul><h5> </h5><h5><strong>วิธีการใช้งาน</strong></h5><ol><li>ปูกระเบื้องบนพื้นผิวที่ต้องการ โดยเว้นช่องว่างสำหรับร่องยาแนว</li><li>วางแผ่นรองรับบนกระเบื้อง แล้ววางเครื่องสั่นทับบนแผ่นรองรับ</li><li>เปิดสวิตช์ให้เครื่องสั่นสะเทือน ทำซ้ำจนกระเบื้องเรียบ</li><li>ปล่อยให้กระเบื้องแห้งสนิทก่อนอุดร่องยาแนว</li></ol><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li></ul><h5> </h5><h5><strong>การรับประกัน</strong></h5><ul><li>รับประกันมอเตอร์ 1 ปี (ไม่รวมอะไหล่)</li></ul>', 'published', '[\"products\\/4x.webp\",\"products\\/4j.webp\",\"products\\/mu.webp\",\"products\\/zf.webp\"]', NULL, 'NN-2443-DN9LW', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 3500, 2500, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 741, '2025-03-12 21:01:30', '2025-05-06 10:58:30', 1, 'Botble\\ACL\\Models\\User', 'products/4x-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(359, 'RUBYSHOP เครื่องดัดเหล็ก รุ่น RB25 1600 วัตต์ Rebar bending Machine', '<ul><li>ดัดได้สูงสุด 180 องศา: ดัดเหล็กเส้นและเหล็กข้ออ้อยได้หลากหลายมุม</li><li>ใช้งานง่าย: เหมาะสำหรับทั้งมืออาชีพและผู้ใช้งานทั่วไป</li><li>ทนทาน: ผลิตจากวัสดุคุณภาพสูง ใช้งานได้ยาวนาน</li><li>ปลอดภัย: มีปุ่มหยุดฉุกเฉิน ป้องกันอันตราย</li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><h6>RUBYSHOP เครื่องดัดเหล็ก รุ่น RB25 1600 วัตต์ Rebar bending Machine ใช้สำหรับงานดัดเหล็กเส้นและเหล็กข้ออ้อยในงานอุตสาหกรรมและก่อสร้าง ดัดได้สูงสุด 180 องศา มีระบบหยุดฉุกเฉินเพื่อความปลอดภัย ใช้งานง่ายและสะดวก</h6><h6> </h6><h5><strong>คุณสมบัติ</strong></h5><ul><li>ดัดเหล็กเส้นขนาด 6-25 มม.</li><li>ดัดเหล็กข้ออ้อยขนาด 6-20 มม.</li><li>กำลังไฟ 1600 วัตต์ ใช้งานกับไฟบ้าน 220V</li><li>ปุ่มหมุนปรับระดับองศา 0-180 องศา</li><li>มีด้ามจับ 4 มุม เคลื่อนย้ายสะดวก</li></ul><h2> </h2><h5><strong>ข้อมูลทางเทคนิค</strong></h5><ul><li>กำลังไฟ: 1600 วัตต์</li><li>กระแสไฟ: 220V (Single Phase)</li><li>ความเร็วในการดัด: 5 วินาที</li><li>ความสามารถในการดัดเหล็ก: 6-25 มม.</li><li>น้ำหนัก: 91 กก.</li><li>ขนาดสินค้า: 45x50x44 ซม.</li></ul><h2> </h2><h5><strong>วิธีใช้งาน</strong></h5><ul><li>ใช้สำหรับดัดเหล็กข้ออ้อยและเหล็กเส้น</li><li>หลังใช้งาน ทำความสะอาดและเช็ดด้วยน้ำมันเพื่อป้องกันสนิม</li></ul><h2> </h2><h5><strong>การรับประกัน</strong></h5><ul><li>รับประกันซ่อมฟรี 1 ปี (ไม่รวมอะไหล่)</li></ul>[media url=https://www.youtube.com/watch?v=OSYNgglmpTY][/media]', 'published', '[\"products\\/d3.webp\"]', NULL, 'NN-2443-AI5U5', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 39990, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 783, '2025-03-12 21:01:33', '2025-05-06 10:57:24', 1, 'Botble\\ACL\\Models\\User', 'products/d3-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(361, 'RUBYSHOP เครื่องดัดเหล็ก รุ่น RB-32: งานเหล็กง่าย จบไว แรงดันสูง', '<ul><li>มอเตอร์ทรงพลัง: 3000 วัตต์ ดัดเหล็กได้รวดเร็วและมีประสิทธิภาพ</li><li>ใช้กับไฟบ้าน: 220 โวลต์ ใช้งานสะดวก</li><li>ดัดเหล็กได้หลากหลาย:เหล็กเส้น: 6-32 มม., เหล็กข้ออ้อย: 6-28 มม.</li><li>ปรับองศาได้: 0-180 องศา ดัดเหล็กได้ตามต้องการ</li><li>รวดเร็ว: ดัดเหล็กได้ใน 6 วินาที</li><li>ทนทาน: เหมาะสำหรับงานหนักและต่อเนื่อง</li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><h6>RUBYSHOP เครื่องดัดเหล็ก รุ่น RB-32 เป็นเครื่องดัดเหล็กคุณภาพสูงที่ออกแบบมาเพื่อตอบสนองความต้องการของงานก่อสร้างและงานเหล็กต่างๆ ด้วยมอเตอร์ทรงพลังและความสามารถในการดัดเหล็กที่หลากหลาย ทำให้เป็นเครื่องมือที่คุ้มค่าและมีประสิทธิภาพ</h6><h5> </h5><h5><strong>คุณสมบัติเด่น</strong></h5><ul><li>กำลังมอเตอร์: 3000 วัตต์</li><li>กระแสไฟ: 220 โวลต์</li><li>ดัดเหล็กเส้น: 6-32 มม.</li><li>ดัดเหล็กข้ออ้อย: 6-28 มม.</li><li>องศาในการดัด: 0-180 องศา</li><li>ความเร็วในการดัด: 6 วินาที</li></ul><h5> </h5><h5><strong>เหมาะสำหรับ</strong></h5><ul><li>โครงการก่อสร้างที่ต้องการดัดเหล็กขนาดใหญ่และหนา</li><li>งานเสริมแรงในโครงสร้างคอนกรีต</li><li>งานเสริมเหล็กในโครงการก่อสร้างที่ซับซ้อน</li></ul><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรสวมใส่อุปกรณ์ป้องกันความปลอดภัยที่เหมาะสมขณะใช้งาน</li></ul>[media url=https://youtu.be/OSYNgglmpTY][/media]', 'published', '[\"products\\/ge.webp\"]', NULL, 'NN-2443-JB20F', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 59900, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 835, '2025-03-12 21:02:54', '2025-04-17 05:48:10', 1, 'Botble\\ACL\\Models\\User', 'products/ge-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(362, 'RUBY SHOP เครื่องกรีดผนัง เซาะร่อง Wall Cutter 2500 วัตต์ รุ่น WALLCD-100A กรีดผนังอิฐมวลเบาเฉพาะ', '<ul><li><h5>เครื่องกรีดผนัง เซาะร่อง เป็นเครื่องมือช่างที่ออกแบบมาเพื่อการเซาะร่องบนผนังอิฐมวลเบาโดยเฉพาะ </h5></li><li><h5>กำลังมอเตอร์ 2500 วัตต์ ทำให้สามารถทำงานได้อย่างมีประสิทธิภาพ ทนทาน และแม่นยำ </h5></li><li><h5>เหมาะสำหรับช่างมืออาชีพและผู้ใช้งานทั่วไปที่ต้องการเครื่องกรีดผนังคุณภาพสูง</h5></li></ul>', '<h5><strong>คุณสมบัติเด่น</strong></h5><ul><li><strong>มอเตอร์ทรงพลัง</strong>: มอเตอร์ขนาด 2500 วัตต์ ให้กำลังสูงในการตัด ช่วยให้การทำงานเป็นไปอย่างราบรื่นและรวดเร็ว</li><li><strong>ออกแบบเฉพาะสำหรับอิฐมวลเบา</strong>: เหมาะสำหรับการใช้งานกับผนังอิฐมวลเบาโดยเฉพาะ ทำให้การตัดเป็นไปอย่างแม่นยำและไม่ทำให้ผนังเสียหาย</li><li><strong>ความทนทานสูง</strong>: ผลิตจากวัสดุคุณภาพดี ทนทานต่อการใช้งานหนักและยาวนาน</li><li><strong>ใช้งานง่าย</strong>: ออกแบบมาให้ใช้งานง่าย ไม่ซับซ้อน เหมาะสำหรับทั้งช่างมืออาชีพและผู้ใช้งานทั่วไป</li><li><strong>ประสิทธิภาพสูง</strong>: สามารถเซาะร่องบนผนังได้อย่างรวดเร็วและแม่นยำ ช่วยประหยัดเวลาและแรงงาน</li></ul><h5> </h5><h5><strong>ข้อมูลทางเทคนิค</strong></h5><ul><li><strong>กำลังไฟฟ้า:</strong> 2500 วัตต์</li><li><strong>แรงดันไฟฟ้า:</strong> 220V/50Hz</li><li><strong>ความเร็วรอบ:</strong> 2200 รอบ/นาที</li><li><strong>ขนาดใบตัด:</strong> 25 มม.</li><li><strong>ความลึกในการตัดสูงสุด:</strong> 30 มม.</li><li><strong>ความกว้างในการตัดสูงสุด:</strong> 25 มม.</li><li><strong>น้ำหนัก:</strong> (ข้อมูลจำเพาะเพิ่มเติม)</li></ul><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li><strong>ใช้งานกับอิฐมวลเบาเท่านั้น:</strong> เครื่องกรีดผนังรุ่นนี้ออกแบบมาสำหรับใช้งานกับผนังอิฐมวลเบาเท่านั้น ห้ามใช้กับวัสดุอื่นๆ</li><li><strong>สวมใส่อุปกรณ์ป้องกัน:</strong> ควรสวมใส่อุปกรณ์ป้องกันความปลอดภัย เช่น แว่นตาป้องกันฝุ่นละอองและหน้ากากกันฝุ่น ขณะใช้งาน</li><li><strong>ตรวจสอบสภาพเครื่อง:</strong> ตรวจสอบสภาพเครื่องก่อนใช้งานทุกครั้ง หากพบความผิดปกติ ควรหยุดใช้งานทันที</li></ul>[media url=https://www.youtube.com/watch?v=GBhk2WZilv8][/media]<p> </p>', 'published', '[\"products\\/wall-cutter-2500-wallcd-100a-19.webp\",\"products\\/wall-cutter-2500-wallcd-100a-5.webp\",\"products\\/wall-cutter-2500-wallcd-100a-6.webp\",\"products\\/wall-cutter-2500-wallcd-100a-7.webp\",\"products\\/wall-cutter-2500-wallcd-100a-18.webp\",\"products\\/wall-cutter-2500-wallcd-100a-10.webp\",\"products\\/100a\\/100a-wallchaser.png\"]', NULL, 'NN-2443-UH19K-gO2PS', 0, 0, 0, NULL, 0, 0, 'in_stock', 1, NULL, 0, 0, 25000, 17000, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1120, '2025-03-12 21:02:59', '2025-05-08 02:50:41', 1, 'Botble\\ACL\\Models\\User', 'products/100a/100a-wallchaser.png', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(363, 'RUBYSHOP เครื่องพ่นสีแรงดันสูง รุ่น RB999s พ่นสีอุตสาหกรรม จบงานไว แรงดันสูง', '<ul><li>พ่นสีได้รวดเร็ว: 8.2 ลิตร/นาที เหมาะสำหรับงานขนาดใหญ่</li><li>มอเตอร์ทรงพลัง: 3000W ให้แรงดันสูงถึง 3625Psi พ่นสีได้หนาและสม่ำเสมอ</li><li>รองรับหัวทิปใหญ่: สูงสุด 0.035 พ่นสีได้หลากหลายรูปแบบ</li><li>ดูดสีหนืดได้: สามารถใช้กับสีที่มีความหนืดสูง เช่น สกิมโค้ท</li><li>ทนทาน: เหมาะสำหรับงานหนักและต่อเนื่อง</li></ul>', '<h5><strong>รายละเอียดสินค้า</strong></h5><h6>RUBYSHOP เครื่องพ่นสีแรงดันสูง รุ่น RB999s เป็นเครื่องพ่นสีอุตสาหกรรมที่ออกแบบมาเพื่อตอบสนองความต้องการของงานพ่นสีขนาดใหญ่ ด้วยประสิทธิภาพที่สูงและทนทาน ทำให้เป็นตัวเลือกที่คุ้มค่าสำหรับผู้ใช้งาน</h6><h2> </h2><h5><strong>คุณสมบัติเด่น</strong></h5><ul><li>พ่นสีได้รวดเร็ว 8.2 ลิตร/นาที</li><li>มอเตอร์ 3000W</li><li>แรงดันไฟฟ้า 220V</li><li>แรงดันสูงสุด 3625Psi</li><li>รองรับหัวทิปใหญ่ถึง 0.035</li><li>สามารถดูดสกิมโค้ทที่มีความหนืดสูงได้</li></ul><h2> </h2><h5><strong>ประโยชน์ของการใช้เครื่องพ่นสีกันไฟ</strong></h5><ul><li>เพิ่มระดับความปลอดภัยในสภาพแวดล้อมที่มีความร้อนสูง</li><li>ช่วยป้องกันความเสียหายต่ออุปกรณ์และโครงสร้าง</li><li>ยืดอายุการใช้งานของวัสดุและอุปกรณ์</li><li>ลดค่าใช้จ่ายในการซ่อมแซมและเปลี่ยนอุปกรณ์ใหม่</li></ul><h2> </h2><h5><strong>การใช้งานในอุตสาหกรรมต่างๆ</strong></h5><ul><li>อุตสาหกรรมปิโตรเคมี</li><li>โรงงานผลิตเหล็กและโลหะ</li><li>โรงไฟฟ้าและโรงงานพลังงาน</li><li>การก่อสร้างอาคารและสิ่งปลูกสร้าง</li><li>ยานพาหนะและอากาศยาน</li></ul><h5> </h5><h5><strong>ข้อมูลเฉพาะ</strong></h5><h6>เครื่องพ่นสีกันไฟนับเป็นอุปกรณ์จำเป็นสำหรับอุตสาหกรรมที่เกี่ยวข้องกับสภาพแวดล้อมที่มีความร้อนสูง คุณสมบัติและประโยชน์ของมันช่วยเพิ่มความปลอดภัย ลดความเสี่ยง และยืดอายุการใช้งานของอุปกรณ์และโครงสร้างต่างๆ</h6>[media url=https://www.youtube.com/watch?v=JNLf01iaydk][/media]', 'published', '[\"products\\/999s-1-720x720.webp\",\"products\\/rubyshop-rb999s.webp\",\"products\\/rubyshop-rb999s-4.webp\",\"products\\/rubyshop-rb999s-3.webp\",\"products\\/rubyshop-rb999s-2.webp\"]', NULL, 'NN-2443-RXCHV-IihGh', 0, 0, 0, NULL, 0, 0, 'in_stock', 1, NULL, 0, 0, 89000, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1078, '2025-03-12 21:03:05', '2025-05-06 08:40:21', 1, 'Botble\\ACL\\Models\\User', 'products/999s-1-720x720-1.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(365, 'เครื่องพ่นสกิมโค้ท ระบบสกรูปั้ม skimcoat-rb-hp30', '<p>เครื่องพ่นสกิมโค้ทขนาดเล็กกะทัดรัด ระบบสกรูปั๊ม ที่ช่วยให้การพ่นสกิมโค้ทรวดเร็วและสม่ำเสมอ</p>', '<p>เหมาะสำหรับงานตกแต่งผนังและเพดาน ใช้งานง่าย ลดระยะเวลาในการทำงาน มาพร้อมคุณสมบัติเด่นดังนี้:</p><p>✅ <strong>ระบบสกรูปั๊มคุณภาพสูง</strong> – ช่วยให้เนื้อสกิมโค้ทไหลสม่ำเสมอ พ่นได้เรียบเนียน ลดปัญหาการอุดตัน<br>✅ <strong>ถังบรรจุขนาด 82 ลิตร</strong> – รองรับปริมาณสกิมโค้ทได้มาก ลดความถี่ในการเติมวัสดุ<br>✅ <strong>ปรับระดับแรงดันได้</strong> – ควบคุมแรงดันให้เหมาะสมกับการใช้งานแต่ละประเภท<br>✅ <strong>เหมาะสำหรับงานรีโนเวทและก่อสร้าง</strong> – ใช้งานได้ทั้งภายในและภายนอกอาคาร<br>✅ <strong>ขนาดกะทัดรัด เคลื่อนย้ายสะดวก</strong> – มีล้อช่วยให้เคลื่อนที่ง่าย เพิ่มความสะดวกในการทำงาน</p><p>เครื่องพ่นสกิมโค้ทรุ่นนี้เหมาะสำหรับช่างมืออาชีพที่ต้องการความสะดวก รวดเร็ว และคุณภาพงานที่สวยงาม</p>', 'draft', '[\"products\\/hp30\\/rbhp-30.jpg\",\"products\\/hp30\\/dsc06734.JPG\",\"products\\/hp30\\/hp30x.png\",\"products\\/hp30\\/dsc06733.JPG\"]', NULL, 'WW-2443-U8EW4', 0, 0, 0, 0, 0, 0, 'in_stock', 0, NULL, 0, 0, 85000, NULL, NULL, NULL, 0, 0, 0, 0, NULL, 61, '2025-03-27 07:54:16', '2025-05-07 09:36:47', 1, 'Botble\\ACL\\Models\\User', 'products/hp30/rb-hp30-01-medium.jpg', 'physical', NULL, 0, 0, 0, 0, 0, NULL),
(366, 'RUBY SHOP เครื่องผสมสี ผสมปูนซีเมนต์ HAND MIXER หัวแฉก รุ่น RB-HM120', '<ul><li><h5>มอเตอร์ประสิทธิภาพสูงช่วยให้การผสมสีและปูนซีเมนต์เป็นไปอย่างรวดเร็วและทั่วถึง</h5></li><li><h5>หัวแฉกออกแบบมาเป็นพิเศษเพื่อการผสมที่มีประสิทธิภาพ ลดการจับตัวเป็นก้อน</h5></li><li><h5>สามารถปรับระดับความเร็วในการผสมได้ตามความเหมาะสมของวัสดุ</h5></li><li><h5> ด้ามจับออกแบบตามหลักสรีรศาสตร์ จับถนัดมือ ลดความเมื่อยล้าในการใช้งาน</h5></li><li><h5>ผลิตจากวัสดุคุณภาพดี ทนทานต่อการใช้งานหนัก</h5><p> </p></li></ul>', '<h5>ข้อมูลจำเพาะ</h5><ul><li>power: 1400W</li><li>Voltage: 220V</li><li>No load speed: 350-500 RPM</li></ul><h5><strong>การใช้งาน</strong></h5><ol><li>ประกอบหัวแฉกเข้ากับตัวเครื่อง</li><li>ใส่ส่วนผสมที่ต้องการผสมลงในภาชนะ</li><li>จุ่มหัวแฉกของเครื่องผสมลงในส่วนผสม</li><li>เปิดเครื่องและปรับระดับความเร็วตามต้องการ</li><li>ผสมส่วนผสมจนเข้ากันได้ดี</li></ol><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรสวมใส่อุปกรณ์ป้องกันความปลอดภัย เช่น แว่นตาและถุงมือ ขณะใช้งาน</li><li>ควรทำความสะอาดเครื่องผสมหลังการใช้งานทุกครั้ง</li></ul>', 'published', '[\"products\\/rb-hm120-01-300-338.jpg\",\"products\\/rb-hm120-03.jpg\"]', NULL, 'NN-2443-KROZX-S18A5', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 2700, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 795, '2025-05-13 03:12:15', '2025-05-13 03:26:06', 1, 'Botble\\ACL\\Models\\User', 'products/1-43.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(367, 'RUBY SHOP เครื่องผสมสี ผสมปูนซีเมนต์ HAND MIXER หัวแฉก รุ่น RB-HM160', '<ul><li><h5>มอเตอร์ประสิทธิภาพสูงช่วยให้การผสมสีและปูนซีเมนต์เป็นไปอย่างรวดเร็วและทั่วถึง</h5></li><li><h5>หัวแฉกออกแบบมาเป็นพิเศษเพื่อการผสมที่มีประสิทธิภาพ ลดการจับตัวเป็นก้อน</h5></li><li><h5>สามารถปรับระดับความเร็วในการผสมได้ตามความเหมาะสมของวัสดุ</h5></li><li><h5> ด้ามจับออกแบบตามหลักสรีรศาสตร์ จับถนัดมือ ลดความเมื่อยล้าในการใช้งาน</h5></li><li><h5>ผลิตจากวัสดุคุณภาพดี ทนทานต่อการใช้งานหนัก</h5><p> </p></li></ul>', '<h5>ข้อมูลจำเพาะ</h5><ul><li>power: 1600W</li><li>Voltage: 220V</li><li>No load speed: 390-550 RPM</li></ul><h5><strong>การใช้งาน</strong></h5><ol><li>ประกอบหัวแฉกเข้ากับตัวเครื่อง</li><li>ใส่ส่วนผสมที่ต้องการผสมลงในภาชนะ</li><li>จุ่มหัวแฉกของเครื่องผสมลงในส่วนผสม</li><li>เปิดเครื่องและปรับระดับความเร็วตามต้องการ</li><li>ผสมส่วนผสมจนเข้ากันได้ดี</li></ol><h5> </h5><h5><strong>ข้อควรระวัง</strong></h5><ul><li>ควรอ่านคู่มือการใช้งานอย่างละเอียดก่อนใช้งาน</li><li>ควรสวมใส่อุปกรณ์ป้องกันความปลอดภัย เช่น แว่นตาและถุงมือ ขณะใช้งาน</li><li>ควรทำความสะอาดเครื่องผสมหลังการใช้งานทุกครั้ง</li></ul>', 'published', '[\"products\\/1-720x720.jpg\"]', NULL, 'NN-2443-KROZX-S18A5-7renW', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 2700, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 791, '2025-05-13 03:26:19', '2025-05-13 03:29:02', 1, 'Botble\\ACL\\Models\\User', 'products/1-720x720.jpg', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(368, 'เครื่องขัดพื้นคอนกรีต RUBYSHOP รุ่น RB-DWS 225A ขนาด 5 นิ้ว', '<p>เครื่องขัดพื้นคอนกรีตสามหัว RUBYSHOP รุ่น RB-DWS 225A กำลัง 2800W รอบสูง 2800 RPM ใช้งานกับไฟ 220V ขนาดแผ่นขัด 5 นิ้ว สายไฟยาว 2 เมตร</p>', '<p><strong>RUBYSHOP เครื่องขัดพื้นคอนกรีตสามหัว รุ่น RB-DWS 225A</strong><br>เพิ่มประสิทธิภาพงานขัดพื้นให้รวดเร็วและเรียบเนียนยิ่งขึ้นด้วยเครื่องขัดพื้นคอนกรีตจาก RUBYSHOP รุ่น RB-DWS 225A มาพร้อมมอเตอร์พลังสูง 2800 วัตต์ รองรับแรงดันไฟฟ้า 220 โวลต์ ให้ความเร็วรอบสูงถึง 2800 RPM ใช้งานได้อย่างต่อเนื่องและทนทาน เหมาะสำหรับงานขัดพื้นปูน พื้นคอนกรีต และพื้นผิวแข็งอื่น ๆ</p><p><strong>คุณสมบัติเด่น:</strong></p><ul><li> มอเตอร์กำลังสูง 2800 วัตต์ ขัดได้เรียบและเร็ว</li><li>ความเร็วรอบสูงถึง 2800 RPM รองรับงานหนักได้อย่างสบาย</li><li>แผ่นขัดขนาด 5 นิ้ว ให้พื้นที่การทำงานที่พอดีและควบคุมง่าย</li><li>ระบบขัดสามหัว เพิ่มความสม่ำเสมอในการขัดทุกจุด</li><li>สายไฟยาว 2 เมตร เคลื่อนไหวสะดวกในพื้นที่ทำงาน</li></ul><p><strong>ข้อมูลทางเทคนิค (Technical Data):</strong></p><ul><li>กำลังไฟ: 2800 วัตต์</li><li>แรงดันไฟฟ้า: 220 โวลต์</li><li>ความเร็วรอบขณะไม่มีโหลด: 2800 รอบ/นาที</li><li>ขนาดแผ่นขัด: 5 นิ้ว</li><li>ความยาวสายไฟ: 2 เมตร</li></ul><p><strong>เหมาะสำหรับ:</strong><br>ช่างก่อสร้าง ผู้รับเหมา หรือเจ้าของบ้านที่ต้องการเครื่องมือคุณภาพสูง สำหรับงานปรับสภาพพื้นผิวคอนกรีตให้เรียบและสวยงาม</p><h5><strong>หมายเหตุ</strong></h5><p>รับประกันมอเตอร์ 1 ปี (ไม่รวมอะไหล่)</p><h2> </h2>', 'published', '[\"products\\/90.png\",\"products\\/screen-shot-2568-05-13-at-101750.png\",\"products\\/screen-shot-2568-05-13-at-101739.png\"]', NULL, 'NN-2443-KGGLP-GTN0f', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 9900, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 817, '2025-05-13 03:57:07', '2025-05-13 04:39:06', 1, 'Botble\\ACL\\Models\\User', 'products/90.png', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(369, 'เครื่องกรีดผนัง RUBYSHOP รุ่น WALLCD-1100 ขนาด 1100W กรีดผนังอิฐมวลเบาเฉพาะ', '<ul><li><h5>เครื่องกรีดผนัง กำลังไฟ 1100 วัตต์ </h5></li><li><h5>ถูกออกแบบมาเฉพาะสำหรับการกรีดผนังอิฐมวลเบา </h5></li><li><h5>ช่วยให้การวางท่อสายไฟและระบบสื่อสารในอาคารเป็นไปอย่างสะดวกและรวดเร็ว</h5></li></ul>', '<h3><strong>รายละเอียดสินค้า </strong></h3><p><strong>RUBY SHOP เครื่องกรีดผนัง เซาะร่อง Wall Cutter รุ่น WALLCD-1100 (1100W)</strong><br>เครื่องกรีดผนังคุณภาพสูงจาก RUBY SHOP รุ่น WALLCD-1100 ออกแบบมาสำหรับงานเซาะร่องผนังอิฐมวลเบาโดยเฉพาะ เหมาะสำหรับงานติดตั้งระบบไฟฟ้า-ประปา ซ่อนสายหรือท่อในผนัง ทำงานสะดวก รวดเร็ว และประหยัดเวลา</p><p>ด้วยกำลังไฟ 1100 วัตต์ ตัวเครื่องสามารถกรีดร่องได้อย่างแม่นยำและสม่ำเสมอ มีน้ำหนักเบา พกพาง่าย เหมาะกับงานติดตั้งมืออาชีพหรือช่างที่ต้องการเครื่องมือสำหรับงานเฉพาะทาง</p><hr><p><strong>คุณสมบัติเด่น:</strong></p><ul><li> กำลังไฟฟ้า 1100 วัตต์ แรงพอสำหรับการกรีดผนังอิฐมวลเบา</li><li>เซาะร่องได้เรียบ คม ร่องเท่ากันทุกแนว</li><li>ใช้งานง่าย น้ำหนักเบา พกพาสะดวก</li><li>เหมาะสำหรับช่างไฟฟ้า ช่างประปา หรือผู้ติดตั้งระบบต่าง ๆ</li></ul><hr><p><strong>ข้อมูลทางเทคนิค (Technical Specifications):</strong></p><ul><li>รุ่น: WALLCD-1100</li><li>กำลังไฟ: 1100 วัตต์</li><li>เหมาะสำหรับผนัง: อิฐมวลเบาเท่านั้น</li><li>การใช้งาน: เซาะร่องท่อไฟ ท่อน้ำ สายไฟ</li></ul><hr><p><strong>เหมาะสำหรับ:</strong></p><ul><li>ผู้รับเหมางานก่อสร้าง</li><li>ช่างติดตั้งระบบไฟฟ้าและประปา</li><li>งานรีโนเวทบ้านที่ต้องเซาะร่องบนผนังเบา</li></ul><p> </p>', 'published', '[\"products\\/1100\\/ruby-shop-wallcd-1100-6.webp\",\"products\\/1100\\/ruby-shop-wallcd-1100-2.webp\",\"products\\/1100\\/ruby-shop-wallcd-1100-5.webp\",\"products\\/1100\\/ruby-shop-wallcd-1100-7.webp\",\"products\\/1100\\/ruby-shop-wallcd-1100-4.webp\"]', NULL, 'NN-2443-K3SXD-PkWi1', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 19000, 13900, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 851, '2025-05-13 04:37:21', '2025-05-13 05:37:29', 1, 'Botble\\ACL\\Models\\User', 'products/1100/100a-wallchaser-2.png', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(370, 'RUBYSHOP เครื่องกรีดผนังไร้ฝุ่น RUBYSHOP รุ่น WALLCD-2005 1800W', '<ul><li><h5>เครื่องเซาะร่องในผนัง กรีดได้ทุกผนัง ไม่ว่าจะเป็น อิฐแดง อิฐมวลเบา คอนกรีต หรือ แกรนิต</h5></li><li><h5>เครื่องเซาะร่องผนัง เครื่องกรีดผนัง วางท่อสายไฟ ท่อประปา ระบบน้ำ ไร้ฝุ่นเมื่อใช้ควบคู่กับน้ำ</h5></li><li><h5>เครื่องเซาะร่องผนัง RUBYSHOP รุ่น WALLCD-2005 ระบบน้ำ กำลัง 1800W ปรับลึกได้ 37 มม. ใบตัด 130 มม. </h5></li></ul>', '<h3><strong>รายละเอียดสินค้า :</strong></h3><p><strong>RUBYSHOP Electric Wall Chaser Groove รุ่น WALLCD-2005</strong><br>เครื่องกรีดผนังระบบน้ำรุ่นใหม่จาก RUBYSHOP ที่ออกแบบเพื่อการทำงานที่สะอาด รวดเร็ว และแม่นยำ เหมาะสำหรับงานเซาะร่องสายไฟ ท่อประปา หรือระบบติดตั้งภายในผนังปูน อิฐมวลเบา และอิฐทั่วไป</p><p>รุ่นนี้มาพร้อมกำลังไฟสูงถึง <strong>1800 วัตต์</strong> รอบหมุน <strong>7000 รอบ/นาที</strong> ใช้งานร่วมกับใบตัดขนาด 130 มม. และสามารถปรับความลึกในการกรีดได้สูงสุด <strong>37 มม.</strong> พร้อมสายไฟยาวถึง <strong>4.9 เมตร</strong> เพื่อการเคลื่อนไหวที่สะดวกในพื้นที่กว้าง</p><hr><p><strong>คุณสมบัติเด่น:</strong></p><ul><li> ระบบน้ำช่วยลดฝุ่นขณะตัด ปลอดภัยต่อสุขภาพผู้ใช้งาน</li><li>ความเร็วรอบสูง 7000 RPM ตัดลึก เร็ว และแม่นยำ</li><li>ปรับระดับความลึกได้ถึง 37 มม. ตอบโจทย์งานติดตั้งทุกประเภท</li><li>ใบตัดขนาด 130 มม. รองรับงานหลากหลาย</li><li>สายไฟยาว 4.9 เมตร เพิ่มความสะดวกในการใช้งานในไซต์งาน</li></ul><hr><p><strong>ข้อมูลทางเทคนิค (Technical Specifications):</strong></p><ul><li>กำลังไฟ: 1800 วัตต์</li><li>แรงดันไฟฟ้า: 220 โวลต์</li><li>ความเร็วรอบ: 7000 RPM (รอบขณะไม่มีโหลด)</li><li>ขนาดใบตัด: 130 มม.</li><li>ความลึกการตัด: ปรับได้สูงสุด 37 มม.</li><li>ความยาวสายไฟ: 4.9 เมตร</li><li>ระบบ: Water Cooling / Dust-Free</li></ul><hr><p><strong>เหมาะสำหรับ:</strong></p><ul><li>ช่างไฟฟ้า ช่างประปา และงานเดินสายระบบต่าง ๆ</li><li>ผู้รับเหมางานก่อสร้าง งานรีโนเวท</li><li>ผู้ที่ต้องการความสะอาดระหว่างทำงาน ตัดโดยไม่ฟุ้งฝุ่น</li></ul>', 'published', '[\"products\\/2005\\/ruby-shop-wallcd-2005-2.webp\",\"products\\/2005\\/ruby-shop-wallcd-2005-3.webp\",\"products\\/2005\\/ruby-shop-wallcd-2005-4.webp\"]', NULL, 'NN-2443-RBNDI-b2bri', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 5900, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 881, '2025-05-13 04:53:29', '2025-05-13 05:40:52', 1, 'Botble\\ACL\\Models\\User', 'products/2001/2005.webp', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(371, 'RUBYSHOP เครื่องกรีดผนังไร้ฝุ่น RUBYSHOP รุ่น WALLCD-2001 3200W', '<ul><li><h5>เครื่องเซาะร่องในผนัง กรีดได้ทุกผนัง ไม่ว่าจะเป็น อิฐแดง อิฐมวลเบา คอนกรีต หรือ แกรนิต</h5></li><li><h5>เครื่องเซาะร่องผนัง เครื่องกรีดผนัง วางท่อสายไฟ ท่อประปา ระบบน้ำ ไร้ฝุ่นเมื่อใช้ควบคู่กับน้ำ</h5></li><li><h5>เครื่องเซาะร่องผนัง RUBYSHOP รุ่น WALLCD-2001 ระบบน้ำ กำลัง 3200W ปรับลึกได้ 37 มม. ใบตัด 130 มม. </h5></li></ul>', '<h3><strong>รายละเอียดสินค้า :</strong></h3><p><strong>RUBYSHOP Electric Wall Chaser Groove รุ่น WALLCD-2001</strong><br>เครื่องกรีดผนังพลังสูงจาก RUBYSHOP รุ่น WALLCD-2001 มาพร้อมกำลังไฟแรงถึง <strong>3200 วัตต์</strong> พร้อมระบบฉีดน้ำช่วยลดฝุ่น ช่วยให้การเซาะร่องเป็นเรื่องสะอาด ปลอดภัย และแม่นยำในทุกเส้นทาง</p><p>มอเตอร์รอบสูง <strong>7000 RPM</strong> ใช้ใบตัดขนาด <strong>130 มม.</strong> สามารถปรับความลึกการกรีดได้สูงสุด <strong>37 มม.</strong> พร้อมสายไฟยาว <strong>4.9 เมตร</strong> เพิ่มความคล่องตัวในการทำงาน เหมาะกับงานติดตั้งสายไฟ ท่อน้ำ หรือเดินระบบภายในอาคาร</p><hr><p><strong>คุณสมบัติเด่น:</strong></p><ul><li>กำลังสูงถึง 3200W ตัดร่องได้เร็ว แรง ไม่สะดุด</li><li>ระบบน้ำลดฝุ่นขณะใช้งาน ลดผลกระทบต่อสุขภาพ</li><li>ใบตัดขนาด 130 มม. ใช้งานได้ทั้งอิฐมวลเบาและผนังปูน</li><li>ปรับความลึกได้ถึง 37 มม. เหมาะกับทุกประเภทงานเดินระบบ</li><li>สายไฟยาว 4.9 เมตร เคลื่อนย้ายง่ายในพื้นที่กว้าง</li></ul><hr><p><strong>ข้อมูลทางเทคนิค (Technical Specifications):</strong></p><ul><li>กำลังไฟ: 3200 วัตต์</li><li>แรงดันไฟฟ้า: 220 โวลต์</li><li>ความเร็วรอบ (No Load Speed): 7000 รอบ/นาที</li><li>ขนาดใบตัด: 130 มม.</li><li>ความลึกการกรีด: ปรับได้สูงสุด 37 มม.</li><li>ความยาวสายไฟ: 4.9 เมตร</li><li>ระบบ: Water Cooling / Dust-Free</li></ul><hr><p><strong>เหมาะสำหรับ:</strong></p><ul><li>งานเซาะร่องสายไฟ ท่อประปา หรือระบบภายใน</li><li>ช่างไฟ ช่างประปา หรือช่างรีโนเวท</li><li>งานที่ต้องการความสะอาด ปลอดฝุ่นระหว่างใช้งาน</li></ul>', 'published', '[\"products\\/2001\\/2001.webp\",\"products\\/2001\\/dsc02547.webp\"]', NULL, 'NN-2443-RBNDI-b2bri-DWifH', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 6500, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 825, '2025-05-13 05:09:38', '2025-05-13 07:29:53', 1, 'Botble\\ACL\\Models\\User', 'products/2001/100a-wallchaser-3.png', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(372, 'RUBYSHOP เครื่องกรีดผนังไร้ฝุ่น RUBYSHOP รุ่น WALLCD-2006 1800W', '<ul><li><h5>เครื่องเซาะร่องในผนัง กรีดได้ทุกผนัง ไม่ว่าจะเป็น อิฐแดง อิฐมวลเบา คอนกรีต หรือ แกรนิต</h5></li><li><h5>เครื่องเซาะร่องผนัง เครื่องกรีดผนัง วางท่อสายไฟ ท่อประปา ระบบน้ำ ไร้ฝุ่นเมื่อใช้ควบคู่กับน้ำ</h5></li><li><h5>เครื่องเซาะร่องผนัง RUBYSHOP รุ่น WALLCD-2005 ระบบน้ำ กำลัง 3200W ใบตัด 156 มม. ลึกสุด 50 มม.</h5></li></ul>', '<h3><strong>รายละเอียดสินค้า :</strong></h3><p><strong>RUBYSHOP Electric Wall Chaser Groove รุ่น WALLCD-2006</strong><br>เครื่องเซาะร่องผนังรุ่นใหม่ล่าสุดจาก RUBYSHOP มาพร้อมใบตัดขนาดใหญ่ <strong>156 มม.</strong> และความสามารถในการปรับความลึกได้ถึง <strong>50 มม.</strong> ช่วยให้คุณทำงานได้อย่างแม่นยำ รวดเร็ว และสะอาด ด้วยระบบ <strong>ฉีดน้ำลดฝุ่น</strong> ที่ปลอดภัยต่อสุขภาพผู้ใช้งาน</p><p>ด้วยกำลังไฟสูงถึง <strong>3200 วัตต์</strong> และความเร็วรอบ <strong>7000 RPM</strong> รุ่นนี้จึงเหมาะสำหรับงานหนัก ใช้งานได้ทั้งผนังอิฐ ผนังปูน หรืออิฐมวลเบา เหมาะสำหรับช่างไฟฟ้า ช่างประปา หรือผู้รับเหมาที่ต้องการเครื่องมือที่ทรงพลังและใช้งานง่าย</p><hr><p><strong>คุณสมบัติเด่น:</strong></p><ul><li>กำลังไฟแรง 3200W เซาะร่องได้ลึกและเสถียร</li><li>ระบบน้ำลดฝุ่น ช่วยให้งานสะอาด ปลอดภัย</li><li>ใบตัดขนาดใหญ่ 156 มม. ทำงานได้กว้างและเร็วขึ้น</li><li>ปรับความลึกได้สูงสุด 50 มม. รองรับงานที่หลากหลาย</li><li>สายไฟยาว 4.9 เมตร ใช้งานสะดวกในไซต์งาน</li></ul><hr><p><strong>ข้อมูลทางเทคนิค (Technical Specifications):</strong></p><ul><li>กำลังไฟ: 3200 วัตต์</li><li>แรงดันไฟฟ้า: 220 โวลต์</li><li>ความเร็วรอบ (No Load Speed): 7000 รอบ/นาที</li><li>ขนาดใบตัด: 156 มม.</li><li>ความลึกการกรีด: ปรับได้สูงสุด 50 มม.</li><li>ความยาวสายไฟ: 4.9 เมตร</li><li>ระบบ: Water Cooling / Dust-Free</li></ul><hr><p><strong>เหมาะสำหรับ:</strong></p><ul><li>ช่างไฟฟ้า ช่างประปา</li><li>งานติดตั้งสายไฟ ท่อน้ำ</li><li>ผู้รับเหมางานรีโนเวท หรือก่อสร้าง</li></ul>', 'published', '[\"products\\/2006\\/3.jpg\",\"products\\/2006\\/1.jpg\",\"products\\/2006\\/2.jpg\"]', NULL, 'NN-2443-RBNDI-b2bri-kfyh1', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 6900, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 837, '2025-05-13 07:21:03', '2025-05-13 07:29:16', 1, 'Botble\\ACL\\Models\\User', 'products/2006/3.jpg', 'physical', NULL, NULL, 0, 0, 0, 0, NULL),
(373, 'เครื่องกรีดผนัง RUBY SHOP รุ่น RB-1009 4800W พร้อมถังเก็บฝุ่นในตัว ใช้งานสะอาด ครบจบ', '<p>RUBY SHOP เครื่องกรีดผนัง เซาะร่องวางท่อไฟ รุ่น RB-1009 (4800W) – 2 in 1 ระบบน้ำและแห้ง พร้อมถังเก็บฝุ่นในตัว<br>เครื่องเซาะร่องทรงพลังรุ่นใหม่ล่าสุดจาก RUBY SHOP สำหรับมืออาชีพสายก่อสร้าง! </p>', '<h5><strong>รายละเอียดสินค้า :</strong></h5><h6>โดดเด่นด้วยระบบ 2-in-1 ใช้งานได้ทั้งระบบน้ำและระบบแห้ง มีถังเก็บฝุ่นในตัว ลดฝุ่นขณะทำงาน ช่วยให้พื้นที่สะอาดและปลอดภัย เหมาะสำหรับใช้งานในอาคารหรือสถานที่ที่ต้องการความสะอาด</h6><h5> </h5><h5><strong>คุณสมบัติเด่น:</strong></h5><ul><li><h6>2 ระบบในเครื่องเดียว: เลือกใช้งานได้ทั้งระบบน้ำไร้ฝุ่น หรือระบบแห้งพร้อมถังดูดฝุ่น</h6></li><li><h6>กำลังไฟสูงถึง 4800W: กรีดผนังลึก แรง ไม่สะดุด</h6></li><li><h6>รองรับผนังทุกชนิด: อิฐมอญ, อิฐมวลเบา, คอนกรีต, แกรนิต</h6></li><li><h6>ใบตัด 5 ใบ ขนาด 135 มม.: ความเร็วรอบ 6500 rpm</h6></li><li><h6>ความลึกสูงสุด 42 มม. / ความกว้างสูงสุด 48 มม.</h6></li><li><h6>ถังเก็บฝุ่นในตัว: ใช้งานสะอาด ลดฝุ่นในที่ปิด</h6></li></ul><h5> </h5><h5><strong>ข้อมูลทางเทคนิค (Technical Specs):</strong></h5><ul><li><h6>กำลังไฟ: 4800 วัตต์</h6></li><li><h6>ระบบ: น้ำ + แห้ง พร้อมถังเก็บฝุ่น</h6></li><li><h6>ขนาดใบตัด: 135 มม. (จำนวน 5 ใบ)</h6></li><li><h6>ความเร็วรอบ: 6500 RPM</h6></li><li><h6>ความลึกสูงสุด: 42 มม.</h6></li><li><h6>ความกว้างสูงสุด: 48 มม.</h6></li><li><h6>น้ำหนัก: 7 กิโลกรัม</h6></li><li><h6>รองรับวัสดุ: อิฐแดง, อิฐมวลเบา, คอนกรีต, แกรนิต</h6></li></ul><h5> </h5><h5><strong>เหมาะสำหรับ:</strong></h5><ul><li><h6>ช่างไฟ ช่างประปา ช่างรีโนเวท</h6></li><li><h6>งานเดินสายไฟ ท่อประปา งานระบบ</h6></li><li><h6>ผู้รับเหมา งานโครงการที่ต้องการประสิทธิภาพและความสะอาดสูง</h6></li></ul>[media url=\"https://www.youtube.com/embed/w5fv0WZ--p8?list=PLdfEpHX9cqTC2SDJk8XF5EYgTCI2eKkeH\"][/media]', 'published', '[\"products\\/1009\\/01-1009-2.jpg\",\"products\\/1009\\/01-1009-1.jpg\",\"products\\/1009\\/01-1009-3.jpg\",\"products\\/1009\\/01-1009-4.jpg\",\"products\\/1009\\/01-1009-5.jpg\"]', NULL, 'NN-2443-RBNDI-b2bri-DWifH-kpxGL', 0, 0, 0, NULL, 0, 0, 'in_stock', 0, NULL, 0, 0, 16500, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 845, '2025-05-13 07:36:23', '2025-05-13 09:29:09', 1, 'Botble\\ACL\\Models\\User', 'products/1009/100a-wallchaser-4.png', 'physical', NULL, NULL, 0, 0, 0, 0, NULL);
INSERT INTO `ec_products_translations` (`lang_code`, `ec_products_id`, `name`, `description`, `content`) VALUES
('th', 364, 'data', '<p>digi</p>', '<p>digi</p>'),
('th', 365, 'เครื่องพ่นสกิมโค้ท ระบบสกรูปั้ม RB-HP30', '<p>เครื่องพ่นสกิมโค้ทขนาดเล็กกะทัดรัด ระบบสกรูปั๊ม ที่ช่วยให้การพ่นสกิมโค้ทรวดเร็วและสม่ำเสมอ</p>', '<p>เหมาะสำหรับงานตกแต่งผนังและเพดาน ใช้งานง่าย ลดระยะเวลาในการทำงาน มาพร้อมคุณสมบัติเด่นดังนี้:</p><p>✅ <strong>ระบบสกรูปั๊มคุณภาพสูง</strong> – ช่วยให้เนื้อสกิมโค้ทไหลสม่ำเสมอ พ่นได้เรียบเนียน ลดปัญหาการอุดตัน<br>✅ <strong>ถังบรรจุขนาด 82 ลิตร</strong> – รองรับปริมาณสกิมโค้ทได้มาก ลดความถี่ในการเติมวัสดุ<br>✅ <strong>ปรับระดับแรงดันได้</strong> – ควบคุมแรงดันให้เหมาะสมกับการใช้งานแต่ละประเภท<br>✅ <strong>เหมาะสำหรับงานรีโนเวทและก่อสร้าง</strong> – ใช้งานได้ทั้งภายในและภายนอกอาคาร<br>✅ <strong>ขนาดกะทัดรัด เคลื่อนย้ายสะดวก</strong> – มีล้อช่วยให้เคลื่อนที่ง่าย เพิ่มความสะดวกในการทำงาน</p><p>เครื่องพ่นสกิมโค้ทรุ่นนี้เหมาะสำหรับช่างมืออาชีพที่ต้องการความสะดวก รวดเร็ว และคุณภาพงานที่สวยงาม</p>');
