INSERT INTO `ec_product_tags` (`id`, `name`, `description`, `status`, `created_at`, `updated_at`) VALUES
(6, 'airless-sprayer', 'RUBYSHOP เครื่องพ่นสีแรงดันสูง พ่นสีอุตสาหกรรม จบงานไว แรงดันสูง เป็นเครื่องพ่นสีอุตสาหกรรมที่ออกแบบมาเพื่อตอบสนองความต้องการของงานพ่นสีขนาดใหญ่ ด้วยประสิทธิภาพที่สูงและทนทาน ทำให้เป็นตัวเลือกที่คุ้มค่าสำหรับผู้ใช้งาน', 'published', '2025-03-14 09:46:37', '2025-03-14 09:46:37'),
(7, 'wallcheser', 'เครื่องกรีดผนัง เซาะร่อง Wall Cutter 2500 วัตต์ รุ่น WALLCD-100A กรีดผนังอิฐมวลเบาเฉพาะ', 'published', '2025-03-14 09:47:50', '2025-03-14 09:47:50'),
(8, 'cement-mortar-spraying-machine', 'เครื่องพ่นปูนฉาบ รุ่น RB-MR004 เป็นเครื่องพ่นปูนฉาบคุณภาพสูง\nออกแบบมาเพื่อตอบโจทย์ความต้องการของช่างก่อสร้างมืออาชีพ\n ด้วยความสามารถในการพ่นปูนได้เร็วถึง 30 วินาทีต่อถุง', 'published', '2025-03-14 09:48:49', '2025-03-14 09:48:58');
