INSERT INTO `pages` (`id`, `name`, `content`, `user_id`, `image`, `template`, `description`, `status`, `created_at`, `updated_at`) VALUES
(2, 'Homepage 2', '<shortcode>[hero-video-mobile-image-ruby desktop_video=\"6474081-uhd-3840-2160-25fps.mp4\" title=\"RUBYSHOP TOOLS\" button_text=\"SHOP\" button_link=\"https://www.rubyshop.co.th/categories\" enable_lazy_loading=\"no\"][/hero-video-mobile-image-ruby]</shortcode><shortcode>[shop-by-category-cards title=\"Shop By Category\" button_text=\"View All Products\" button_link=\"/allproducts\"][{\"image\":\"\",\"title\":\"Control Series\",\"subtitle\":\"Stain Sprayers\",\"link\":\"/product-categories/control-series\"},{\"image\":\"\",\"title\":\"FLEXiO\",\"subtitle\":\"Paint &amp; Stain Sprayers\",\"link\":\"/product-categories/flexio\"},{\"image\":\"\",\"title\":\"Control Pro\",\"subtitle\":\"\",\"link\":\"/product-categories/control-pro\"},{\"image\":\"\",\"title\":\"Earlex\",\"subtitle\":\"\",\"link\":\"/product-categories/earlex\"},{\"image\":\"\",\"title\":\"FURNO\",\"subtitle\":\"\",\"link\":\"/product-categories/furno\"},{\"image\":\"\",\"title\":\"Steamer\",\"subtitle\":\"\",\"link\":\"/product-categories/steamer\"}][/shop-by-category-cards]</shortcode><p>&nbsp;</p><shortcode>[ruby-feature-card card1_image=\"home/new/m6-1.webp\" card1_title=\"แข็งแกร่ง ทนทาน ท้าทายทุกงานหนัก!\" card1_description=\"เครื่องพ่นปูน Rubyshop ทำงานได้เต็มประสิทธิภาพโดยไม่ต้องใช้เชื้อเพลิง เพิ่มความคล่องตัวในทุกไซต์งาน พร้อมความสะดวกสบายที่ไม่เคยมีมาก่อน ช่วยให้การทำงานทุกประเภทเป็นเรื่องง่าย ตอบโจทย์ทุกความต้องการของช่างในทุกสถานการณ์\" card1_button_text=\"LEARN MORE\" card1_button_link=\"https://www.rubyshop.co.th/product-categories/cement-mortar-spraying-machine\" card2_image=\"home/new/1009b-1.webp\" card2_title=\"ทรงพลัง เพื่อการทำงานหนัก\" card2_description=\"เครื่องกรีดผนัง Rubyshop แข็งแกร่ง ทนทาน ให้พลังการกรีดลึกและแม่นยำ รองรับงานหนักแบบมืออาชีพ ทำงานได้ยาวนานโดยไม่สะดุด พร้อมระบบที่ทำให้การใช้งานเป็นเรื่องสะดวก เหมาะกับงานที่ต้องการความแม่นยำและความเร็ว\" card2_button_text=\"LEARN MORE\" card2_button_link=\"https://www.rubyshop.co.th/product-categories/wallcheser\" card3_image=\"home/new/rb-899.webp\" card3_title=\"ฉลาดล้ำ ทำงานไว ไม่เหนื่อยฟรี!\" card3_description=\"เครื่องพ่นสีแรงดันสูง Rubyshop มาพร้อมกับเทคโนโลยีที่ช่วยให้การทำงานเร็วขึ้นและมีความแม่นยำมากยิ่งขึ้น ด้วยการออกแบบที่ตอบโจทย์ช่างที่ต้องการทำงานได้เนี๊ยบและเร็วทันใจ ช่วยลดเวลาในการทำงานและเพิ่มประสิทธิภาพโดยรวม ให้งานเสร็จเร็วขึ้น ทำให้คุณสามารถรับงานได้มากขึ้นในเวลาเดียวกัน ไม่ว่าจะเป็นการทำสี หรือการพ่นงานที่ต้องการความละเอียดสูง เครื่องพ่นสีของเราก็พร้อมจะให้ความสามารถที่ครบครัน\" card3_button_text=\"LEARN MORE\" card3_button_link=\"https://www.rubyshop.co.th/product-categories/airless-sprayer\" enable_lazy_loading=\"yes\"][/ruby-feature-card]</shortcode><shortcode>[images-with-fade-animation background_image=\"home/new/rb-899-2.webp\" card_title=\"เครื่องพ่นสีเคลื่อนที่: พร้อมพ่นทุกที่ งานสีเนียนจบไว &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; \" card_description=\"เครื่องพ่นสีเคลื่อนที่: ของ Rubyshop ถูกออกแบบมาเพื่อเพิ่มความสะดวกสบายและประสิทธิภาพในการพ่นสีแรงดันสูง ช่วยให้ช่างสีสามารถเคลื่อนย้ายอุปกรณ์ได้อย่างคล่องตัว &nbsp; &nbsp; &nbsp;\" button_text=\"ดูเลย &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; \" button_link=\"http://127.0.0.1:8000/product-categories/airless-sprayer\" enable_lazy_loading=\"yes\"][/images-with-fade-animation]</shortcode><shortcode>[ruby-slider-tools section_title=\"อุปกรณ์เพื่อการช่าง\" slide1_image=\"home/new/airless-spayer-4.webp\" slide1_title=\"เครื่องพ่นสีไร้อากาศระดับมืออาชีพ\" slide1_description=\"เครื่องพ่นสีประสิทธิภาพสูงสำหรับงานทาสีระดับมืออาชีพ\" slide1_link=\"https://www.rubyshop.co.th/product-categories/airless-sprayer\" slide2_image=\"home/new/airless-sprayer.webp\" slide2_title=\"เครื่องพ่นปูน\" slide2_description=\"การพ่นปูนที่มีประสิทธิภาพสำหรับพื้นผิวขนาดใหญ่และโครงการต่างๆ\" slide2_link=\"https://www.rubyshop.co.th/product-categories/cement-mortar-spraying-machine\" slide3_image=\"home/new/rb-09.webp\" slide3_title=\"เครื่องพ่นสีแบบกะทัดรัด\" slide3_description=\"น้ำหนักเบาและอเนกป