INSERT INTO `pages` (`id`, `name`, `content`, `user_id`, `image`, `template`, `description`, `status`, `created_at`, `updated_at`) VALUES
(12, 'Privacy Policy', '<p style=\"-webkit-text-stroke-width:0px;background-color:rgb(255, 255, 255);box-sizing:border-box;color:rgb(4, 4, 4);font-family:Prompt, sans-serif;font-size:18px;font-style:normal;font-variant-caps:normal;font-variant-ligatures:normal;font-weight:400;letter-spacing:normal;line-height:26px;margin:0px 0px 15px;orphans:2;padding:0px;text-align:start;text-decoration-color:initial;text-decoration-style:initial;text-decoration-thickness:initial;text-indent:0px;text-transform:none;transition:0.3s ease-out;white-space:normal;widows:2;word-spacing:0px;\"><strong style=\"box-sizing:border-box;font-weight:bolder;margin:0px;padding:0px;\">นโยบายความเป็นส่วนตัว</strong><br>เว็บไซต์: https://www.rubyshop.co.th</p><p style=\"-webkit-text-stroke-width:0px;background-color:rgb(255, 255, 255);box-sizing:border-box;color:rgb(4, 4, 4);font-family:Prompt, sans-serif;font-size:18px;font-style:normal;font-variant-caps:normal;font-variant-ligatures:normal;font-weight:400;letter-spacing:normal;line-height:26px;margin:0px 0px 15px;orphans:2;padding:0px;text-align:start;text-decoration-color:initial;text-decoration-style:initial;text-decoration-thickness:initial;text-indent:0px;text-transform:none;transition:0.3s ease-out;white-space:normal;widows:2;word-spacing:0px;\">เราตระหนักถึงความสำคัญของความเป็นส่วนตัวของผู้ใช้และให้ความสำคัญกับการคุ้มครองข้อมูลส่วนบุคคลของคุณ ดังนั้น นโยบายความเป็นส่วนตัวฉบับนี้จึงจัดทำขึ้นเพื่ออธิบายว่าข้อมูลของคุณถูกเก็บรวบรวม ใช้งาน และปกป้องอย่างไร</p><p style=\"-webkit-text-stroke-width:0px;background-color:rgb(255, 255, 255);box-sizing:border-box;color:rgb(4, 4, 4);font-family:Prompt, sans-serif;font-size:18px;font-style:normal;font-variant-caps:normal;font-variant-ligatures:normal;font-weight:400;letter-spacing:normal;line-height:26px;margin:0px 0px 15px;orphans:2;padding:0px;text-align:start;text-decoration-color:initial;text-decoration-style:initial;text-decoration-thickness:initial;text-indent:0px;text-transform:none;transition:0.3s ease-out;white-space:normal;widows:2;word-spacing:0px;\">1. การเก็บรวบรวมข้อมูล<br>เมื่อคุณเข้าชมเว็บไซต์ของเรา อาจมีการเก็บรวบรวมข้อมูลต่อไปนี้:</p><p style=\"-webkit-text-stroke-width:0px;background-color:rgb(255, 255, 255);box-sizing:border-box;color:rgb(4, 4, 4);font-family:Prompt, sans-serif;font-size:18px;font-style:normal;font-variant-caps:normal;font-variant-ligatures:normal;font-weight:400;letter-spacing:normal;line-height:26px;margin:0px 0px 15px;orphans:2;padding:0px;text-align:start;text-decoration-color:initial;text-decoration-style:initial;text-decoration-thickness:initial;text-indent:0px;text-transform:none;transition:0.3s ease-out;white-space:normal;widows:2;word-spacing:0px;\">ข้อมูลส่วนบุคคล เช่น ชื่อ นามสกุล อีเมล เบอร์โทรศัพท์ (เมื่อคุณกรอกแบบฟอร์มหรือลงทะเบียน)<br>ข้อมูลเกี่ยวกับการใช้งานเว็บไซต์ เช่น IP Address, ประเภทของเบราว์เซอร์, หน้าเว็บที่คุณเข้าชม, และพฤติกรรมการใช้งานเว็บไซต์<br>ข้อมูลที่เกี่ยวข้องกับการทำธุรกรรม เช่น รายละเอียดคำสั่งซื้อ ที่อยู่จัดส่ง และข้อมูลการชำระเงิน (เราไม่เก็บข้อมูลบัตรเครดิตโดยตรง ระบบจะใช้บริการชำระเงินที่ปลอดภัยจากบุคคลที่สาม)<br>&nbsp;</p><p style=\"-webkit-text-stroke-width:0px;background-color:rgb(255, 255, 255);box-sizing:border-box;color:rgb(4, 4, 4);font-family:Prompt, sans-serif;font-size:18px;font-style:normal;font-variant-caps:normal;font-variant-ligatures:normal;font-weight:400;letter-spacing:normal;line-height:26px;margin:0px 0px 15px;orphans:2;padding:0px;text-align:start;text-decoration-color:initial;text-decoration-style:initial;text-decoration-thickness:initial;text-indent:0px;text-transform:none;transition:0.3s ease-out;white-space:normal;widows:2;word-spacing:0px;\">2. การใช้ข้อมูล<br>เราใช้ข้อมูลของคุณเพื่อวัตถุประสงค์ดังต่อไปนี้:</p><p style=\"-webkit-text-stroke-width:0px;background-color:rgb(255, 255, 255);box-sizing:border-box;color:rgb(4, 4, 4);font-family:Prompt, sans-serif;font-size:18px;font-style:normal;font-variant-caps:normal;font-variant-ligatures:normal;font-weight:400;letter-spacing:normal;line-height:26px;margin:0px 0px 15px;orphans:2;padding:0px;text-align:start;text-decoration-color:initial;text-decoration-style:initial;text-decoration-thickness:initial;text-indent:0px;text-transform:none;transition:0.3s ease-out;white-space:normal;widows:2;word-spacing:0px;\">ให้บริการและปรับปรุงประสบการณ์ของผู้ใช้บนเว็บไซต์<br>ดำเนินการตามคำสั่งซื้อและให้บริการลูกค้า<br>ส่งข่าวสาร โปรโมชั่น หรือข้อเสนอพิเศษ (หากคุณสมัครรับข่าวสารจากเรา)<br>วิเคราะห์ข้อมูลการใช้งานเพื่อปรับปรุงประสิทธิภาพของเว็บไซต์<br>ปฏิบัติตามข้อกำหนดทางกฎหมายและข้อบังคับที่เกี่ยวข้อง<br>&nbsp;</p><p style=\"-webkit-text-stroke-width:0px;background-color:rgb(255, 255, 255);box-sizing:border-box;color:rgb(4, 4, 4);font-family:Prompt, sans-serif;font-size:18px;font-style:normal;font-variant-caps:normal;font-variant-ligatures:normal;font-weight:400;letter-spacing:normal;line-height:26px;margin:0px 0px 15px;orphans:2;padding:0px;text-align:start;text-decoration-color:initial;text-decoration-style:initial;text-decoration-thickness:initial;text-indent:0px;text-transform:none;transition:0.3s ease-out;white-space:normal;widows:2;word-spacing:0px;\">3. การเปิดเผยข้อมูลแก่บุคคลที่สาม<br>เราไม่ขาย แลกเปลี่ยน หรือเปิดเผยข้อมูลส่วนบุคคลของคุณให้แก่บุคคลที่สาม เว้นแต่ในกรณีต่อไปนี้:</p><p style=\"-webkit-text-stroke-width:0px;background-color:rgb(255, 255, 255);box-sizing:border-box;color:rgb(4, 4, 4);font-family:Prompt, sans-serif;font-size:18px;font-style:normal;font-variant-caps:normal;font-variant-ligatures:normal;font-weight:400;letter-spacing:normal;line-height:26px;margin:0px 0px 15px;orphans:2;padding:0px;text-align:start;text-decoration-color:initial;text-decoration-style:initial;text-decoration-thickness:initial;text-indent:0px;text-transform:none;transition:0.3s ease-out;white-space:normal;widows:2;word-spacing:0px;\">จำเป็นต้องใช้บริการจากบุคคลที่สาม เช่น ผู้ให้บริการชำระเงิน หรือบริษัทขนส่งสินค้า<br>เพื่อปฏิบัติตามข้อกำหนดทางกฎหมาย หรือเมื่อมีคำร้องขอจากหน่วยงานภาครัฐ<br>เพื่อป้องกันการฉ้อโกงและเพิ่มความปลอดภัยของเว็บไซต์<br>&nbsp;</p><p style=\"-webkit-text-stroke-width:0px;background-color:rgb(255, 255, 255);box-sizing:border-box;color:rgb(4, 4, 4);font-family:Prompt, sans-serif;font-size:18px;font-style:normal;font-variant-caps:normal;font-variant-ligatures:normal;font-weight:400;letter-spacing:normal;line-height:26px;margin:0px 0px 15px;orphans:2;padding:0px;text-align:start;text-decoration-color:initial;text-decoration-style:initial;text-decoration-thickness:initial;text-indent:0px;text-transform:none;transition:0.3s ease-out;white-space:normal;widows:2;word-spacing:0px;\">4. คุกกี้ (Cookies) และเทคโนโลยีติดตาม<br>เราใช้คุกกี้และเทคโนโลยีอื่น ๆ เพื่อช่วยให้เราปรับปรุงประสบการณ์ของผู้ใช้บนเว็บไซต์<br>คุณสามารถตั้งค่าเบราว์เซอร์ของคุณให้ปฏิเสธคุกกี้หรือแจ้งเตือนเมื่อมีการใช้คุกกี้ได้<br>&nbsp;</p><p style=\"-webkit-text-stroke-width:0px;background-color:rgb(255, 255, 255);box-sizing:border-box;color:rgb(4, 4, 4);font-family:Prompt, sans-serif;font-size:18px;font-style:normal;font-variant-caps:normal;font-variant-ligatures:normal;font-weight:400;letter-spacing:normal;line-height:26px;margin:0px 0px 15px;orphans:2;padding:0px;text-align:start;text-decoration-color:initial;text-decoration-style:initial;text-decoration-thickness:initial;text-indent:0px;text-transform:none;transition:0.3s ease-out;white-space:normal;widows:2;word-spacing:0px;\">5. สิทธิของคุณเกี่ยวกับข้อมูลส่วนบุคคล<br>คุณมีสิทธิ์ในการ:</p><p style=\"-webkit-text-stroke-width:0px;background-color:rgb(255, 255, 255);box-sizing:border-box;color:rgb(4, 4, 4);font-family:Prompt, sans-serif;font-size:18px;font-style:normal;font-variant-caps:normal;font-variant-ligatures:normal;font-weight:400;letter-spacing:normal;line-height:26px;margin:0px 0px 15px;orphans:2;padding:0px;text-align:start;text-decoration-color:initial;text-decoration-style:initial;text-decoration-thickness:initial;text-indent:0px;text-transform:none;transition:0.3s ease-out;white-space:normal;widows:2;word-spacing:0px;\">ขอเข้าถึง แก้ไข หรือลบข้อมูลส่วนบุคคลของคุณ<br>ยกเลิกการสมัครรับข่าวสารทางอีเมลได้ทุกเมื่อ<br>คัดค้านการใช้ข้อมูลส่วนบุคคลของคุณในบางกรณี<br>&nbsp;</p><p style=\"-webkit-text-stroke-width:0px;background-color:rgb(255, 255, 255);box-sizing:border-box;color:rgb(4, 4, 4);font-family:Prompt, sans-serif;font-size:18px;font-style:normal;font-variant-caps:normal;font-variant-ligatures:normal;font-weight:400;letter-spacing:normal;line-height:26px;margin:0px 0px 15px;orphans:2;padding:0px;text-align:start;text-decoration-color:initial;text-decoration-style:initial;text-decoration-thickness:initial;text-indent:0px;text-transform:none;transition:0.3s ease-out;white-space:normal;widows:2;word-spacing:0px;\">6. การรักษาความปลอดภัยของข้อมูล<br>เราใช้มาตรการรักษาความปลอดภัยที่เหมาะสมเพื่อปกป้องข้อมูลของคุณจากการเข้าถึงโดยไม่ได้รับอนุญาต หรือการรั่วไหลของข้อมูล<br>อย่างไรก็ตาม ไม่มีระบบใดที่สามารถรับประกันความปลอดภัยได้ 100%<br>&nbsp;</p><p style=\"-webkit-text-stroke-width:0px;background-color:rgb(255, 255, 255);box-sizing:border-box;color:rgb(4, 4, 4);font-family:Prompt, sans-serif;font-size:18px;font-style:normal;font-variant-caps:normal;font-variant-ligatures:normal;font-weight:400;letter-spacing:normal;line-height:26px;margin:0px 0px 15px;orphans:2;padding:0px;text-align:start;text-decoration-color:initial;text-decoration-style:initial;text-decoration-thickness:initial;text-indent:0px;text-transform:none;transition:0.3s ease-out;white-space:normal;widows:2;word-spacing:0px;\">7. การเปลี่ยนแปลงนโยบายความเป็นส่วนตัว<br>เราขอสงวนสิทธิ์ในการเปลี่ยนแปลงนโยบายความเป็นส่วนตัวนี้โดยไม่ต้องแจ้งให้ทราบล่วงหน้า<br>โปรดตรวจสอบหน้านี้เป็นระยะเพื่อดูการอัปเดต<br>&nbsp;</p><p style=\"-webkit-text-stroke-width:0px;background-color:rgb(255, 255, 255);box-sizing:border-box;color:rgb(4, 4, 4);font-family:Prompt, sans-serif;font-size:18px;font-style:normal;font-variant-caps:normal;font-variant-ligatures:normal;font-weight:400;letter-spacing:normal;line-height:26px;margin:0px 0px 15px;orphans:2;padding:0px;text-align:start;text-decoration-color:initial;text-decoration-style:initial;text-decoration-thickness:initial;text-indent:0px;text-transform:none;transition:0.3s ease-out;white-space:normal;widows:2;word-spacing:0px;\">8. ติดต่อเรา<br>หากคุณมีคำถามเกี่ยวกับนโยบายความเป็นส่วนตัวนี้ กรุณาติดต่อเราได้ที่:</p><p style=\"-webkit-text-stroke-width:0px;background-color:rgb(255, 255, 255);box-sizing:border-box;color:rgb(4, 4, 4);font-family:Prompt, sans-serif;font-size:18px;font-style:normal;font-variant-caps:normal;font-variant-ligatures:normal;font-weight:400;letter-spacing:normal;line-height:26px;margin:0px 0px 15px;orphans:2;padding:0px;text-align:start;text-decoration-color:initial;text-decoration-style:initial;text-decoration-thickness:initial;text-indent:0px;text-transform:none;transition:0.3s ease-out;white-space:normal;widows:2;word-spacing:0px;\">อีเมล: <a style=\"background-color:rgb(255, 255, 255);border-style:none;box-sizing:border-box;color:rgb(17, 17, 17);font-family:Tahoma, Arial, &quot;MS Sans Serif&quot;, sans-serif;font-size:14px;font-style:normal;font-weight:400;margin:0px;outline:none;padding:0px;text-decoration:none;transition:0.3s ease-out;word-spacing:0px;\" href=\"mailto:saleruby.benjavan@gmail.com\">saleruby.benjavan@gmail.com</a><br>เบอร์โทรศัพท์: <a style=\"background-color:rgb(255, 255, 255);border-style:none;box-sizing:border-box;color:rgb(106, 114, 119);font-family:Tahoma, Arial, &quot;MS Sans Serif&quot;, sans-serif;font-size:14px;font-style:normal;font-weight:400;margin:0px;outline:none;padding:0px;text-decoration:none;transition:0.3s ease-out;word-spacing:0px;\" href=\"tel:0896667802\">0896667802</a></p>', 1, NULL, 'default', 'นโยบายความเป็นส่วนตัว\nเว็บไซต์: https://www.rubyshop.co.th\n\nเราตระหนักถึงความสำคัญของความเป็นส่วนตัวของผู้ใช้และให้ความสำคัญกับการคุ้มครองข้อมูลส่วนบุคคลของคุณ ดังนั้น นโยบายความเป็นส่วนตัวฉบับนี้จึงจัดทำขึ้นเพื่ออธิบายว่าข้อมูลของคุณถูกเก็บรวบรวม ใช้งาน และปกป้องอย่างไร', 'published', '2025-01-21 21:20:43', '2025-03-15 09:07:42'),
