INSERT INTO `tags` (`id`, `name`, `author_id`, `author_type`, `description`, `status`, `created_at`, `updated_at`) VALUES
(1, 'airless sprayer', 1, 'Botble\\ACL\\Models\\User', 'เปลี่ยนงานพ่นสีให้เป็นเรื่องง่ายด้วย เครื่องพ่นสีแรงดันสูง (Airless Sprayer) เหมาะสำหรับงานทาบ้าน เฟอร์นิเจอร์ หรือโปรเจกต์ช่างทุกประเภท พ่นสีได้เร็ว พื้นผิวเรียบเนียน ประหยัดแรงและเวลา เหมาะทั้งมืออาชีพและมือใหม่ที่ต้องการผลลัพธ์ระดับโปร!', 'published', '2025-01-21 21:20:43', '2025-05-07 09:05:32'),
(2, 'Wall Chaser', 1, 'Botble\\ACL\\Models\\User', 'เจาะร่องเดินสายไฟและท่อน้ำได้ง่ายและเรียบร้อยด้วย เครื่องกรีดผนัง (Wall Chaser) เครื่องมือช่างที่ออกแบบมาเพื่อความแม่นยำและประหยัดเวลา ร่องตรง สะอาด ทำงานไว เหมาะสำหรับช่างไฟ ช่างประปา และงานรีโนเวททุกประเภท!', 'published', '2025-01-21 21:20:43', '2025-05-07 09:05:11'),
(3, 'Mortar Sprayer', 1, 'Botble\\ACL\\Models\\User', 'เพิ่มประสิทธิภาพงานก่อสร้างด้วย เครื่องพ่นปูนซีเมนต์ (Mortar Sprayer) พ่นได้ทั้งปูนฉาบ ปูนมอร์ตาร์ และวัสดุก่อสร้างอื่น ๆ พ่นไว เรียบเนียน ประหยัดแรงงาน ลดเวลาการทำงาน เหมาะสำหรับช่างมืออาชีพและผู้รับเหมา!', 'published', '2025-01-21 21:20:43', '2025-05-07 09:04:43'),
(4, 'Skim Coat Machine', 1, 'Botble\\ACL\\Models\\User', 'สร้างผนังเรียบเนียนระดับมือโปรด้วย เครื่องพ่นสกิมโค้ท (Skim Coat Machine) ใช้งานง่าย พ่นเร็ว ไม่ต้องฉาบมือ ลดเวลาทำงานและแรงงาน เหมาะสำหรับงานรีโนเวท งานก่อสร้าง และผู้รับเหมาที่ต้องการคุณภาพและความเร็วในทุกโปรเจกต์!', 'published', '2025-01-21 21:20:43', '2025-05-07 09:04:11');
